function clearLocalCrmCollections(data) {
  if (!data || typeof data !== "object") {
    return false;
  }
  let changed = false;
  ["accounts", "contacts", "leads", "deals"].forEach((key) => {
    const current = data[key];
    if (Array.isArray(current)) {
      if (current.length) {
        changed = true;
      }
      data[key] = [];
      return;
    }
    data[key] = [];
    changed = true;
  });
  return changed;
}

function clearLocalWorkCollections(data) {
  if (!data || typeof data !== "object") {
    return false;
  }
  let changed = false;
  ["tasks", "projects", "waitingList"].forEach((key) => {
    if (Array.isArray(data[key])) {
      if (data[key].length) {
        changed = true;
      }
    } else {
      changed = true;
    }
    data[key] = [];
  });
  return changed;
}

function clearLocalAttendanceCollections(data) {
  if (!data || typeof data !== "object") {
    return false;
  }
  let changed = false;
  if (Array.isArray(data.attendanceLogs)) {
    if (data.attendanceLogs.length) {
      changed = true;
    }
  } else {
    changed = true;
  }
  if (Array.isArray(data.attendanceRequests)) {
    if (data.attendanceRequests.length) {
      changed = true;
    }
  } else {
    changed = true;
  }
  if (data.attendancePolicy && typeof data.attendancePolicy === "object" && Object.keys(data.attendancePolicy).length) {
    changed = true;
  } else if (!data.attendancePolicy || typeof data.attendancePolicy !== "object") {
    changed = true;
  }
  data.attendanceLogs = [];
  data.attendanceRequests = [];
  data.attendancePolicy = {};
  return changed;
}

function readStoredDismissedWrapupId() {
  if (typeof window === "undefined" || !window.sessionStorage) {
    return "";
  }
  try {
    return String(window.sessionStorage.getItem(CALL_DISMISSED_WRAPUP_STORAGE_KEY) || "").trim();
  } catch (_error) {
    return "";
  }
}

function persistDismissedWrapupId(value = "") {
  if (typeof window === "undefined" || !window.sessionStorage) {
    return;
  }
  const normalized = String(value || "").trim();
  try {
    if (normalized) {
      window.sessionStorage.setItem(CALL_DISMISSED_WRAPUP_STORAGE_KEY, normalized);
      return;
    }
    window.sessionStorage.removeItem(CALL_DISMISSED_WRAPUP_STORAGE_KEY);
  } catch (_error) {
    // Ignore storage write failures so the call dock still works normally.
  }
}

function setDismissedWrapupId(value = "") {
  const normalized = String(value || "").trim();
  state.callDismissedWrapupId = normalized;
  persistDismissedWrapupId(normalized);
}

function clearLocalMessengerCollections(data) {
  if (!data || typeof data !== "object") {
    return false;
  }
  let changed = false;
  if (Array.isArray(data.channels)) {
    if (data.channels.length) {
      changed = true;
    }
  } else {
    changed = true;
  }
  if (Array.isArray(data.directThreads)) {
    if (data.directThreads.length) {
      changed = true;
    }
  } else {
    changed = true;
  }
  data.channels = [];
  data.directThreads = [];
  if (Array.isArray(data.messages)) {
    const filtered = data.messages.filter((message) => {
      if (message?.isMessenger) {
        return false;
      }
      const targetType = message?.targetType || (message?.channelId ? "channel" : "direct");
      const commMode = String(message?.commMode || "").trim().toLowerCase();
      if ((targetType === "channel" || targetType === "direct") && (!commMode || commMode === "internal")) {
        return false;
      }
      return true;
    });
    if (filtered.length !== data.messages.length) {
      changed = true;
    }
    data.messages = filtered;
  } else {
    data.messages = [];
    changed = true;
  }
  return changed;
}

function clearLocalConnectedBootstrapCollections(data) {
  if (!data || typeof data !== "object") {
    return false;
  }
  let changed = false;
  if (data.workspace && typeof data.workspace === "object" && Object.keys(data.workspace).length) {
    changed = true;
  } else if (!data.workspace || typeof data.workspace !== "object") {
    changed = true;
  }
  if (data.currentUser && typeof data.currentUser === "object" && Object.keys(data.currentUser).length) {
    changed = true;
  } else if (!data.currentUser || typeof data.currentUser !== "object") {
    changed = true;
  }
  if (Array.isArray(data.teamMembers)) {
    if (data.teamMembers.length) {
      changed = true;
    }
  } else {
    changed = true;
  }
  if (Array.isArray(data.messages)) {
    if (data.messages.length) {
      changed = true;
    }
  } else {
    changed = true;
  }
  if (data.metrics && typeof data.metrics === "object" && Object.keys(data.metrics).length) {
    changed = true;
  } else if (!data.metrics || typeof data.metrics !== "object") {
    changed = true;
  }
  data.workspace = {};
  data.currentUser = {};
  data.teamMembers = [];
  data.messages = [];
  data.metrics = {};
  return changed;
}

