function consumeEmailIntegrationReturnParams() {
  const params = new URLSearchParams(window.location.search || "");
  const status = String(params.get("email") || "").trim().toLowerCase();
  if (!status) {
    return null;
  }

  const result = {
    status,
    message: String(params.get("message") || "").trim(),
    provider: String(params.get("provider") || "").trim(),
    integrationId: String(params.get("integrationId") || "").trim()
  };

  params.delete("email");
  params.delete("message");
  params.delete("provider");
  params.delete("integrationId");

  const nextSearch = params.toString();
  const nextUrl = `${window.location.pathname}${nextSearch ? `?${nextSearch}` : ""}${window.location.hash}`;
  window.history.replaceState({}, "", nextUrl);
  return result;
}

