function dismissToast(toastId) {
  const targetId = Number(toastId);
  state.toasts = (state.toasts || []).filter((toast) => toast.id !== targetId);
  const timer = toastTimers.get(targetId);
  if (timer) {
    window.clearTimeout(timer);
    toastTimers.delete(targetId);
  }
  toastActionHandlers.delete(targetId);
  renderToastViewport();
}

function showToast(message, options = {}) {
  const text = String(message || "").trim();
  if (!text) {
    return 0;
  }
  const viewport = document.getElementById("toastViewport");
  if (!viewport) {
    nativeWindowAlert?.(text);
    return 0;
  }
  const toast = {
    id: ++toastSequence,
    title: String(options.title || "").trim(),
    message: text,
    tone: String(options.tone || inferToastToneFromMessage(text)).trim() || "info",
    actionLabel: String(options.actionLabel || "").trim()
  };
  if (typeof options.onAction === "function") {
    toastActionHandlers.set(toast.id, options.onAction);
  }
  state.toasts = [...(state.toasts || []).filter((item) => item.id !== toast.id), toast].slice(-5);
  renderToastViewport();
  if (options.duration !== 0) {
    const duration = Number.isFinite(Number(options.duration)) ? Math.max(2200, Number(options.duration)) : 4200;
    const timer = window.setTimeout(() => dismissToast(toast.id), duration);
    toastTimers.set(toast.id, timer);
  }
  return toast.id;
}

function installAlertShim() {
  window.alert = (message) => {
    showToast(message, { tone: inferToastToneFromMessage(message) });
  };
}

function clearFormFeedback(form) {
  if (!(form instanceof HTMLFormElement)) {
    return;
  }
  form.querySelectorAll(".form-feedback").forEach((node) => node.remove());
  form.querySelectorAll(".form-field.is-field-error").forEach((node) => node.classList.remove("is-field-error"));
  form.querySelectorAll("[aria-invalid='true']").forEach((node) => node.removeAttribute("aria-invalid"));
}

function showFormFeedback(form, message, options = {}) {
  if (!(form instanceof HTMLFormElement)) {
    showToast(message, { tone: options.tone || "danger" });
    return;
  }
  clearFormFeedback(form);
  const feedback = document.createElement("div");
  const tone = String(options.tone || "danger").trim() || "danger";
  feedback.className = `form-feedback is-${tone}`;
  feedback.setAttribute("role", "alert");
  feedback.innerHTML = `
    <i class="bi ${getToastIcon(tone)}" aria-hidden="true"></i>
    <span>${escapeModalText(String(message || "").trim())}</span>
  `;
  form.prepend(feedback);
  const field =
    options.field instanceof HTMLElement
      ? options.field
      : options.fieldSelector
        ? form.querySelector(options.fieldSelector)
        : null;
  if (field instanceof HTMLElement) {
    field.setAttribute("aria-invalid", "true");
    field.closest(".form-field")?.classList.add("is-field-error");
    if (options.focus !== false) {
      field.focus?.();
      field.select?.();
    }
  }
}

