function normalizeLeadCompanyFields(data) {
  let changed = false;
  (data?.leads || []).forEach((lead) => {
    if (!lead || typeof lead !== "object") {
      return;
    }
    const company = String(lead.company || "").trim();
    const interest = String(lead.interest || "").trim();
    if (!company) {
      return;
    }
    if (company === "Individual" || (interest && company === interest)) {
      lead.company = "";
      changed = true;
    }
  });
  return changed;
}

function getDefaultCrmSortState(routeId) {
  const key = String(routeId || "").trim();
  if (key === "leads") {
    return { key: "lastTouch", dir: "desc" };
  }
  return { key: "", dir: "none" };
}

function getCrmSortState(routeId) {
  const key = String(routeId || "").trim();
  const fallback = getDefaultCrmSortState(key);
  if (!["leads", "contacts", "accounts", "deals", "team"].includes(key)) {
    return fallback;
  }
  const current = state.crmSortByRoute?.[key] || fallback;
  const normalized = {
    key: String(current.key || "").trim(),
    dir: current.dir === "desc" ? "desc" : current.dir === "asc" ? "asc" : "none"
  };
  if (key === "leads" && (!normalized.key || normalized.dir === "none")) {
    return fallback;
  }
  return normalized;
}

function getCrmPageState(routeId) {
  const key = String(routeId || "").trim();
  const value = Number(state.crmPageByRoute?.[key]);
  return Number.isFinite(value) && value > 0 ? Math.floor(value) : 1;
}

function getCrmPageSizeOptions(routeId) {
  return String(routeId || "").trim() === "leads" ? [25, 50, 100] : [20, 50, 100];
}

function getCrmPageSizeState(routeId) {
  const key = String(routeId || "").trim();
  const value = Number(state.crmPageSizeByRoute?.[key]);
  if (getCrmPageSizeOptions(key).includes(value)) {
    return value;
  }
  return key === "leads" ? 25 : 20;
}

