function flushPendingEmailIntegrationNotice(options = {}) {
  if (!pendingEmailIntegrationReturn) {
    return;
  }

  const pending = pendingEmailIntegrationReturn;
  pendingEmailIntegrationReturn = null;

  if (pending.status === "connected") {
    if (options.connected) {
      const connectedEmail = String(options.email || "").trim();
      window.alert(`Gmail connected${connectedEmail ? ` as ${connectedEmail}` : ""}.`);
      return;
    }
    const fallbackMessage =
      String(options.message || "").trim() ||
      "Google sign-in finished, but the app could not confirm an active Gmail connection for this workspace user.";
    window.alert(`Gmail connection could not be verified: ${fallbackMessage}`);
    return;
  }

  if (pending.status === "error") {
    const message = String(pending.message || options.message || "Unknown error").trim() || "Unknown error";
    window.alert(`Gmail connection failed: ${message}`);
  }
}

