function normalizeEmailAddress(value) {
  return String(value || "").trim().toLowerCase();
}

function normalizeInviteContextRecord(raw) {
  if (!raw || typeof raw !== "object") {
    return null;
  }

  const inviteId = String(raw.inviteId || raw.id || "").trim();
  const token = String(raw.token || raw.inviteToken || raw.invite || "").trim();
  const email = normalizeEmailAddress(raw.email);
  if (!inviteId && !token && !email) {
    return null;
  }

  const createdAt = Number(raw.createdAt || Date.now());
  if (Number.isFinite(createdAt) && Date.now() - createdAt > INVITE_CONTEXT_MAX_AGE_MS) {
    return null;
  }

  return {
    inviteId,
    token,
    email,
    name: String(raw.name || "").trim(),
    role: String(raw.role || "Member").trim() || "Member",
    team: String(raw.team || "General").trim() || "General",
    workspace: String(raw.workspace || "Workspace").trim() || "Workspace",
    invitedBy: String(raw.invitedBy || "").trim(),
    createdAt: Number.isFinite(createdAt) ? createdAt : Date.now()
  };
}

function readStoredInviteContext() {
  const readers = [
    () => window.sessionStorage.getItem(INVITE_CONTEXT_STORAGE_KEY),
    () => window.localStorage.getItem(INVITE_CONTEXT_STORAGE_KEY)
  ];

  for (const read of readers) {
    try {
      const raw = read();
      if (!raw) {
        continue;
      }
      const parsed = normalizeInviteContextRecord(JSON.parse(raw));
      if (parsed) {
        return parsed;
      }
    } catch {
      // no-op
    }
  }

  return null;
}

function persistInviteContext(context) {
  const normalized = normalizeInviteContextRecord({
    ...(context && typeof context === "object" ? context : {}),
    createdAt: Date.now()
  });
  if (!normalized) {
    return null;
  }

  const payload = JSON.stringify(normalized);
  try {
    window.sessionStorage.setItem(INVITE_CONTEXT_STORAGE_KEY, payload);
  } catch {
    // no-op
  }
  try {
    window.localStorage.setItem(INVITE_CONTEXT_STORAGE_KEY, payload);
  } catch {
    // no-op
  }
  return normalized;
}

function clearStoredInviteContext() {
  try {
    window.sessionStorage.removeItem(INVITE_CONTEXT_STORAGE_KEY);
  } catch {
    // no-op
  }
  try {
    window.localStorage.removeItem(INVITE_CONTEXT_STORAGE_KEY);
  } catch {
    // no-op
  }
}

function parseInviteContextFromHash(hashValue = window.location.hash) {
  const params = getHashQueryParams(hashValue);
  return normalizeInviteContextRecord({
    inviteId: String(params.get("id") || params.get("inviteId") || "").trim(),
    token: String(params.get("token") || params.get("invite") || "").trim(),
    email: params.get("email"),
    name: String(params.get("name") || "").trim(),
    role: String(params.get("role") || "Member").trim(),
    team: String(params.get("team") || "General").trim(),
    workspace: String(params.get("workspace") || "Workspace").trim(),
    invitedBy: String(params.get("invitedBy") || "").trim()
  });
}

function parseInviteContextFromSearch(searchValue = window.location.search) {
  const params = new URLSearchParams(searchValue || "");
  return normalizeInviteContextRecord({
    inviteId: String(params.get("inviteId") || "").trim(),
    token: String(params.get("inviteToken") || "").trim(),
    email: params.get("inviteEmail"),
    name: String(params.get("inviteName") || "").trim(),
    role: String(params.get("inviteRole") || "Member").trim(),
    team: String(params.get("inviteTeam") || "General").trim(),
    workspace: String(params.get("inviteWorkspace") || "Workspace").trim(),
    invitedBy: String(params.get("inviteBy") || "").trim()
  });
}

function isSupabaseAuthCallbackHash(hashValue = window.location.hash) {
  const raw = String(hashValue || "").replace(/^#\/?/, "").trim().toLowerCase();
  if (!raw) {
    return false;
  }
  return (
    raw.includes("access_token=") ||
    raw.includes("refresh_token=") ||
    raw.includes("expires_in=") ||
    raw.includes("token_type=") ||
    raw.includes("error=") ||
    raw.includes("error_description=")
  );
}

function sanitizeInviteUrlInPlace(options = {}) {
  const normalizedOptions =
    options && typeof options === "object" ? options : { hashValue: options };
  const hashValue = String(normalizedOptions.hashValue || window.location.hash || "").trim();
  const source = String(normalizedOptions.source || "").trim().toLowerCase();
  const searchParams = new URLSearchParams(normalizedOptions.searchValue || window.location.search || "");
  let searchChanged = false;

  INVITE_AUTH_QUERY_PARAM_KEYS.forEach((key) => {
    if (!searchParams.has(key)) {
      return;
    }
    searchParams.delete(key);
    searchChanged = true;
  });

  let nextHash = hashValue;
  if (source === "hash" && nextHash && !isSupabaseAuthCallbackHash(nextHash)) {
    const raw = nextHash.replace(/^#\/?/, "").trim();
    const routeId = raw.split("?")[0].trim() || "invite";
    nextHash = `#/${routeId === "invite" ? "invite" : routeId}`;
  } else if (source === "search" && !nextHash) {
    nextHash = "#/invite";
  }

  if (!searchChanged && nextHash === hashValue) {
    return;
  }

  const nextSearch = searchParams.toString();
  const nextUrl = `${window.location.pathname}${nextSearch ? `?${nextSearch}` : ""}${nextHash}`;
  window.history.replaceState({}, "", nextUrl);
}

function captureInviteContextFromLocation(hashValue = window.location.hash, options = {}) {
  const { cleanUrl = true } = options;
  const fromHash = parseInviteContextFromHash(hashValue);
  const fromSearch = fromHash ? null : parseInviteContextFromSearch(window.location.search);
  const fromLocation = fromHash || fromSearch;
  if (!fromLocation) {
    return readStoredInviteContext();
  }

  const stored = persistInviteContext(fromLocation);
  if (cleanUrl) {
    sanitizeInviteUrlInPlace({
      hashValue,
      source: fromHash ? "hash" : "search",
      searchValue: window.location.search
    });
  }
  return stored;
}

