function captureMessengerUiState(root = document.getElementById("viewContent")) {
  if (!(root instanceof HTMLElement)) {
    return state.messengerUiState || createEmptyMessengerUiState();
  }
  const conversationKey = String(state.selectedConversationKey || "").trim();
  const messageList = root.querySelector("#commMessageList");
  const conversationList = root.querySelector(".conversation-list.messenger-list");
  const composer = root.querySelector("#commComposerText");
  const currentDrafts = {
    ...((state.messengerUiState && state.messengerUiState.draftsByConversationKey) || {})
  };
  if (conversationKey && composer instanceof HTMLTextAreaElement) {
    currentDrafts[conversationKey] = {
      value: String(composer.value || ""),
      selectionStart: Number.isFinite(composer.selectionStart) ? composer.selectionStart : null,
      selectionEnd: Number.isFinite(composer.selectionEnd) ? composer.selectionEnd : null
    };
  }
  const nextState = {
    ...(state.messengerUiState || createEmptyMessengerUiState()),
    draftsByConversationKey: currentDrafts,
    messageListScrollTop: Number(messageList?.scrollTop || 0),
    conversationListScrollTop: Number(conversationList?.scrollTop || 0),
    lastSelectedConversationKey: conversationKey,
    lastCapturedAt: Date.now()
  };
  state.messengerUiState = nextState;
  return nextState;
}

function clearMessengerUiDraft(conversationKey = state.selectedConversationKey) {
  const normalizedConversationKey = String(conversationKey || "").trim();
  const nextState = {
    ...(state.messengerUiState || createEmptyMessengerUiState()),
    draftsByConversationKey: {
      ...((state.messengerUiState && state.messengerUiState.draftsByConversationKey) || {})
    }
  };
  if (normalizedConversationKey) {
    delete nextState.draftsByConversationKey[normalizedConversationKey];
  }
  state.messengerUiState = nextState;
}

function restoreMessengerUiState(root = document.getElementById("viewContent"), options = {}) {
  if (!(root instanceof HTMLElement)) {
    return;
  }
  const conversationKey = String(state.selectedConversationKey || "").trim();
  const messageList = root.querySelector("#commMessageList");
  const conversationList = root.querySelector(".conversation-list.messenger-list");
  const composer = root.querySelector("#commComposerText");
  const messengerUiState = state.messengerUiState || createEmptyMessengerUiState();
  const draftEntry = conversationKey
    ? messengerUiState.draftsByConversationKey?.[conversationKey] || null
    : null;
  const autoScrollToBottom = Boolean(options.autoScrollToBottom);
  if (conversationList instanceof HTMLElement) {
    conversationList.scrollTop = Number.isFinite(Number(messengerUiState.conversationListScrollTop))
      ? Math.max(0, Number(messengerUiState.conversationListScrollTop || 0))
      : 0;
  }
  if (messageList instanceof HTMLElement) {
    if (autoScrollToBottom) {
      messageList.scrollTop = messageList.scrollHeight;
    } else {
      messageList.scrollTop = Number.isFinite(Number(messengerUiState.messageListScrollTop))
        ? Math.max(0, Number(messengerUiState.messageListScrollTop || 0))
        : 0;
    }
  }
  if (composer instanceof HTMLTextAreaElement) {
    const editingMessageId = String(state.messengerEditMessageId || "").trim();
    const nextValue = editingMessageId ? String(state.messengerEditDraft || "") : String(draftEntry?.value || "");
    composer.value = nextValue;
    if (document.activeElement === composer && draftEntry) {
      const selectionStart = Number.isFinite(Number(draftEntry.selectionStart)) ? Number(draftEntry.selectionStart) : nextValue.length;
      const selectionEnd = Number.isFinite(Number(draftEntry.selectionEnd)) ? Number(draftEntry.selectionEnd) : nextValue.length;
      try {
        composer.setSelectionRange(selectionStart, selectionEnd);
      } catch {
        // Ignore browsers that refuse selection updates here.
      }
    }
  }
}

function resolveRouteFromLocation(hashValue = window.location.hash) {
  const resolved = getRouteFromHash(hashValue || `#/${defaultRouteId}`);
  if (resolved !== defaultRouteId) {
    return resolved;
  }

  const raw = String(hashValue || "").replace(/^#\/?/, "").trim();
  const candidate = raw.split("?")[0].trim();
  if (!candidate || candidate.includes("=")) {
    return captureInviteContextFromLocation(hashValue, { cleanUrl: false }) ? "invite" : resolved;
  }

  return resolved;
}

function isStandalonePublicRoute(routeId = state.routeId) {
  const normalizedRouteId = String(routeId || "").trim();
  return normalizedRouteId === "invite" || normalizedRouteId === "login";
}

function normalizeAppHash(hashValue) {
  const raw = String(hashValue || "").trim();
  if (!raw) {
    return `#/${defaultRouteId}`;
  }
  if (raw.startsWith("#/")) {
    return raw;
  }
  if (raw.startsWith("#")) {
    return `#/${raw.slice(1).replace(/^\/?/, "")}`;
  }
  return `#/${raw.replace(/^\/+/, "")}`;
}

function readStoredAuthReturnHash() {
  try {
    const raw = window.sessionStorage.getItem(AUTH_RETURN_HASH_STORAGE_KEY);
    if (!raw) {
      return "";
    }
    const normalized = normalizeAppHash(raw);
    return isStandalonePublicRoute(resolveRouteFromLocation(normalized)) ? "" : normalized;
  } catch {
    return "";
  }
}

function clearStoredAuthReturnHash() {
  try {
    window.sessionStorage.removeItem(AUTH_RETURN_HASH_STORAGE_KEY);
  } catch {
    // no-op
  }
}

function persistAuthReturnHash(hashValue = window.location.hash) {
  const normalized = normalizeAppHash(hashValue || `#/${defaultRouteId}`);
  if (isStandalonePublicRoute(resolveRouteFromLocation(normalized))) {
    return "";
  }
  try {
    window.sessionStorage.setItem(AUTH_RETURN_HASH_STORAGE_KEY, normalized);
  } catch {
    // no-op
  }
  return normalized;
}

function consumeStoredAuthReturnHash() {
  const stored = readStoredAuthReturnHash();
  clearStoredAuthReturnHash();
  return stored;
}

function resolvePostAuthTargetHash(isInviteRoute = false) {
  if (isInviteRoute) {
    return `#/${defaultRouteId}`;
  }
  if (state.routeId === "login") {
    return readStoredAuthReturnHash() || `#/${defaultRouteId}`;
  }
  return normalizeAppHash(window.location.hash || `#/${defaultRouteId}`);
}

function getStoredAuthReturnRouteLabel() {
  const storedHash = readStoredAuthReturnHash();
  if (!storedHash) {
    return "";
  }
  const routeId = resolveRouteFromLocation(storedHash);
  if (isStandalonePublicRoute(routeId)) {
    return "";
  }
  return String(getRoute(routeId)?.label || "").trim();
}

function replaceLocationHash(nextHash) {
  const normalizedHash = normalizeAppHash(nextHash || `#/${defaultRouteId}`);
  const nextUrl = `${window.location.pathname}${window.location.search}${normalizedHash}`;
  window.history.replaceState({}, "", nextUrl);
  return normalizedHash;
}

function redirectToLoginRoute(hashValue = window.location.hash) {
  const normalizedHash = normalizeAppHash(hashValue || `#/${defaultRouteId}`);
  if (isStandalonePublicRoute(resolveRouteFromLocation(normalizedHash))) {
    return false;
  }
  persistAuthReturnHash(normalizedHash);
  replaceLocationHash("#/login");
  renderRoute();
  return true;
}

function redirectAuthenticatedLoginRoute() {
  const nextHash = consumeStoredAuthReturnHash() || `#/${defaultRouteId}`;
  replaceLocationHash(nextHash);
  renderRoute();
  return true;
}

const CRM_BOOTSTRAP_ROUTE_IDS = new Set([
  "leads",
  "contacts",
  "accounts",
  "deals",
  "lead-profile",
  "account-profile",
  "deal-profile"
]);
const WORK_BOOTSTRAP_ROUTE_IDS = new Set(["my-work", "calendar", "kanban", "table", "projects", "comms-calls"]);
const ATTENDANCE_BOOTSTRAP_ROUTE_IDS = new Set(["attendance"]);
const MESSENGER_BOOTSTRAP_ROUTE_IDS = new Set(["comms-messenger"]);
const CALLS_BOOTSTRAP_ROUTE_IDS = new Set(["comms-calls"]);
const DASHBOARD_BOOTSTRAP_ROUTE_IDS = new Set(["dashboard"]);
const EMAIL_BOOTSTRAP_ROUTE_IDS = new Set(["comms-email"]);

function mergeWorkspaceBundleMember(bundle, memberPatch) {
  const memberId = String(memberPatch?.id || bundle?.member?.id || "").trim();
  if (!bundle || !memberId || !memberPatch || typeof memberPatch !== "object") {
    return bundle;
  }
  const nextMember = String(bundle?.member?.id || "").trim() === memberId
    ? { ...(bundle.member || {}), ...memberPatch }
    : { ...(bundle.member || {}), ...memberPatch };
  const existingTeamMembers = Array.isArray(bundle.teamMembers) ? bundle.teamMembers : [];
  let foundTeamMember = false;
  const nextTeamMembers = existingTeamMembers.map((member) => {
    if (String(member?.id || "").trim() !== memberId) {
      return member;
    }
    foundTeamMember = true;
    return { ...member, ...memberPatch };
  });
  if (!foundTeamMember) {
    nextTeamMembers.push({ ...memberPatch });
  }
  return {
    ...bundle,
    member: nextMember,
    teamMembers: nextTeamMembers
  };
}

