function createPostAuthRefreshPlan(targetRouteId = defaultRouteId, targetHash = window.location.hash) {
  const blocking = [];
  const deferred = [];
  const scheduled = new Set();
  const commsAccessEnabled = canAccessComms();
  const addTask = (bucket, key, run) => {
    if (scheduled.has(key)) {
      return;
    }
    scheduled.add(key);
    bucket.push({ key, run });
  };

  const crmTask = () =>
    refreshSupabaseCrmData({
      render: false,
      persist: false,
      alertOnError: false,
      syncDashboard: false
    });
  const leadsPageTask = () =>
    refreshSupabaseLeadsPageData({
      render: false,
      persist: false,
      alertOnError: false,
      force: true
    });
  const contactsTask = () =>
    refreshSupabaseCrmCollectionData("contacts", {
      render: false,
      alertOnError: false,
      force: true
    });
  const accountsTask = () =>
    refreshSupabaseCrmCollectionData("accounts", {
      render: false,
      alertOnError: false,
      force: true
    });
  const dealsTask = () =>
    refreshSupabaseCrmCollectionData("deals", {
      render: false,
      alertOnError: false,
      force: true
    });
  const workTask = () =>
    refreshSupabaseWorkData({
      render: false,
      persist: false,
      alertOnError: false,
      syncDashboard: false
    });
  const attendanceTask = () =>
    refreshSupabaseAttendanceData({
      render: false,
      persist: false,
      alertOnError: false
    });
  const dashboardTask = () =>
    refreshSupabaseDashboardData({
      render: false,
      alertOnError: false
    });
  const notificationsTask = () =>
    refreshSupabaseNotifications({
      render: false,
      alertOnError: false,
      showToasts: false,
      force: true
    });
  const messengerTask = () => {
    const selected = parseConversationOption(state.selectedConversationKey || "");
    const conversationId =
      selected.targetType === "channel" || selected.targetType === "direct" ? selected.targetId : "";
    return refreshSupabaseMessengerData({
      render: false,
      alertOnError: false,
      conversationId,
      fetchAllMessages: false
    });
  };
  const callsSnapshotTask = () =>
    refreshSupabaseCallsData({
      render: false,
      persist: false,
      alertOnError: false,
      syncProvider: false,
      syncDashboard: false
    });
  const leadProfileTask = () => {
    const leadId = getRequestedLeadProfileId(targetHash);
    return leadId
      ? refreshSupabaseLeadProfileData({
          leadId,
          render: false,
          force: true,
          alertOnError: false
        })
      : Promise.resolve(false);
  };
  const accountProfileTask = () => {
    const accountId = getRequestedAccountProfileId(targetHash);
    return accountId
      ? refreshSupabaseAccountProfileData({
          accountId,
          render: false,
          force: true,
          alertOnError: false
        })
      : Promise.resolve(false);
  };
  const dealProfileTask = () => {
    const dealId = getRequestedDealProfileId(targetHash);
    return dealId
      ? refreshSupabaseDealProfileData({
          dealId,
          render: false,
          force: true,
          alertOnError: false
        })
      : Promise.resolve(false);
  };
  const emailStatusTask = () =>
    refreshEmailIntegrationStatus({
      render: false,
      alertOnError: false
    });
  const emailMailboxTask = async () => {
    const status = await refreshEmailIntegrationStatus({
      render: false,
      alertOnError: false
    });
    if (!status?.connected) {
      resetEmailMailboxState();
      return state.emailMailbox;
    }
    return refreshEmailMailbox({
      folder: getActiveEmailMailboxFolderId(),
      render: false,
      alertOnError: false,
      force: true
    });
  };

  if (targetRouteId === "leads") {
    addTask(blocking, "leads-page", leadsPageTask);
  } else if (targetRouteId === "lead-profile") {
    addTask(blocking, "lead-profile", leadProfileTask);
  } else if (targetRouteId === "contacts") {
    addTask(blocking, "contacts", contactsTask);
  } else if (targetRouteId === "account-profile") {
    addTask(blocking, "account-profile", accountProfileTask);
  } else if (targetRouteId === "accounts") {
    addTask(blocking, "accounts", accountsTask);
  } else if (targetRouteId === "deal-profile") {
    addTask(blocking, "deal-profile", dealProfileTask);
  } else if (targetRouteId === "deals") {
    addTask(blocking, "deals", dealsTask);
  } else if (CRM_BOOTSTRAP_ROUTE_IDS.has(targetRouteId)) {
    addTask(blocking, "crm", crmTask);
  } else {
    addTask(deferred, "crm", crmTask);
  }

  if (WORK_BOOTSTRAP_ROUTE_IDS.has(targetRouteId)) {
    addTask(blocking, "work", workTask);
  } else {
    addTask(deferred, "work", workTask);
  }

  if (ATTENDANCE_BOOTSTRAP_ROUTE_IDS.has(targetRouteId)) {
    addTask(blocking, "attendance", attendanceTask);
  } else {
    addTask(deferred, "attendance", attendanceTask);
  }

  if (canAccessDashboard()) {
    if (DASHBOARD_BOOTSTRAP_ROUTE_IDS.has(targetRouteId)) {
      addTask(blocking, "dashboard", dashboardTask);
    } else {
      addTask(deferred, "dashboard", dashboardTask);
    }
  }

  if (commsAccessEnabled) {
    if (MESSENGER_BOOTSTRAP_ROUTE_IDS.has(targetRouteId)) {
      addTask(blocking, "messenger", messengerTask);
    } else {
      addTask(deferred, "messenger", messengerTask);
    }

    if (CALLS_BOOTSTRAP_ROUTE_IDS.has(targetRouteId)) {
      addTask(blocking, "calls", callsSnapshotTask);
    } else {
      addTask(deferred, "calls", callsSnapshotTask);
    }

    if (EMAIL_BOOTSTRAP_ROUTE_IDS.has(targetRouteId)) {
      addTask(blocking, "email", emailMailboxTask);
    } else {
      addTask(deferred, "email", emailStatusTask);
    }
  }

  addTask(deferred, "notifications", notificationsTask);

  return { blocking, deferred };
}

async function runPostAuthRefreshTask(task, syncId, options = {}) {
  if (!task || typeof task.run !== "function") {
    return false;
  }
  if (syncId !== authSyncSequence || !state.signedInUser) {
    return false;
  }
  try {
    return await task.run();
  } finally {
    if (options.renderAfter && syncId === authSyncSequence && state.signedInUser && state.authAccessState === "granted") {
      renderRoute();
    }
  }
}

async function runBlockingPostAuthRefreshTasks(tasks, syncId) {
  if (!Array.isArray(tasks) || !tasks.length) {
    return [];
  }
  return Promise.allSettled(tasks.map((task) => runPostAuthRefreshTask(task, syncId)));
}

function startDeferredPostAuthRefreshTasks(tasks, syncId, options = {}) {
  if (!Array.isArray(tasks) || !tasks.length) {
    return;
  }
  if (options.batchRender) {
    void Promise.allSettled(tasks.map((task) => runPostAuthRefreshTask(task, syncId))).finally(() => {
      if (syncId === authSyncSequence && state.signedInUser && state.authAccessState === "granted") {
        renderRoute();
      }
    });
    return;
  }
  tasks.forEach((task) => {
    void runPostAuthRefreshTask(task, syncId, { renderAfter: true });
  });
}

function loadAuthAccessCache() {
  try {
    const raw = window.localStorage.getItem(AUTH_ACCESS_CACHE_KEY);
    if (!raw) {
      return { granted: false, email: "" };
    }
    const parsed = JSON.parse(raw);
    return {
      granted: Boolean(parsed?.granted),
      email: normalizeEmailAddress(parsed?.email)
    };
  } catch {
    return { granted: false, email: "" };
  }
}

function loadLastKnownAuthEmail() {
  try {
    return normalizeEmailAddress(window.localStorage.getItem(AUTH_LAST_EMAIL_STORAGE_KEY));
  } catch {
    return "";
  }
}

function persistAuthAccessCache(granted, email = "") {
  try {
    if (!granted) {
      window.localStorage.removeItem(AUTH_ACCESS_CACHE_KEY);
      return;
    }
    window.localStorage.setItem(
      AUTH_ACCESS_CACHE_KEY,
      JSON.stringify({
        granted: true,
        email: normalizeEmailAddress(email)
      })
    );
  } catch {
    // no-op
  }
}

function persistLastKnownAuthEmail(email = "") {
  const normalized = normalizeEmailAddress(email);
  if (!normalized) {
    return;
  }
  try {
    window.localStorage.setItem(AUTH_LAST_EMAIL_STORAGE_KEY, normalized);
  } catch {
    // no-op
  }
}

