function getBaseAppUrl() {
  return getPublicAppUrl();
}

function getInviteAcceptanceContext(hashValue = window.location.hash) {
  const captured = captureInviteContextFromLocation(hashValue, { cleanUrl: true });
  const invite = captured || readStoredInviteContext();
  if (!invite) {
    return null;
  }
  return {
    inviteId: String(invite.inviteId || "").trim(),
    token: String(invite.token || "").trim(),
    email: normalizeEmailAddress(invite.email),
    name: String(invite.name || "").trim(),
    role: String(invite.role || "Member").trim() || "Member",
    team: String(invite.team || "General").trim() || "General",
    workspace: String(invite.workspace || state.data.workspace?.name || "Workspace").trim() || "Workspace",
    invitedBy: String(invite.invitedBy || "").trim()
  };
}

function shouldUseShortInviteLinks() {
  return state.supabaseConfigured && invitePublicApiAvailability !== "missing";
}

function getInviteAcceptanceUrl(inviteLike) {
  const invite = inviteLike && typeof inviteLike === "object" ? inviteLike : {};
  const inviteId = String(invite.inviteId || invite.id || "").trim();
  if (inviteId && shouldUseShortInviteLinks()) {
    const query = new URLSearchParams();
    query.set("id", inviteId);
    return `${getBaseAppUrl()}#/invite?${query.toString()}`;
  }

  const token = String(invite.token || invite.inviteToken || "").trim();
  if (!token) {
    return "";
  }
  const query = new URLSearchParams();
  query.set("token", token);
  const email = normalizeEmailAddress(invite.email);
  if (email) {
    query.set("email", email);
  }
  const name = String(invite.name || "").trim();
  if (name) {
    query.set("name", name);
  }
  const role = String(invite.role || "").trim();
  if (role) {
    query.set("role", role);
  }
  const team = String(invite.team || "").trim();
  if (team) {
    query.set("team", team);
  }
  const workspace = String(invite.workspace || state.data.workspace?.name || "").trim();
  if (workspace) {
    query.set("workspace", workspace);
  }
  const invitedBy = String(invite.invitedBy || invite.updatedBy || resolveCurrentUserName(state.data)).trim();
  if (invitedBy) {
    query.set("invitedBy", invitedBy);
  }
  return `${getBaseAppUrl()}#/invite?${query.toString()}`;
}

