function normalizeInviteLookupErrorMessage(message) {
  const text = String(message || "").trim();
  if (!text) {
    return "This invite could not be loaded.";
  }
  if (text.includes("Invite public API unavailable")) {
    return "This environment is missing the Supabase invite function. Ask your workspace admin to deploy the latest Edge Functions, then resend the invite.";
  }
  if (text.includes("Request failed (404)") || text.includes("Invite not found")) {
    return "This invite is not valid. Ask your workspace administrator for a new invite link.";
  }
  if (text.includes("Request failed (410)") || text.includes("Invite is no longer active")) {
    return "This invite is no longer active. Ask your workspace administrator for a new invite link.";
  }
  if (text.includes("Failed to fetch")) {
    return "The app could not load this invite right now. Check your connection and try again.";
  }
  return text;
}

function normalizeLoginEmailLookupErrorMessage(message) {
  const text = String(message || "").trim();
  if (!text) {
    return "We could not verify this invite right now. Please try again.";
  }
  if (text.includes("Failed to fetch")) {
    return "We could not verify this invite right now. Refresh and try again. If it keeps happening, ask your workspace admin to resend the invite.";
  }
  if (text.includes("Request failed (404)") || text.includes("Function not found")) {
    return "Invite verification is not available right now. Ask your workspace admin to resend the invite in a few minutes.";
  }
  return "We could not verify this invite right now. Please try again.";
}

async function fetchInviteContextById(inviteId) {
  const normalizedId = String(inviteId || "").trim();
  if (!normalizedId) {
    throw new Error("Invite id is required");
  }

  const response = await invokeSupabaseFunction("invite-resolve", {
    method: "GET",
    query: { id: normalizedId }
  });
  const result = await response.json().catch(() => ({}));
  if (!response.ok) {
    if (response.status === 404 && !String(result.error || "").trim()) {
      invitePublicApiAvailability = "missing";
      throw new Error("Invite public API unavailable");
    }
    throw new Error(result.error || `Request failed (${response.status})`);
  }
  invitePublicApiAvailability = "available";

  const invite = normalizeInviteContextRecord({
    ...(result.invite && typeof result.invite === "object" ? result.invite : {}),
    inviteId: normalizedId
  });
  if (!invite || !invite.token || !invite.email) {
    throw new Error("Invite details are incomplete.");
  }
  return invite;
}

function startInviteContextResolution(hashValue = window.location.hash) {
  const invite = getInviteAcceptanceContext(hashValue);
  const inviteId = String(invite?.inviteId || "").trim();
  const hasDetails = Boolean(invite?.token && invite?.email);
  if (!inviteId || hasDetails) {
    if (state.inviteLookupStatus.loading || state.inviteLookupStatus.inviteId || state.inviteLookupStatus.error) {
      setInviteLookupStatus(createEmptyInviteLookupStatus());
    }
    return;
  }

  if (state.inviteLookupStatus.loading && state.inviteLookupStatus.inviteId === inviteId) {
    return;
  }
  if (state.inviteLookupStatus.resolved && state.inviteLookupStatus.inviteId === inviteId && !state.inviteLookupStatus.error) {
    return;
  }

  const syncId = ++inviteLookupSyncSequence;
  setInviteLookupStatus({
    loading: true,
    inviteId,
    resolved: false,
    error: ""
  });
  state.inviteRouteMessage = "";
  state.inviteRouteLink = "";

  fetchInviteContextById(inviteId)
    .then((resolvedInvite) => {
      if (syncId !== inviteLookupSyncSequence) {
        return;
      }
      persistInviteContext({
        ...(invite && typeof invite === "object" ? invite : {}),
        ...resolvedInvite,
        inviteId
      });
      setInviteLookupStatus({
        loading: false,
        inviteId,
        resolved: true,
        error: ""
      });
      state.inviteRouteMessage = "";
      state.inviteRouteLink = "";
      if (state.routeId === "invite") {
        renderRoute();
      }
    })
    .catch((error) => {
      if (syncId !== inviteLookupSyncSequence) {
        return;
      }
      const message = normalizeInviteLookupErrorMessage(error?.message || error);
      setInviteLookupStatus({
        loading: false,
        inviteId,
        resolved: false,
        error: message
      });
      state.inviteRouteMessage = message;
      state.inviteRouteLink = "";
      if (state.routeId === "invite") {
        renderRoute();
      }
    });
}

async function copyTextWithFallback(text, promptLabel = "Copy value") {
  if (navigator.clipboard && typeof navigator.clipboard.writeText === "function") {
    await navigator.clipboard.writeText(text).catch(() => {
      window.prompt(promptLabel, text);
    });
    return;
  }
  window.prompt(promptLabel, text);
}

