async function refreshSupabaseLeadProfileData(options = {}) {
  if (!state.supabaseConfigured || !state.signedInUser) {
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  const leadId = String(options.leadId || state.selectedLeadId || "").trim();
  if (!leadId) {
    return false;
  }
  if (!isUuidLike(workspaceId)) {
    if (String((state.leadProfileData || {}).leadId || "").trim() === leadId) {
      state.leadProfileData = createEmptyLeadProfileData({ leadId });
    }
    return false;
  }

  const { render = state.routeId === "lead-profile", force = false, alertOnError = false } = options;
  const current = state.leadProfileData || createEmptyLeadProfileData();
  const cacheKey = buildLeadDetailCacheKey(workspaceId, leadId);
  const cachedBundle = readQueryCache(cacheKey, {
    staleMs: LEAD_PROFILE_CACHE_STALE_MS,
    maxAgeMs: LEAD_PROFILE_CACHE_MAX_AGE_MS
  });
  if (!force && current.leadId === leadId && current.loaded && (!cachedBundle || !cachedBundle.stale)) {
    return !current.error;
  }
  if (!force && current.leadId === leadId && current.loading) {
    return true;
  }

  if (cachedBundle?.value) {
    hydrateLeadProfileFromCachedBundle(leadId, cachedBundle.value);
    state.leadProfileData = createEmptyLeadProfileData({
      ...state.leadProfileData,
      leadId,
      loaded: true,
      loading: Boolean(cachedBundle.stale),
      error: "",
      lastAttemptAt: Number(cachedBundle.updatedAt || Date.now())
    });
    if (String(state.activeLeadDrawerId || "").trim() === leadId) {
      renderLeadDrawerModalContent(leadId);
    }
    if (render && state.routeId === "lead-profile" && String(state.selectedLeadId || "").trim() === leadId) {
      renderRoute();
    }
    if (!cachedBundle.stale) {
      return Boolean(cachedBundle.value?.lead);
    }
  } else {
    state.leadProfileData = createEmptyLeadProfileData({
      leadId,
      loading: true,
      error: "",
      lastAttemptAt: Date.now()
    });
  }

  const refreshSequence = ++leadProfileRefreshSequence;

  try {
    const bundle = await fetchAndCacheQuery(cacheKey, () =>
      fetchSupabaseLeadProfileBundle(workspaceId, leadId, {
        teamMembers: state.data.teamMembers
      })
    );
    if (refreshSequence !== leadProfileRefreshSequence) {
      return Boolean(bundle?.lead);
    }
    if (!bundle?.lead) {
      invalidateQueryCache(cacheKey);
    }
    hydrateLeadProfileFromCachedBundle(leadId, bundle);
    if (String(state.activeLeadDrawerId || "").trim() === leadId) {
      renderLeadDrawerModalContent(leadId);
    }
    if (render && state.routeId === "lead-profile" && String(state.selectedLeadId || "").trim() === leadId) {
      renderRoute();
    }
    return Boolean(bundle?.lead);
  } catch (error) {
    if (refreshSequence !== leadProfileRefreshSequence) {
      return false;
    }
    state.leadProfileData = createEmptyLeadProfileData({
      ...state.leadProfileData,
      leadId,
      loaded: Boolean(state.leadProfileData?.lead),
      loading: false,
      error: String(error?.message || error || "Lead profile sync failed."),
      lastAttemptAt: Date.now(),
      lastErrorAt: Date.now()
    });
    if (String(state.activeLeadDrawerId || "").trim() === leadId) {
      renderLeadDrawerModalContent(leadId);
    }
    console.error("Supabase lead profile sync failed:", error);
    if (render && state.routeId === "lead-profile" && String(state.selectedLeadId || "").trim() === leadId) {
      renderRoute();
    }
    if (alertOnError) {
      window.alert(`Lead profile sync failed: ${String(error?.message || error || "Unknown error")}`);
    }
    return false;
  }
}

async function refreshSupabaseContactProfileData(options = {}) {
  if (!state.supabaseConfigured || !state.signedInUser) {
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  const contactId = String(options.contactId || state.activeContactDrawerId || "").trim();
  if (!contactId || !isUuidLike(workspaceId)) {
    return false;
  }

  const { force = false } = options;
  const cacheKey = buildContactDetailCacheKey(workspaceId, contactId);
  const cachedBundle = readQueryCache(cacheKey, {
    staleMs: CRM_DETAIL_CACHE_STALE_MS,
    maxAgeMs: CRM_DETAIL_CACHE_MAX_AGE_MS
  });

  if (cachedBundle?.value) {
    hydrateContactProfileFromCachedBundle(cachedBundle.value);
    if (String(state.activeContactDrawerId || "").trim() === contactId) {
      renderContactDrawerModalContent(contactId);
    }
    if (!force && !cachedBundle.stale) {
      return Boolean(cachedBundle.value?.contact);
    }
  }

  const refreshSequence = ++contactProfileRefreshSequence;

  try {
    const bundle = await fetchAndCacheQuery(cacheKey, () =>
      fetchSupabaseContactProfileBundle(workspaceId, contactId, {
        teamMembers: state.data.teamMembers
      })
    );
    if (refreshSequence !== contactProfileRefreshSequence) {
      return Boolean(bundle?.contact);
    }
    if (!bundle?.contact) {
      invalidateQueryCache(cacheKey);
    }
    hydrateContactProfileFromCachedBundle(bundle);
    if (String(state.activeContactDrawerId || "").trim() === contactId) {
      renderContactDrawerModalContent(contactId);
    }
    return Boolean(bundle?.contact);
  } catch (error) {
    if (refreshSequence !== contactProfileRefreshSequence) {
      return false;
    }
    console.error("Supabase contact profile sync failed:", error);
    return false;
  }
}

