async function refreshSupabaseCrmCollectionData(routeId, options = {}) {
  const normalizedRouteId = String(routeId || "").trim();
  if (!["contacts", "accounts", "deals"].includes(normalizedRouteId)) {
    return false;
  }
  if (!state.supabaseConfigured || !state.signedInUser) {
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    return false;
  }

  const { render = state.routeId === normalizedRouteId, force = false, alertOnError = false } = options;
  const current = getCrmCollectionFetchState(normalizedRouteId);
  const queryKey = buildCrmCollectionCacheKey(workspaceId, normalizedRouteId);
  const cachedSnapshot = readQueryCache(queryKey, {
    staleMs: CRM_COLLECTION_CACHE_STALE_MS,
    maxAgeMs: CRM_COLLECTION_CACHE_MAX_AGE_MS
  });
  if (!force && current.loaded && current.queryKey === queryKey && (!cachedSnapshot || !cachedSnapshot.stale)) {
    return true;
  }
  if (!force && current.loading && current.queryKey === queryKey) {
    return true;
  }

  const fetchers = {
    contacts: fetchSupabaseContactsSnapshot,
    accounts: fetchSupabaseAccountsSnapshot,
    deals: fetchSupabaseDealsSnapshot
  };
  const fetcher = fetchers[normalizedRouteId];
  if (typeof fetcher !== "function") {
    return false;
  }

  if (cachedSnapshot?.value) {
    hydrateCrmCollectionFromCachedSnapshot(normalizedRouteId, cachedSnapshot.value, queryKey);
    updateCrmCollectionFetchState(normalizedRouteId, {
      queryKey,
      loaded: true,
      loading: Boolean(cachedSnapshot.stale),
      error: "",
      lastAttemptAt: Number(cachedSnapshot.updatedAt || Date.now())
    });
    setCrmCollectionLoading(normalizedRouteId, Boolean(cachedSnapshot.stale));
    if (render) {
      renderRoute();
    }
    if (!cachedSnapshot.stale) {
      return true;
    }
  } else {
    setCrmCollectionLoading(normalizedRouteId, true);
    updateCrmCollectionFetchState(normalizedRouteId, {
      queryKey,
      loaded: false,
      loading: true,
      error: "",
      lastAttemptAt: Date.now()
    });
    if (render && getCrmRouteRecordCount(normalizedRouteId) === 0) {
      renderRoute();
    }
  }

  setCrmCollectionLoading(normalizedRouteId, true);
  updateCrmCollectionFetchState(normalizedRouteId, {
    ...getCrmCollectionFetchState(normalizedRouteId),
    queryKey,
    loading: true,
    error: "",
    lastAttemptAt: Date.now()
  });

  try {
    const snapshot = await fetchAndCacheQuery(queryKey, () =>
      fetcher(workspaceId, {
        teamMembers: state.data.teamMembers
      })
    );
    hydrateCrmCollectionFromCachedSnapshot(normalizedRouteId, snapshot, queryKey);
    setCrmCollectionLoading(normalizedRouteId, false);
    updateCrmCollectionFetchState(normalizedRouteId, {
      queryKey,
      loaded: true,
      loading: false,
      error: "",
      lastAttemptAt: Date.now(),
      lastErrorAt: 0
    });
    if (render) {
      renderRoute();
    }
    return true;
  } catch (error) {
    setCrmCollectionLoading(normalizedRouteId, false);
    updateCrmCollectionFetchState(normalizedRouteId, {
      queryKey,
      loaded: Boolean(cachedSnapshot?.value),
      loading: false,
      error: String(error?.message || error || "Collection sync failed."),
      lastAttemptAt: Date.now(),
      lastErrorAt: Date.now()
    });
    console.error(`Supabase ${normalizedRouteId} sync failed:`, error);
    if (render) {
      renderRoute();
    }
    if (alertOnError) {
      const label = normalizedRouteId[0].toUpperCase() + normalizedRouteId.slice(1);
      window.alert(`${label} sync failed: ${String(error?.message || error || "Unknown error")}`);
    }
    return false;
  }
}

async function refreshSupabaseLeadsPageData(options = {}) {
  if (!shouldUseSupabaseLeadsRouteData()) {
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    return false;
  }

  const {
    render = state.routeId === "leads",
    persist = false,
    alertOnError = false,
    force = false,
    skipInitialRender = false,
    preserveInput = null
  } = options;
  const requestOptions = buildLeadsPageRequestOptions();
  const queryKey = buildLeadsPageRequestKey(workspaceId, requestOptions);
  const current = state.leadsPageData || createEmptyLeadsPageData();
  const cachedPage = readQueryCache(queryKey, {
    staleMs: LEADS_PAGE_CACHE_STALE_MS,
    maxAgeMs: LEADS_PAGE_CACHE_MAX_AGE_MS
  });
  const cursorState = resolveLeadsPageCursorForRequest(workspaceId, requestOptions, current);
  const queueLeadPageBackgroundRefresh = () => {
    void maybeRunLeadWeeklyCleanup(requestOptions).catch((cleanupError) => {
      console.warn("Weekly lead cleanup skipped:", cleanupError);
    });
    void refreshSupabaseLeadsPageMetaData(requestOptions).catch((metaError) => {
      console.warn("Lead page metadata refresh skipped:", metaError);
    });
  };

  if (!force && current.loaded && current.queryKey === queryKey && (!cachedPage || !cachedPage.stale)) {
    queueLeadPageBackgroundRefresh();
    return true;
  }
  if (!force && state.crmLoadingByRoute?.leads && current.queryKey === queryKey) {
    return true;
  }

  if (cachedPage?.value) {
    hydrateLeadsPageFromCachedResult(cachedPage.value, requestOptions, queryKey, current);
    state.leadsPageData = createEmptyLeadsPageData({
      ...state.leadsPageData,
      queryKey,
      rowLoading: false,
      loaded: true,
      error: "",
      lastAttemptAt: Number(cachedPage.updatedAt || Date.now())
    });
    state.crmLoadingByRoute = {
      ...state.crmLoadingByRoute,
      leads: Boolean(cachedPage.stale)
    };
    if (render && !skipInitialRender) {
      finishLeadsPageRefreshRender(preserveInput);
    }
    queueLeadPageBackgroundRefresh();
    if (!cachedPage.stale) {
      return true;
    }
  }

  if (!cachedPage?.value) {
    state.leadsPageData = createEmptyLeadsPageData({
      ...current,
      queryKey,
      lastKnownTotalCount: Number(current?.lastKnownTotalCount || current?.totalCount || 0),
      rowLoading: true,
      error: "",
      lastAttemptAt: Date.now(),
      scope: requestOptions.scope,
      statusFilter: requestOptions.statusFilter,
      dateFilter: requestOptions.dateFilter,
      sourceFilter: requestOptions.sourceFilter,
      timezoneFilter: requestOptions.timezoneFilter,
      ownerFilter: requestOptions.ownerFilter,
      page: requestOptions.page,
      pageSize: requestOptions.pageSize,
      sortKey: requestOptions.sortKey,
      sortDir: requestOptions.sortDir,
      sourceOptions:
        Array.isArray(current.sourceOptions) && current.sourceOptions.length
          ? current.sourceOptions
          : [{ id: "all", label: "All" }]
    });
  } else {
    state.leadsPageData = createEmptyLeadsPageData({
      ...state.leadsPageData,
      queryKey,
      lastKnownTotalCount: Number(state.leadsPageData?.lastKnownTotalCount || state.leadsPageData?.totalCount || 0),
      rowLoading: false,
      loaded: true,
      error: "",
      lastAttemptAt: Date.now(),
      scope: requestOptions.scope,
      statusFilter: requestOptions.statusFilter,
      dateFilter: requestOptions.dateFilter,
      sourceFilter: requestOptions.sourceFilter,
      timezoneFilter: requestOptions.timezoneFilter,
      ownerFilter: requestOptions.ownerFilter,
      page: requestOptions.page,
      pageSize: requestOptions.pageSize,
      sortKey: requestOptions.sortKey,
      sortDir: requestOptions.sortDir
    });
  }
  state.crmLoadingByRoute = {
    ...state.crmLoadingByRoute,
    leads: true
  };

  if (render && !skipInitialRender && !cachedPage?.value) {
    finishLeadsPageRefreshRender(preserveInput);
  }

  const refreshSequence = ++leadsPageRefreshSequence;

  try {
    const pageData = await fetchAndCacheQuery(queryKey, () =>
      fetchSupabaseLeadsPage(workspaceId, {
        ...requestOptions,
        includeMeta: false,
        ...(cursorState
          ? {
              cursor: cursorState.cursor,
              cursorDirection: cursorState.cursorDirection
            }
          : {})
      })
    );
    if (refreshSequence !== leadsPageRefreshSequence) {
      return true;
    }
    hydrateLeadsPageFromCachedResult(pageData, requestOptions, queryKey, current);
    if (Boolean(pageData?.hasNextPage ?? pageData?.hasMore)) {
      const nextPage = Math.max(1, Number(requestOptions.page || 1) + 1);
      void prefetchSupabaseLeadsPageData(requestOptions, nextPage).catch((prefetchError) => {
        console.warn("Lead page prefetch skipped:", prefetchError);
      });
    }
    state.crmLoadingByRoute = {
      ...state.crmLoadingByRoute,
      leads: false
    };
    if (persist) {
      saveData(state.data);
    }
    if (render) {
      finishLeadsPageRefreshRender(preserveInput);
    }
    queueLeadPageBackgroundRefresh();
    return true;
  } catch (error) {
    if (refreshSequence !== leadsPageRefreshSequence) {
      return false;
    }
    state.crmLoadingByRoute = {
      ...state.crmLoadingByRoute,
      leads: false
    };
    state.leadsPageData = {
      ...state.leadsPageData,
      rowLoading: false,
      loaded: Boolean((state.leadsPageData?.rows || []).length),
      error: String(error?.message || error || "Lead list sync failed."),
      lastErrorAt: Date.now()
    };
    console.error("Supabase leads page sync failed:", error);
    if (render) {
      finishLeadsPageRefreshRender(preserveInput);
    }
    if (alertOnError) {
      window.alert(`Lead list sync failed: ${String(error?.message || error || "Unknown error")}`);
    }
    return false;
  }
}

async function prefetchSupabaseLeadsPageData(requestOptions = {}, pageOverride = null) {
  if (!shouldUseSupabaseLeadsRouteData()) {
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    return false;
  }

  const nextPage = Math.max(1, Number(pageOverride || Number(requestOptions.page || 0) + 1) || 1);
  const prefetchOptions = {
    ...requestOptions,
    page: nextPage,
    includeMeta: false
  };
  const cursorState = resolveLeadsPageCursorForRequest(workspaceId, prefetchOptions, state.leadsPageData || createEmptyLeadsPageData());
  const queryKey = buildLeadsPageRequestKey(workspaceId, prefetchOptions);
  const cachedPage = readQueryCache(queryKey, {
    staleMs: LEADS_PAGE_CACHE_STALE_MS,
    maxAgeMs: LEADS_PAGE_CACHE_MAX_AGE_MS
  });
  if (cachedPage?.value && !cachedPage.stale) {
    return true;
  }
  if (cachedPage?.value && cachedPage.stale && !state.crmLoadingByRoute?.leads) {
    // Allow stale cache to be warmed quietly without blocking the active page.
  }

  try {
    await fetchAndCacheQuery(queryKey, () =>
      fetchSupabaseLeadsPage(workspaceId, {
        ...prefetchOptions,
        includeMeta: false,
        ...(cursorState
          ? {
              cursor: cursorState.cursor,
              cursorDirection: cursorState.cursorDirection
            }
          : {})
      })
    );
    return true;
  } catch (error) {
    console.warn("Lead page prefetch failed:", error);
    return false;
  }
}

async function refreshSupabaseCallsPerformanceData(options = {}) {
  if (!shouldUseSupabaseCallsPerformanceData()) {
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    return false;
  }

  if (!state.attendanceSnapshotLoaded) {
    try {
      await refreshSupabaseAttendanceData({
        render: false,
        persist: false,
        alertOnError: false
      });
    } catch (error) {
      console.warn("Attendance policy preload for calls performance failed:", error);
    }
  }

  let resolvedPerformancePolicy = getCallsPerformancePolicy();
  if (!state.attendanceSnapshotLoaded || !Object.keys(state.data?.attendancePolicy || {}).length) {
    try {
      const explicitPolicy = await fetchSupabaseAttendancePolicyForWorkspace(workspaceId);
      if (explicitPolicy && typeof explicitPolicy === "object" && Object.keys(explicitPolicy).length) {
        resolvedPerformancePolicy = {
          ...defaultAttendancePolicy(),
          ...explicitPolicy
        };
        state.data.attendancePolicy = structuredClone(resolvedPerformancePolicy);
        state.attendanceSnapshotLoaded = true;
      }
    } catch (error) {
      console.warn("Attendance policy fetch for calls performance failed:", error);
    }
  }

  const { render = state.routeId === "comms-calls" && state.callsView === "performance", force = false } = options;
  const requestCallsPerformanceRefreshRender = () => {
    if (render) {
      requestCallsPerformanceRouteRender();
    }
  };
  const requestWindow = buildCallsPerformanceRequestWindow(resolvedPerformancePolicy);
  const queryKey = buildCallsPerformanceRequestKey(workspaceId, requestWindow);
  const current = state.callsPerformanceData || createEmptyCallsPerformanceData();
  const cachedPerformance = readQueryCache(queryKey, {
    staleMs: CALLS_PERFORMANCE_CACHE_STALE_MS,
    maxAgeMs: CALLS_PERFORMANCE_CACHE_MAX_AGE_MS
  });

  if (!force && current.loaded && current.queryKey === queryKey && (!cachedPerformance || !cachedPerformance.stale)) {
    return true;
  }
  if (!force && current.loading && current.queryKey === queryKey) {
    return true;
  }

  if (cachedPerformance?.value) {
    state.callsPerformanceData = buildCallsPerformanceCachedState(
      queryKey,
      requestWindow,
      resolvedPerformancePolicy,
      cachedPerformance,
      current.sourceKind,
      { loading: Boolean(cachedPerformance.stale) }
    );
    requestCallsPerformanceRefreshRender();
    if (!cachedPerformance.stale && !force) {
      return true;
    }
  } else {
    state.callsPerformanceData = createEmptyCallsPerformanceData({
      queryKey,
      loading: true,
      error: "",
      lastAttemptAt: Date.now(),
      startIso: requestWindow.startIso,
      endIso: requestWindow.endIso,
      sourceKind: current.sourceKind,
      policy: structuredClone(resolvedPerformancePolicy)
    });

    requestCallsPerformanceRefreshRender();
  }

  const refreshSequence = ++callsPerformanceRefreshSequence;

  try {
    const result = await fetchAndCacheQuery(queryKey, () =>
      fetchSupabaseLeadStatusEvents(workspaceId, {
        teamMembers: state.data.teamMembers,
        startAt: requestWindow.startAt,
        endBefore: requestWindow.endBefore,
        timeZone: requestWindow.timeZone,
        shiftStart: requestWindow.shiftStart,
        shiftEnd: requestWindow.shiftEnd
      })
    );
    if (refreshSequence !== callsPerformanceRefreshSequence) {
      return true;
    }
    state.callsPerformanceData = createEmptyCallsPerformanceData({
      queryKey,
      loaded: true,
      loading: false,
      error: "",
      lastAttemptAt: Date.now(),
      lastErrorAt: 0,
      startIso: requestWindow.startIso,
      endIso: requestWindow.endIso,
      sourceKind: String(result?.sourceKind || "events").trim() || "events",
      policy: structuredClone(resolvedPerformancePolicy),
      events: Array.isArray(result?.events) ? result.events : []
    });
    prefetchCallsPerformanceDateWindows(workspaceId, resolvedPerformancePolicy);
    requestCallsPerformanceRefreshRender();
    return true;
  } catch (error) {
    if (refreshSequence !== callsPerformanceRefreshSequence) {
      return false;
    }
    state.callsPerformanceData = createEmptyCallsPerformanceData({
      queryKey,
      loaded: false,
      loading: false,
      error: String(error?.message || error || "Performance activity sync failed."),
      lastAttemptAt: current.lastAttemptAt || 0,
      lastErrorAt: Date.now(),
      startIso: requestWindow.startIso,
      endIso: requestWindow.endIso,
      sourceKind: current.sourceKind,
      policy: structuredClone(resolvedPerformancePolicy)
    });
    console.error("Supabase calls performance sync failed:", error);
    requestCallsPerformanceRefreshRender();
    return false;
  }
}

function getCrmRouteRecordCount(routeId = state.routeId) {
  if (routeId === "leads") {
    return Array.isArray(state.data.leads) ? state.data.leads.length : 0;
  }
  if (routeId === "contacts") {
    return Array.isArray(state.data.contacts) ? state.data.contacts.length : 0;
  }
  if (routeId === "accounts") {
    return Array.isArray(state.data.accounts) ? state.data.accounts.length : 0;
  }
  if (routeId === "deals") {
    return Array.isArray(state.data.deals) ? state.data.deals.length : 0;
  }
  return 0;
}

async function refreshSupabaseCrmData(options = {}) {
  if (!state.supabaseConfigured || !state.signedInUser) {
    resetSystemHealthEntry("crmSync");
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    resetSystemHealthEntry("crmSync");
    return false;
  }

  const {
    render = true,
    persist = true,
    alertOnError = false,
    syncDashboard = state.routeId === "dashboard"
  } = options;
  const shouldRenderCrmSkeleton =
    !render &&
    ["leads", "contacts", "accounts", "deals"].includes(String(state.routeId || "").trim()) &&
    getCrmRouteRecordCount(state.routeId) === 0;
  setCrmLoadingState(true);
  if (shouldRenderCrmSkeleton) {
    renderRoute();
  }

  try {
    const snapshot = await withRetryableSystemSync(
      "crmSync",
      async () => fetchSupabaseCrmSnapshot(workspaceId, {
        teamMembers: state.data.teamMembers
      }),
      {
        label: "CRM sync",
        source: "snapshot:crm",
        attempts: 3,
        failureDetail: "CRM records could not be refreshed."
      }
    );
    applySupabaseCrmSnapshot(snapshot);
    try {
      state.data.leadActivityEvents = await fetchSupabaseLeadActivityEvents(workspaceId, {
        teamMembers: state.data.teamMembers,
        limit: 500
      });
    } catch (activityError) {
      console.warn("Lead activity audit sync failed:", activityError);
      if (!Array.isArray(state.data.leadActivityEvents)) {
        state.data.leadActivityEvents = [];
      }
    }
    clearQueryCache({ preservePersistent: true });
    invalidateDashboardCaches(workspaceId);
    if (syncDashboard) {
      await refreshSupabaseDashboardData({
        render: state.routeId === "dashboard",
        alertOnError: false,
        force: true
      });
    }
    setCrmLoadingState(false);
    if (persist) {
      saveData(state.data);
    }
    if (render || shouldRenderCrmSkeleton) {
      renderRoute();
    }
    return true;
  } catch (error) {
    setCrmLoadingState(false);
    console.error("Supabase CRM sync failed:", error);
    if (shouldRenderCrmSkeleton) {
      renderRoute();
    }
    if (alertOnError) {
      window.alert(`CRM data sync failed: ${String(error?.message || error || "Unknown error")}`);
    }
    return false;
  }
}

async function refreshSupabaseWorkData(options = {}) {
  if (!state.supabaseConfigured || !state.signedInUser) {
    clearSupabaseWorkState();
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    clearSupabaseWorkState();
    return false;
  }

  const {
    render = true,
    persist = false,
    alertOnError = false,
    syncDashboard = state.routeId === "dashboard"
  } = options;

  try {
    const snapshot = await withRetryableSystemSync(
      "workSync",
      async () => fetchSupabaseWorkSnapshot(),
      {
        label: "Work sync",
        source: "rpc:get_work_snapshot",
        attempts: 3,
        failureDetail: "Projects and tasks could not be refreshed."
      }
    );
    applyWorkSnapshotResult(snapshot, { persist, render, invalidateDashboard: false });
    if (syncDashboard) {
      invalidateDashboardCaches(workspaceId);
      await refreshSupabaseDashboardData({
        render: state.routeId === "dashboard",
        alertOnError: false,
        force: true
      });
    }
    return true;
  } catch (error) {
    console.error("Supabase work sync failed:", error);
    if (alertOnError) {
      window.alert(`Work data sync failed: ${String(error?.message || error || "Unknown error")}`);
    }
    return false;
  }
}

async function refreshSupabaseAttendanceData(options = {}) {
  if (!state.supabaseConfigured || !state.signedInUser) {
    clearSupabaseAttendanceState();
    return false;
  }

  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    clearSupabaseAttendanceState();
    return false;
  }

  const { render = true, persist = false, alertOnError = false } = options;

  try {
    const snapshot = await withRetryableSystemSync(
      "attendanceSync",
      async () => fetchSupabaseAttendanceSnapshot(),
      {
        label: "Attendance sync",
        source: "rpc:get_attendance_snapshot",
        attempts: 3,
        failureDetail: "Attendance records could not be refreshed."
      }
    );
    let resolvedSnapshot = snapshot;
    try {
      const explicitPolicy = await fetchSupabaseAttendancePolicyForWorkspace(workspaceId);
      if (explicitPolicy && typeof explicitPolicy === "object") {
        resolvedSnapshot = {
          ...snapshot,
          policy: explicitPolicy
        };
      }
    } catch (policyError) {
      console.warn("Attendance policy overlay sync failed:", policyError);
    }
    applySupabaseAttendanceSnapshot(resolvedSnapshot);
    if (persist) {
      saveData(state.data);
    }
    if (render) {
      if (state.routeId === "comms-calls" && state.callsView === "performance") {
        requestCallsPerformanceRouteRender();
      } else {
        renderRoute();
      }
    }
    return true;
  } catch (error) {
    console.error("Supabase attendance sync failed:", error);
    if (alertOnError) {
      window.alert(`Attendance sync failed: ${String(error?.message || error || "Unknown error")}`);
    }
    return false;
  }
}

function isSupabaseWorkWriteEnabled() {
  return Boolean(
    state.supabaseConfigured &&
      state.signedInUser &&
      state.authAccessState === "granted" &&
      String(state.data.workspace?.id || "").trim()
  );
}

function isSupabaseCrmWriteEnabled() {
  return Boolean(
    state.supabaseConfigured &&
      state.signedInUser &&
      state.authAccessState === "granted" &&
      String(state.data.workspace?.id || "").trim()
  );
}

function isSupabaseTeamWriteEnabled() {
  return Boolean(
    state.supabaseConfigured &&
      state.signedInUser &&
      state.authAccessState === "granted" &&
      String(state.data.workspace?.id || "").trim()
  );
}

function isSupabaseMessengerEnabled() {
  return Boolean(
    state.supabaseConfigured &&
      state.signedInUser &&
      state.authAccessState === "granted" &&
      canAccessMessenger() &&
      String(state.data.workspace?.id || "").trim()
  );
}

function getConnectedWorkspaceUnavailableMessage(subject = "This action") {
  const label = String(subject || "This action").trim() || "This action";
  if (!state.supabaseConfigured) {
    return "";
  }
  if (!state.signedInUser) {
    return `${label} requires you to sign in to the connected workspace first.`;
  }
  if (state.authAccessState !== "granted") {
    return String(state.authAccessMessage || "Workspace access is still loading. Try again in a moment.").trim();
  }
  if (!String(state.data.workspace?.id || "").trim()) {
    return "Workspace data is still loading. Try again in a moment.";
  }
  return `${label} requires the connected workspace backend.`;
}

function blockConnectedModeLocalFallback(subject, options = {}) {
  if (!state.supabaseConfigured) {
    return false;
  }
  const message = getConnectedWorkspaceUnavailableMessage(subject);
  if (!message) {
    return false;
  }
  const form = options.form;
  if (form instanceof HTMLFormElement) {
    const feedbackOptions = options.fieldSelector ? { fieldSelector: options.fieldSelector } : {};
    showFormFeedback(form, message, feedbackOptions);
  } else {
    window.alert(message);
  }
  return true;
}

function findTeamMemberByName(name) {
  const normalizedName = normalizeForMatch(name);
  if (!normalizedName) {
    return null;
  }
  const teamMembers = Array.isArray(state.data.teamMembers) ? state.data.teamMembers : [];
  const exactMatch =
    teamMembers.find((member) => normalizeForMatch(member.name) === normalizedName) || null;
  if (exactMatch) {
    return exactMatch;
  }

  return (
    teamMembers.find((member) => {
      const memberName = normalizeForMatch(member.name);
      const firstName = memberName.split(" ")[0] || "";
      return (
        firstName === normalizedName ||
        memberName.startsWith(`${normalizedName} `) ||
        normalizedName.startsWith(`${firstName} `)
      );
    }) || null
  );
}

function findTeamMemberById(memberId) {
  const normalizedId = String(memberId || "").trim();
  if (!normalizedId) {
    return null;
  }
  return (
    (Array.isArray(state.data.teamMembers) ? state.data.teamMembers : []).find(
      (member) => String(member.id || "").trim() === normalizedId
    ) || null
  );
}

function resolveTeamMemberIdByName(name, fallbackToCurrentUser = true) {
  const matchedMember = findTeamMemberByName(name);
  if (matchedMember?.id) {
    return String(matchedMember.id || "").trim();
  }
  return fallbackToCurrentUser ? resolveCurrentUserId(state.data) : "";
}

function findAccountByName(name) {
  const normalizedName = normalizeForMatch(name);
  if (!normalizedName) {
    return null;
  }
  return (
    (state.data.accounts || []).find(
      (account) => !account.archived && normalizeForMatch(account.name) === normalizedName
    ) || null
  );
}

function buildCrmMutationMeta(source, extra = {}) {
  const baseMeta = source && typeof source === "object" && source.meta && typeof source.meta === "object" ? source.meta : {};
  return {
    ...baseMeta,
    ...extra
  };
}

function normalizeLeadAttemptCountValue(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) {
    return 0;
  }
  return Math.max(0, Math.min(3, Math.round(numeric)));
}

function normalizeLeadAttemptIso(value) {
  const text = String(value || "").trim();
  if (!text) {
    return "";
  }
  const parsed = Date.parse(text);
  return Number.isFinite(parsed) ? new Date(parsed).toISOString() : "";
}

function normalizeLeadAttemptHistoryEntriesValue(value) {
  if (!Array.isArray(value)) {
    return [];
  }
  return value
    .filter((entry) => entry && typeof entry === "object")
    .map((entry) => {
      const reason = String(entry.reason || entry.text || "").trim();
      const note = String(entry.note || "").trim();
      const createdAt = normalizeLeadAttemptIso(entry.createdAt || entry.loggedAt);
      const actor = String(entry.actor || "").trim();
      const outcome = String(entry.outcome || "").trim();
      return {
        id: String(entry.id || "").trim(),
        createdAt,
        reason: reason || "Outreach attempt logged.",
        note,
        actor,
        outcome
      };
    })
    .filter((entry) => Boolean(entry.createdAt) || Boolean(entry.reason) || Boolean(entry.note) || Boolean(entry.actor));
}

function normalizeLeadWeeklyRemovalStateValue(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === LEAD_WEEKLY_REMOVAL_PENDING || normalized === LEAD_WEEKLY_REMOVAL_REMOVED) {
    return normalized;
  }
  return "";
}

function normalizeLeadWeeklyRemovalDueAtValue(value) {
  const parsed = Date.parse(String(value || "").trim());
  if (!Number.isFinite(parsed)) {
    return "";
  }
  const offsetMs = LEAD_WEEKLY_REMOVAL_TIMEZONE_OFFSET_HOURS * 60 * 60 * 1000;
  const localDate = new Date(parsed + offsetMs);
  const isFriday = localDate.getUTCDay() === LEAD_WEEKLY_REMOVAL_WEEKDAY;
  const isBeforeCutoff =
    localDate.getUTCHours() < LEAD_WEEKLY_REMOVAL_CUTOFF_HOUR ||
    (
      localDate.getUTCHours() === LEAD_WEEKLY_REMOVAL_CUTOFF_HOUR &&
      localDate.getUTCMinutes() === 0 &&
      localDate.getUTCSeconds() === 0 &&
      localDate.getUTCMilliseconds() === 0
    );
  if (isFriday && isBeforeCutoff) {
    return new Date(
      Date.UTC(
        localDate.getUTCFullYear(),
        localDate.getUTCMonth(),
        localDate.getUTCDate(),
        LEAD_WEEKLY_REMOVAL_CUTOFF_HOUR,
        0,
        0,
        0
      ) - offsetMs
    ).toISOString();
  }
  return new Date(parsed).toISOString();
}

function getLeadAttemptTrackingMeta(source = null) {
  const baseMeta = source && typeof source === "object" && source.meta && typeof source.meta === "object" ? source.meta : {};
  return {
    attemptCount: normalizeLeadAttemptCountValue(baseMeta.attemptCount),
    lastAttemptAt: normalizeLeadAttemptIso(baseMeta.lastAttemptAt),
    lastAttemptReason: String(baseMeta.lastAttemptReason || "").trim(),
    assignedAt: normalizeLeadAttemptIso(baseMeta.assignedAt) || normalizeLeadAttemptIso(source?.createdAt),
    attemptHistory: normalizeLeadAttemptHistoryEntriesValue(baseMeta.attemptHistory)
  };
}

function isLeadAttemptLimitReached(source = null) {
  return getLeadAttemptTrackingMeta(source).attemptCount >= 3;
}

function getLeadWeeklyRemovalMeta(source = null) {
  const baseMeta = source && typeof source === "object" && source.meta && typeof source.meta === "object" ? source.meta : {};
  return {
    unqualifiedAt: normalizeLeadAttemptIso(baseMeta.unqualifiedAt),
    removalDueAt: normalizeLeadWeeklyRemovalDueAtValue(baseMeta.unqualifiedRemovalDueAt),
    removalState: normalizeLeadWeeklyRemovalStateValue(baseMeta.unqualifiedRemovalState),
    removedFromActiveAt: normalizeLeadAttemptIso(baseMeta.removedFromActiveAt),
    removedFromActiveReason: String(baseMeta.removedFromActiveReason || "").trim()
  };
}

function getLeadAttemptWeeklyRemovalMeta(source = null) {
  const baseMeta = source && typeof source === "object" && source.meta && typeof source.meta === "object" ? source.meta : {};
  return {
    attemptLimitAt: normalizeLeadAttemptIso(baseMeta.attemptLimitAt),
    removalDueAt: normalizeLeadWeeklyRemovalDueAtValue(baseMeta.attemptLimitRemovalDueAt),
    removalState: normalizeLeadWeeklyRemovalStateValue(baseMeta.attemptLimitRemovalState),
    removedFromActiveAt: normalizeLeadAttemptIso(baseMeta.attemptLimitRemovedFromActiveAt),
    removedFromActiveReason: String(baseMeta.attemptLimitRemovedFromActiveReason || "").trim()
  };
}

function resolveLeadWeeklyRemovalDueAtValue(referenceIso = new Date().toISOString()) {
  const parsed = Date.parse(String(referenceIso || "").trim());
  const date = Number.isFinite(parsed) ? new Date(parsed) : new Date();
  const localOffsetMs = LEAD_WEEKLY_REMOVAL_TIMEZONE_OFFSET_HOURS * 60 * 60 * 1000;
  const localNow = new Date(date.getTime() + localOffsetMs);
  const localWeekday = localNow.getUTCDay();
  const localHour = localNow.getUTCHours();
  const localMinute = localNow.getUTCMinutes();
  const localSecond = localNow.getUTCSeconds();
  const localMillisecond = localNow.getUTCMilliseconds();
  const daysUntilFriday = (LEAD_WEEKLY_REMOVAL_WEEKDAY - localWeekday + 7) % 7;
  const passedFridayCutoff =
    localWeekday > LEAD_WEEKLY_REMOVAL_WEEKDAY ||
    (
      localWeekday === LEAD_WEEKLY_REMOVAL_WEEKDAY &&
      (
        localHour > LEAD_WEEKLY_REMOVAL_CUTOFF_HOUR ||
        (
          localHour === LEAD_WEEKLY_REMOVAL_CUTOFF_HOUR &&
          (localMinute > 0 || localSecond > 0 || localMillisecond > 0)
        )
      )
    );
  const targetDays = passedFridayCutoff ? daysUntilFriday || 7 : daysUntilFriday;
  return new Date(
    Date.UTC(
      localNow.getUTCFullYear(),
      localNow.getUTCMonth(),
      localNow.getUTCDate() + targetDays,
      LEAD_WEEKLY_REMOVAL_CUTOFF_HOUR,
      0,
      0,
      0
    ) - localOffsetMs
  ).toISOString();
}

function buildLeadWeeklyRemovalBackfillMeta(sourceLead, nowIso = new Date().toISOString()) {
  const lifecycle = getLeadWeeklyRemovalMeta(sourceLead);
  return {
    unqualifiedAt: lifecycle.unqualifiedAt || nowIso,
    unqualifiedRemovalDueAt: lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(nowIso),
    unqualifiedRemovalState: lifecycle.removalState || LEAD_WEEKLY_REMOVAL_PENDING,
    removedFromActiveAt: "",
    removedFromActiveReason: ""
  };
}

function buildLeadWeeklyRemovalArchiveMeta(sourceLead, archivedAt = new Date().toISOString()) {
  const lifecycle = getLeadWeeklyRemovalMeta(sourceLead);
  return {
    unqualifiedAt: lifecycle.unqualifiedAt || archivedAt,
    unqualifiedRemovalDueAt: lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(archivedAt),
    unqualifiedRemovalState: LEAD_WEEKLY_REMOVAL_REMOVED,
    removedFromActiveAt: archivedAt,
    removedFromActiveReason: LEAD_WEEKLY_REMOVAL_REASON
  };
}

function buildLeadAttemptWeeklyRemovalBackfillMeta(sourceLead, nowIso = new Date().toISOString()) {
  const lifecycle = getLeadAttemptWeeklyRemovalMeta(sourceLead);
  return {
    attemptLimitAt: lifecycle.attemptLimitAt || nowIso,
    attemptLimitRemovalDueAt: lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(nowIso),
    attemptLimitRemovalState: lifecycle.removalState || LEAD_WEEKLY_REMOVAL_PENDING,
    attemptLimitRemovedFromActiveAt: "",
    attemptLimitRemovedFromActiveReason: ""
  };
}

function buildLeadAttemptWeeklyRemovalArchiveMeta(sourceLead, archivedAt = new Date().toISOString()) {
  const lifecycle = getLeadAttemptWeeklyRemovalMeta(sourceLead);
  return {
    attemptLimitAt: lifecycle.attemptLimitAt || archivedAt,
    attemptLimitRemovalDueAt: lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(archivedAt),
    attemptLimitRemovalState: LEAD_WEEKLY_REMOVAL_REMOVED,
    attemptLimitRemovedFromActiveAt: archivedAt,
    attemptLimitRemovedFromActiveReason: LEAD_WEEKLY_ATTEMPT_REMOVAL_REASON
  };
}

function buildLeadUnqualifiedRemovalMetaPatch(sourceLead, nextStatus, nowIso = new Date().toISOString()) {
  const normalizedNextStatus = String(nextStatus || "").trim();
  const lifecycle = getLeadWeeklyRemovalMeta(sourceLead);
  const hadWeeklyRemovalMeta =
    Boolean(lifecycle.unqualifiedAt) ||
    Boolean(lifecycle.removalDueAt) ||
    Boolean(lifecycle.removalState) ||
    Boolean(lifecycle.removedFromActiveAt) ||
    Boolean(lifecycle.removedFromActiveReason);

  if (normalizedNextStatus === "Unqualified") {
    return {
      ...buildLeadWeeklyRemovalBackfillMeta(sourceLead, nowIso),
      removedFromActiveAt: "",
      removedFromActiveReason: ""
    };
  }

  if (!hadWeeklyRemovalMeta && String(sourceLead?.status || "").trim() !== "Unqualified") {
    return {};
  }

  return {
    unqualifiedAt: "",
    unqualifiedRemovalDueAt: "",
    unqualifiedRemovalState: "",
    removedFromActiveAt: "",
    removedFromActiveReason: ""
  };
}

function needsLeadWeeklyRemovalBackfill(sourceLead) {
  if (!sourceLead || String(sourceLead?.status || "").trim() !== "Unqualified" || Boolean(sourceLead?.archived)) {
    return false;
  }
  const lifecycle = getLeadWeeklyRemovalMeta(sourceLead);
  if (lifecycle.removalState === LEAD_WEEKLY_REMOVAL_REMOVED) {
    return false;
  }
  return !lifecycle.unqualifiedAt || !lifecycle.removalDueAt || !lifecycle.removalState;
}

function isLeadPendingWeeklyRemoval(sourceLead) {
  if (!sourceLead || String(sourceLead?.status || "").trim() !== "Unqualified" || Boolean(sourceLead?.archived)) {
    return false;
  }
  const lifecycle = getLeadWeeklyRemovalMeta(sourceLead);
  const dueAt = lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(new Date().toISOString());
  return lifecycle.removalState !== LEAD_WEEKLY_REMOVAL_REMOVED && Boolean(dueAt);
}

function isLeadWeeklyRemovalDue(sourceLead, referenceIso = new Date().toISOString()) {
  if (!isLeadPendingWeeklyRemoval(sourceLead)) {
    return false;
  }
  const lifecycle = getLeadWeeklyRemovalMeta(sourceLead);
  const dueAt = lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(referenceIso);
  const dueMs = Date.parse(dueAt);
  const referenceMs = Date.parse(String(referenceIso || "").trim());
  if (!Number.isFinite(dueMs) || !Number.isFinite(referenceMs)) {
    return false;
  }
  return dueMs <= referenceMs;
}

function needsLeadAttemptWeeklyRemovalBackfill(sourceLead) {
  if (!sourceLead || Boolean(sourceLead?.archived)) {
    return false;
  }
  const attemptTracking = getLeadAttemptTrackingMeta(sourceLead);
  if (attemptTracking.attemptCount < 3) {
    return false;
  }
  const status = String(sourceLead?.status || "").trim();
  if (["Qualified", "Unqualified", "Converted"].includes(status)) {
    return false;
  }
  const lifecycle = getLeadAttemptWeeklyRemovalMeta(sourceLead);
  return !lifecycle.attemptLimitAt || !lifecycle.removalDueAt || !lifecycle.removalState;
}

function isLeadPendingAttemptWeeklyRemoval(sourceLead) {
  if (!sourceLead || Boolean(sourceLead?.archived)) {
    return false;
  }
  const attemptTracking = getLeadAttemptTrackingMeta(sourceLead);
  if (attemptTracking.attemptCount < 3) {
    return false;
  }
  const status = String(sourceLead?.status || "").trim();
  if (["Qualified", "Unqualified", "Converted"].includes(status)) {
    return false;
  }
  const lifecycle = getLeadAttemptWeeklyRemovalMeta(sourceLead);
  const dueAt = lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(new Date().toISOString());
  return lifecycle.removalState !== LEAD_WEEKLY_REMOVAL_REMOVED && Boolean(dueAt);
}

function isLeadAttemptWeeklyRemovalDue(sourceLead, referenceIso = new Date().toISOString()) {
  if (!isLeadPendingAttemptWeeklyRemoval(sourceLead)) {
    return false;
  }
  const lifecycle = getLeadAttemptWeeklyRemovalMeta(sourceLead);
  const dueAt = lifecycle.removalDueAt || resolveLeadWeeklyRemovalDueAtValue(referenceIso);
  const dueMs = Date.parse(dueAt);
  const referenceMs = Date.parse(String(referenceIso || "").trim());
  if (!Number.isFinite(dueMs) || !Number.isFinite(referenceMs)) {
    return false;
  }
  return dueMs <= referenceMs;
}

function resolveLeadAssignedAtValue(existingLead, nextOwner, fallbackIso = new Date().toISOString()) {
  if (!existingLead) {
    return fallbackIso;
  }
  const currentTracking = getLeadAttemptTrackingMeta(existingLead);
  const previousOwnerId = String(existingLead?.ownerId || resolveTeamMemberIdByName(existingLead?.owner) || "").trim();
  const nextOwnerId = String(resolveTeamMemberIdByName(nextOwner) || "").trim();
  const previousOwnerKey = previousOwnerId || normalizeForMatch(existingLead?.owner);
  const nextOwnerKey = nextOwnerId || normalizeForMatch(nextOwner);
  const ownerChanged = Boolean(previousOwnerKey || nextOwnerKey) && previousOwnerKey !== nextOwnerKey;
  if (ownerChanged) {
    return fallbackIso;
  }
  return currentTracking.assignedAt || normalizeLeadAttemptIso(existingLead?.createdAt) || fallbackIso;
}

function resolveLeadWeeklyRedistributionDueAtValue(referenceIso = new Date().toISOString()) {
  return resolveLeadWeeklyRemovalDueAtValue(referenceIso);
}

function isLeadPendingFridayRedistributionDue(lead, referenceIso = new Date().toISOString()) {
  if (!lead || Boolean(lead?.archived) || normalizeLeadAttemptIso(lead?.archivedAt)) {
    return false;
  }
  if (String(lead?.status || "").trim() !== "New") {
    return false;
  }
  if (String(lead?.ownerId || "").trim()) {
    return false;
  }
  const createdAt = normalizeLeadAttemptIso(lead?.createdAt) || normalizeLeadAttemptIso(lead?.updatedAt) || "";
  const dueAt = resolveLeadWeeklyRedistributionDueAtValue(createdAt || referenceIso);
  const dueMs = Date.parse(String(dueAt || "").trim());
  const referenceMs = Date.parse(String(referenceIso || "").trim());
  if (!Number.isFinite(dueMs) || !Number.isFinite(referenceMs)) {
    return false;
  }
  return dueMs <= referenceMs;
}

function buildLeadStatusChangeMeta(sourceLead, nextStatus, nowIso = new Date().toISOString()) {
  const previousStatus = String(sourceLead?.status || "").trim();
  const normalizedStatus = String(nextStatus || "").trim();
  const currentMemberId = resolveCurrentUserId(state.data) || "";
  const currentMemberName = String(state.data.currentUser?.name || "").trim();
  return {
    lastStatusChangedAt: nowIso,
    lastStatusChangedByMemberId: currentMemberId,
    lastStatusChangedByName: currentMemberName,
    lastStatusChangedFrom: previousStatus,
    lastStatusChangedTo: normalizedStatus
  };
}

function buildLeadStatusMetaPatch(sourceLead, nextStatus, nowIso = new Date().toISOString()) {
  return {
    ...buildLeadStatusChangeMeta(sourceLead, nextStatus, nowIso),
    ...buildLeadUnqualifiedRemovalMetaPatch(sourceLead, nextStatus, nowIso)
  };
}

function normalizeLeadAttemptReasonKey(reason) {
  return String(reason || "").trim().replace(/\s+/g, " ").toLowerCase();
}

function isLeadUnqualifiedAttemptReason(reason) {
  return LEAD_UNQUALIFIED_ATTEMPT_REASONS.has(normalizeLeadAttemptReasonKey(reason));
}

function buildLeadAttemptMutation(sourceLead, reason, note = "", actorName = "", nowIso = new Date().toISOString()) {
  const attemptTracking = getLeadAttemptTrackingMeta(sourceLead);
  const currentCount = normalizeLeadAttemptCountValue(attemptTracking.attemptCount);
  const nextAttemptCount = Math.max(0, Math.min(3, currentCount + 1));
  const currentStatus = String(sourceLead?.status || "").trim();
  const shouldUnqualify = isLeadUnqualifiedAttemptReason(reason);
  const nextStatus =
    currentStatus === "Unqualified"
      ? "Unqualified"
      : shouldUnqualify
        ? "Unqualified"
        : currentStatus === "New" || !currentStatus
          ? "Contacted"
          : currentStatus;
  const statusChangedByAttempt = currentStatus !== nextStatus;
  const autoContacted = currentStatus === "New" && nextStatus === "Contacted";
  const autoUnqualified = currentStatus !== "Unqualified" && nextStatus === "Unqualified";
  const assignedAt = attemptTracking.assignedAt || resolveLeadAssignedAtValue(sourceLead, sourceLead.owner, nowIso);
  const existingHistory = Array.isArray(attemptTracking.attemptHistory)
    ? attemptTracking.attemptHistory.filter((entry) => entry && typeof entry === "object")
    : [];
  const nextHistory = [
    ...existingHistory,
    {
      id: createId("lath"),
      createdAt: nowIso,
      reason: String(reason || "").trim(),
      note: String(note || "").trim(),
      actor: String(actorName || "").trim(),
      outcome: nextStatus
    }
  ];
  return {
    attemptTracking,
    nextAttemptCount,
    nextStatus,
    autoContacted,
    autoUnqualified,
    statusChangedByAttempt,
    metaPatch: {
      attemptCount: nextAttemptCount,
      lastAttemptAt: nowIso,
      lastAttemptReason: String(reason || "").trim(),
      attemptHistory: nextHistory,
      assignedAt,
      ...(nextAttemptCount >= 3 ? buildLeadAttemptWeeklyRemovalBackfillMeta(sourceLead, nowIso) : {}),
      ...(statusChangedByAttempt ? buildLeadStatusMetaPatch(sourceLead, nextStatus, nowIso) : {})
    }
  };
}

async function persistLeadAttemptChange(leadId, reason, note = "", options = {}) {
  const lead = getLeadById(leadId);
  const normalizedReason = String(reason || "").trim();
  const normalizedNote = String(note || "").trim();
  const { refreshDashboard = true, form = null } = options;
  if (!lead || !normalizedReason || isLeadAttemptLimitReached(lead)) {
    return false;
  }

  const nowIso = new Date().toISOString();
  const currentMemberId = resolveCurrentUserId(state.data) || "";
  const currentMemberName = String(state.data.currentUser?.name || "").trim();
  const { nextAttemptCount, nextStatus, autoContacted, autoUnqualified, metaPatch } = buildLeadAttemptMutation(
    lead,
    normalizedReason,
    normalizedNote,
    currentMemberName,
    nowIso
  );

  if (isSupabaseCrmWriteEnabled()) {
    await updateSupabaseLead(
      lead.id,
      buildSupabaseLeadPayload(
        {
          name: lead.name,
          company: lead.company,
          source: lead.source,
          status: nextStatus,
          owner: lead.owner,
          nextFollowUp: lead.nextFollowUp,
          email: lead.email || "",
          phone: lead.phone || "",
          secondaryPhone: lead.secondaryPhone || "",
          interest: lead.interest || "",
          role: lead.role || "",
          notes: lead.notes || "",
          tags: lead.tags || []
        },
        {
          existing: lead,
          archivedAt: lead.archived ? lead.archivedAt || nowIso : null,
          meta: metaPatch
        }
      )
    );
  } else if (blockConnectedModeLocalFallback("Logging lead attempts", { form })) {
    return false;
  }

  patchLeadAcrossCaches(lead.id, {
    status: nextStatus,
    meta: {
      ...(lead.meta && typeof lead.meta === "object" ? lead.meta : {}),
      ...metaPatch
    },
    updatedAt: nowIso,
    updatedById: currentMemberId,
    updatedBy: currentMemberName
  });
  invalidateCallsPerformanceCaches();
  state.callsPerformanceData = createEmptyCallsPerformanceData({
    sourceKind: state.callsPerformanceData?.sourceKind || "events"
  });
  if (refreshDashboard) {
    revalidateDashboardAfterMutation({ render: false });
  }

  pushLeadActivity({
    leadId: lead.id,
    type: "lead-attempt-logged",
    text: `Attempt ${nextAttemptCount}/3 logged: ${normalizedReason}.${normalizedNote ? ` ${normalizedNote}` : ""}${autoContacted ? " Lead moved to Contacted." : ""}${autoUnqualified ? " Lead moved to Unqualified." : ""}`
  });
  return {
    leadId: lead.id,
    nextAttemptCount,
    nextStatus,
    autoContacted,
    autoUnqualified
  };
}

function buildSupabaseLeadPayload(values, options = {}) {
  const existing = options.existing || null;
  const workspaceId = String(state.data.workspace?.id || "").trim();
  const currentMemberId = resolveCurrentUserId(state.data) || null;
  const account = findAccountByName(values.company);
  return {
    workspace_id: workspaceId,
    account_id: account?.id || null,
    name: String(values.name || "").trim(),
    company_name: String(values.company || "").trim(),
    email: normalizeEmailAddress(values.email),
    phone: String(values.phone || "").trim(),
    secondary_phone: String(values.secondaryPhone || "").trim(),
    role: String(values.role || "").trim(),
    interest: String(values.interest || "").trim(),
    source: String(values.source || "Inbound").trim() || "Inbound",
    status: String(values.status || "New").trim() || "New",
    owner_member_id: resolveTeamMemberIdByName(values.owner) || currentMemberId,
    next_follow_up_date: String(values.nextFollowUp || "").trim() || null,
    crm_conversation_id: String(existing?.crmConversationId || "").trim() || null,
    notes: String(values.notes || "").trim(),
    tags: Array.isArray(values.tags) ? values.tags : [],
    meta: buildCrmMutationMeta(existing, options.meta || {}),
    updated_by_member_id: currentMemberId,
    ...(options.includeCreatedBy ? { created_by_member_id: currentMemberId } : {}),
    ...(Object.hasOwn(options, "archivedAt") ? { archived_at: options.archivedAt || null } : {})
  };
}

