function buildSupabaseDealPayload(values, options = {}) {
  const existing = options.existing || null;
  const workspaceId = String(state.data.workspace?.id || "").trim();
  const currentMemberId = resolveCurrentUserId(state.data) || null;
  const account = findAccountByName(values.account);
  const contact =
    getContactById(String(values.contactId || "").trim()) ||
    (String(values.contactName || "").trim()
      ? (state.data.contacts || []).find((item) => normalizeForMatch(item.name) === normalizeForMatch(values.contactName))
      : null) ||
    null;
  const normalizedValue = getDealValueNumber(values.value);
  const payload = {
    workspace_id: workspaceId,
    account_id: account?.id || null,
    name: String(values.name || "").trim(),
    stage: normalizeDealStage(values.stage),
    value_amount: normalizedValue,
    currency: String(values.currency || state.data.workspace?.currency || "USD").trim() || "USD",
    close_date: String(values.closeDate || "").trim() || null,
    owner_member_id: resolveTeamMemberIdByName(values.owner) || currentMemberId,
    crm_conversation_id: String(existing?.crmConversationId || "").trim() || null,
    notes: String(values.notes || existing?.notes || "").trim(),
    tags: Array.isArray(values.tags) ? values.tags : Array.isArray(existing?.tags) ? existing.tags : [],
    meta: buildCrmMutationMeta(existing, {
      accountName: String(values.account || "").trim(),
      contactId: String(contact?.id || values.contactId || "").trim(),
      contactName: String(contact?.name || values.contactName || "").trim()
    }),
    updated_by_member_id: currentMemberId,
    ...(options.includeCreatedBy ? { created_by_member_id: currentMemberId } : {})
  };
  if (Object.hasOwn(options, "archivedAt")) {
    payload.archived_at = options.archivedAt || null;
  }
  return payload;
}

async function persistDealStageChange(dealId, nextStage) {
  const deal = getDealById(dealId);
  if (!deal) {
    return false;
  }
  const normalizedNextStage = normalizeDealStage(nextStage);
  if (!normalizedNextStage || normalizedNextStage === deal.stage) {
    return false;
  }
  const stageGuidance = getDealStageChangeGuidance(deal, normalizedNextStage);
  if (stageGuidance?.blocking) {
    if (stageGuidance.focus === "closeDate") {
      openDealComposerModal(deal.id, { focusCloseDate: true });
    } else {
      openDealComposerModal(deal.id, { focusValue: true });
    }
    const modalForm = document.getElementById("modalForm");
    if (modalForm instanceof HTMLFormElement && modalForm.dataset.mode === "deal-compose") {
      showFormFeedback(modalForm, stageGuidance.message, {
        fieldSelector: stageGuidance.focus === "closeDate" ? "[data-deal-close-trigger]" : "input[name='valueDisplay']"
      });
    } else {
      showToast(stageGuidance.message, { tone: "danger" });
    }
    return false;
  }
  if (stageGuidance?.message) {
    showToast(stageGuidance.message, {
      tone: "warning",
      actionLabel: stageGuidance.focus === "closeDate" ? "Set Close Date" : "Set Value",
      onAction: () =>
        openDealComposerModal(deal.id, {
          focusCloseDate: stageGuidance.focus === "closeDate",
          focusValue: stageGuidance.focus !== "closeDate"
        }),
      duration: 5600
    });
  }

  if (isSupabaseCrmWriteEnabled()) {
    await updateSupabaseDeal(
      deal.id,
      buildSupabaseDealPayload(
        {
          name: deal.name,
          contactId: deal.contactId || "",
          contactName: deal.contactName || "",
          account: deal.account,
          stage: normalizedNextStage,
          value: deal.value,
          closeDate: deal.closeDate,
          owner: deal.owner,
          notes: deal.notes || "",
          tags: deal.tags || [],
          currency: deal.currency || state.data.workspace?.currency || "USD"
        },
        { existing: deal }
      )
    );
    await refreshSupabaseCrmData({ render: false, persist: false, alertOnError: false, syncDashboard: false });
    revalidateDashboardAfterMutation();
    return true;
  }

  if (blockConnectedModeLocalFallback("Updating deal stages")) {
    return false;
  }

  deal.stage = normalizedNextStage;
  deal.updatedAt = new Date().toISOString();
  invalidateDashboardCaches();
  return true;
}

async function persistAccountArchiveState(accountId, archivedAt) {
  const account = getAccountById(accountId);
  if (!account) {
    return false;
  }

  if (isSupabaseCrmWriteEnabled()) {
    await updateSupabaseAccount(
      account.id,
      buildSupabaseAccountPayload(
        {
          name: account.name,
          industry: account.industry,
          health: account.health,
          owner: account.owner,
          notes: account.notes || "",
          tags: account.tags || [],
          openDeals: account.openDeals || 0,
          arr: account.arr || 0,
          renewalDate: account.renewalDate || "",
          primaryContactId: account.primaryContactId || "",
          primaryContactName: account.primaryContactName || "",
          website: account.website || "",
          address: account.address || "",
          companySize: account.companySize || ""
        },
        { existing: account, archivedAt }
      )
    );
    await refreshSupabaseCrmData({ render: false, persist: false, alertOnError: false });
    return true;
  }

  if (blockConnectedModeLocalFallback("Updating account archive state")) {
    return false;
  }

  account.archived = Boolean(archivedAt);
  account.archivedAt = archivedAt || "";
  account.updatedAt = new Date().toISOString();
  return true;
}

