async function persistLeadWeeklyRedistributionAssignment(leadSource, assignedMember) {
  const lead = leadSource && typeof leadSource === "object" ? leadSource : getLeadById(leadSource);
  if (!lead) {
    return false;
  }

  const ownerId = String(assignedMember?.id || "").trim();
  const owner = String(assignedMember?.name || "").trim();
  if (!ownerId || !owner) {
    return false;
  }

  const nowIso = new Date().toISOString();
  const assignedAt = resolveLeadAssignedAtValue(lead, owner, nowIso);
  const metaPatch = {
    assignedAt,
    weeklyRedistributionAssignedAt: nowIso,
    weeklyRedistributionAssignedReason: LEAD_WEEKLY_REDISTRIBUTION_REASON
  };

  if (isSupabaseCrmWriteEnabled()) {
    await updateSupabaseLead(
      lead.id,
      buildSupabaseLeadPayload(
        {
          name: lead.name,
          company: lead.company,
          source: lead.source,
          status: lead.status,
          owner,
          nextFollowUp: lead.nextFollowUp,
          email: lead.email || "",
          phone: lead.phone || "",
          secondaryPhone: lead.secondaryPhone || "",
          interest: lead.interest || "",
          role: lead.role || "",
          notes: lead.notes || "",
          tags: lead.tags || []
        },
        {
          existing: lead,
          meta: metaPatch
        }
      )
    );
  } else {
    if (blockConnectedModeLocalFallback("Redistributing new leads")) {
      return false;
    }
  }

  patchLeadAcrossCaches(lead.id, {
    ownerId,
    owner,
    meta: {
      ...(lead.meta && typeof lead.meta === "object" ? lead.meta : {}),
      ...metaPatch
    },
    updatedAt: nowIso
  });
  return true;
}

async function persistLeadStatusChange(leadId, nextStatus, options = {}) {
  const lead = getLeadById(leadId);
  const normalizedStatus = String(nextStatus || "").trim();
  const { optimistic = false } = options;
  if (!lead || !["New", "Contacted", "Qualified", "Unqualified"].includes(normalizedStatus)) {
    return false;
  }
  const previousStatus = String(lead.status || "").trim();
  if (previousStatus === normalizedStatus && !optimistic) {
    return false;
  }
  const nowIso = new Date().toISOString();
  const currentMemberId = resolveCurrentUserId(state.data) || "";
  const currentMemberName = String(state.data.currentUser?.name || "").trim();
  const nextStatusMeta = buildLeadStatusMetaPatch(lead, normalizedStatus, nowIso);

  if (isSupabaseCrmWriteEnabled()) {
    await updateSupabaseLead(
      lead.id,
      buildSupabaseLeadPayload(
        {
          name: lead.name,
          company: lead.company,
          source: lead.source,
          status: normalizedStatus,
          owner: lead.owner,
          nextFollowUp: lead.nextFollowUp,
          email: lead.email || "",
          phone: lead.phone || "",
          secondaryPhone: lead.secondaryPhone || "",
          interest: lead.interest || "",
          role: lead.role || "",
          notes: lead.notes || "",
          tags: lead.tags || []
        },
        {
          existing: lead,
          archivedAt: lead.archived ? lead.archivedAt || new Date().toISOString() : null,
          meta: nextStatusMeta
        }
      )
    );
  } else {
    if (blockConnectedModeLocalFallback("Updating lead status")) {
      return false;
    }
  }

  if (!optimistic) {
    patchLeadAcrossCaches(lead.id, {
      status: normalizedStatus,
      updatedAt: nowIso
    });
  }
  patchLeadAcrossCaches(lead.id, {
    meta: {
      ...(lead.meta && typeof lead.meta === "object" ? lead.meta : {}),
      ...nextStatusMeta
    },
    updatedById: currentMemberId,
    updatedBy: currentMemberName
  });
  invalidateCallsPerformanceCaches();
  state.callsPerformanceData = createEmptyCallsPerformanceData({
    sourceKind: state.callsPerformanceData?.sourceKind || "events"
  });
  if (isSupabaseCrmWriteEnabled()) {
    // Keep the status interaction snappy; a small lead update should not block on a full CRM reload.
    revalidateDashboardAfterMutation({ render: false });
  }

  pushLeadActivity({
    leadId: lead.id,
    type: "lead-status-updated",
    text: `Lead status changed to ${normalizedStatus}.`
  });
  return true;
}

async function maybeRunLeadWeeklyCleanup(requestOptions = {}) {
  if (!isSupabaseCrmWriteEnabled()) {
    return false;
  }
  const currentUserRole = String(requestOptions.currentUserRole || resolveCurrentUserRole(state.data) || "").trim();
  if (getLeadListScopeForRole(currentUserRole) === "mine") {
    return false;
  }
  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    return false;
  }
  if (leadWeeklyCleanupPromise) {
    return leadWeeklyCleanupPromise;
  }

  leadWeeklyCleanupPromise = (async () => {
    const nowIso = new Date().toISOString();
    const [pendingUnqualifiedLeads, pendingAttemptLimitLeads, pendingRedistributionLeads] = await Promise.all([
      fetchSupabasePendingUnqualifiedLeads(workspaceId, {
        teamMembers: state.data.teamMembers,
        currentUserId: requestOptions.currentUserId || resolveCurrentUserId(state.data),
        currentUserRole,
        scope: requestOptions.scope || getLeadListScopeForRole(currentUserRole),
        ownerFilter: requestOptions.ownerFilter || getEffectiveLeadsOwnerFilter(state.leadsOwnerFilter, currentUserRole)
      }),
      fetchSupabasePendingAttemptLimitLeads(workspaceId, {
        teamMembers: state.data.teamMembers,
        currentUserId: requestOptions.currentUserId || resolveCurrentUserId(state.data),
        currentUserRole,
        scope: requestOptions.scope || getLeadListScopeForRole(currentUserRole),
        ownerFilter: requestOptions.ownerFilter || getEffectiveLeadsOwnerFilter(state.leadsOwnerFilter, currentUserRole)
      }),
      fetchSupabasePendingFridayRedistributionLeads(workspaceId).catch((error) => {
        console.warn("Weekly lead redistribution candidate fetch skipped:", error);
        return [];
      })
    ]);

    const backfillMap = new Map();
    const unqualifiedBackfillLeads = pendingUnqualifiedLeads.filter((lead) => needsLeadWeeklyRemovalBackfill(lead));
    const attemptLimitBackfillLeads = pendingAttemptLimitLeads.filter((lead) => needsLeadAttemptWeeklyRemovalBackfill(lead));

    if (unqualifiedBackfillLeads.length || attemptLimitBackfillLeads.length) {
      await Promise.allSettled([
        ...unqualifiedBackfillLeads.map(async (lead) => {
          const metaPatch = buildLeadWeeklyRemovalBackfillMeta(lead, nowIso);
          const changed = await persistLeadWeeklyRemovalMeta(lead, metaPatch);
          if (changed) {
            backfillMap.set(String(lead.id || "").trim(), metaPatch);
          }
          return changed;
        }),
        ...attemptLimitBackfillLeads.map(async (lead) => {
          const metaPatch = buildLeadAttemptWeeklyRemovalBackfillMeta(lead, nowIso);
          const changed = await persistLeadWeeklyRemovalMeta(lead, metaPatch);
          if (changed) {
            backfillMap.set(String(lead.id || "").trim(), metaPatch);
          }
          return changed;
        })
      ]);
    }

    const normalizedPendingUnqualifiedLeads = pendingUnqualifiedLeads.map((lead) => {
      const leadId = String(lead?.id || "").trim();
      const backfillPatch = backfillMap.get(leadId);
      if (!backfillPatch) {
        return lead;
      }
      return {
        ...lead,
        meta: {
          ...(lead.meta && typeof lead.meta === "object" ? lead.meta : {}),
          ...backfillPatch
        }
      };
    });
    const normalizedPendingAttemptLimitLeads = pendingAttemptLimitLeads.map((lead) => {
      const leadId = String(lead?.id || "").trim();
      const backfillPatch = backfillMap.get(leadId);
      if (!backfillPatch) {
        return lead;
      }
      return {
        ...lead,
        meta: {
          ...(lead.meta && typeof lead.meta === "object" ? lead.meta : {}),
          ...backfillPatch
        }
      };
    });
    const dueRedistributionLeads = pendingRedistributionLeads.filter((lead) => isLeadPendingFridayRedistributionDue(lead, nowIso));

    const dueUnqualifiedLeads = normalizedPendingUnqualifiedLeads.filter((lead) => isLeadWeeklyRemovalDue(lead, nowIso));
    const dueAttemptLimitLeads = normalizedPendingAttemptLimitLeads.filter((lead) => isLeadAttemptWeeklyRemovalDue(lead, nowIso));
    if (!dueUnqualifiedLeads.length && !dueAttemptLimitLeads.length && !dueRedistributionLeads.length) {
      if (backfillMap.size) {
        clearQueryCache();
      }
      return backfillMap.size > 0;
    }

    const archivedUnqualifiedLeadIds = [];
    const archivedAttemptLimitLeadIds = [];
    const redistributedLeadIds = [];
    const assignableMembers = getLeadRedistributionTeamMembers();
    await Promise.allSettled([
      ...dueUnqualifiedLeads.map(async (lead) => {
        const archivedAt = new Date().toISOString();
        const changed = await persistLeadArchiveState(lead.id, archivedAt, {
          existingLead: lead,
          meta: buildLeadWeeklyRemovalArchiveMeta(lead, archivedAt)
        });
        if (changed) {
          archivedUnqualifiedLeadIds.push(String(lead.id || "").trim());
          pushLeadActivity({
            leadId: lead.id,
            type: "lead-archived",
            text: "Lead removed from active leads by the weekly unqualified cleanup."
          });
        }
        return changed;
      }),
      ...dueAttemptLimitLeads.map(async (lead) => {
        const archivedAt = new Date().toISOString();
        const changed = await persistLeadArchiveState(lead.id, archivedAt, {
          existingLead: lead,
          meta: buildLeadAttemptWeeklyRemovalArchiveMeta(lead, archivedAt)
        });
        if (changed) {
          archivedAttemptLimitLeadIds.push(String(lead.id || "").trim());
          pushLeadActivity({
            leadId: lead.id,
            type: "lead-archived",
            text: "Lead removed from active leads by the weekly 3/3 cleanup."
          });
        }
        return changed;
      }),
      ...dueRedistributionLeads.map(async (lead, index) => {
        if (!assignableMembers.length) {
          return false;
        }
        const assignedMember = assignableMembers[index % assignableMembers.length];
        if (!assignedMember) {
          return false;
        }
        const changed = await persistLeadWeeklyRedistributionAssignment(lead, assignedMember);
        if (changed) {
          redistributedLeadIds.push(String(lead.id || "").trim());
          pushLeadActivity({
            leadId: lead.id,
            type: "lead-owner-reassigned",
            text: `Lead redistributed to ${String(assignedMember.name || "an agent").trim()} by the weekly Friday redistribution.`
          });
        }
        return changed;
      })
    ]);

    const totalArchivedCount = archivedUnqualifiedLeadIds.length + archivedAttemptLimitLeadIds.length;
    const totalRedistributedCount = redistributedLeadIds.length;
    if (totalArchivedCount || totalRedistributedCount) {
      clearQueryCache();
      [...archivedUnqualifiedLeadIds, ...archivedAttemptLimitLeadIds, ...redistributedLeadIds].forEach((leadId) => {
        state.selectedLeadIds.delete(leadId);
        if (String(state.selectedLeadId || "").trim() === leadId) {
          state.selectedLeadId = "";
          state.leadProfileData = createEmptyLeadProfileData();
        }
      });
      const summaryParts = [];
      if (archivedUnqualifiedLeadIds.length) {
        summaryParts.push(
          `${archivedUnqualifiedLeadIds.length} unqualified lead${archivedUnqualifiedLeadIds.length === 1 ? "" : "s"}`
        );
      }
      if (archivedAttemptLimitLeadIds.length) {
        summaryParts.push(
          `${archivedAttemptLimitLeadIds.length} lead${archivedAttemptLimitLeadIds.length === 1 ? "" : "s"} at 3/3`
        );
      }
      if (redistributedLeadIds.length) {
        summaryParts.push(
          `${redistributedLeadIds.length} new lead${redistributedLeadIds.length === 1 ? "" : "s"} redistributed`
        );
      }
      showToast(
        summaryParts.length
          ? `${summaryParts.join(" and ")}${redistributedLeadIds.length ? "." : " removed from active leads."}`
          : "Weekly lead cleanup completed.",
        { tone: "info" }
      );
    } else if (backfillMap.size) {
      clearQueryCache();
    }

    return totalArchivedCount > 0 || totalRedistributedCount > 0 || backfillMap.size > 0;
  })();

  try {
    return await leadWeeklyCleanupPromise;
  } finally {
    leadWeeklyCleanupPromise = null;
  }
}

async function syncSupabaseWorkspaceAccess(user, options = {}) {
  const { alertOnDeny = true, syncId = ++authSyncSequence } = options;
  const inviteContext = getInviteAcceptanceContext(window.location.hash);
  const isInviteRoute = state.routeId === "invite" && Boolean(inviteContext?.inviteId || inviteContext?.token || inviteContext?.email);
  const targetHash = resolvePostAuthTargetHash(isInviteRoute);
  const targetRouteId = resolveRouteFromLocation(targetHash);
  if (!state.supabaseConfigured) {
    state.authBootstrapPending = false;
    state.authAccessState = "demo";
    state.authAccessMessage = "";
    state.inviteRouteMessage = "";
    state.inviteRouteLink = "";
    setEmailIntegrationStatus(createEmptyEmailIntegrationStatus());
    resetEmailMailboxState();
    state.authAccessCachedGranted = true;
    const knownEmail = normalizeEmailAddress(user?.email || state.signedInUser?.email || state.lastKnownAuthEmail);
    persistAuthAccessCache(true, knownEmail);
    state.lastKnownAuthEmail = knownEmail;
    persistLastKnownAuthEmail(knownEmail);
    return true;
  }
  if (!user?.email) {
    state.authBootstrapPending = false;
    state.authAccessState = "signed-out";
    if (!isInviteRoute) {
      state.inviteRouteMessage = "";
      state.inviteRouteLink = "";
    }
    setEmailIntegrationStatus(createEmptyEmailIntegrationStatus());
    resetEmailMailboxState();
    state.authAccessCachedGranted = false;
    persistAuthAccessCache(false);
    return false;
  }

  const email = normalizeEmailAddress(user.email);
  const provider = String(user.provider || "google").trim() || "google";
  const shouldKeepCurrentShell = state.authAccessCachedGranted || state.authAccessState === "granted";
  state.authBootstrapPending = false;
  state.authAccessState = "loading";
  state.authAccessMessage = "";
  if (!isInviteRoute) {
    state.inviteRouteMessage = "";
    state.inviteRouteLink = "";
  }
  if (shouldKeepCurrentShell) {
    updateBanner();
    updateHeaderMenus();
  } else {
    renderRoute();
  }

  const denyAccess = async (message) => {
    if (syncId !== authSyncSequence) {
      return false;
    }
    state.authAccessState = "blocked";
    state.authAccessMessage = String(message || "Workspace access was denied.").trim();
    state.authBootstrapPending = false;
    setEmailIntegrationStatus(createEmptyEmailIntegrationStatus());
    resetEmailMailboxState();
    state.authAccessCachedGranted = false;
    persistAuthAccessCache(false);
    renderRoute();
    if (alertOnDeny) {
      window.alert(state.authAccessMessage);
    }
    if (!authSignOutInFlight) {
      authSignOutInFlight = true;
      try {
        await signOutCurrentUser();
      } catch {
        // no-op
      } finally {
        authSignOutInFlight = false;
      }
    }
    return false;
  };

  const failInviteAcceptance = async (message) => {
    if (syncId !== authSyncSequence) {
      return false;
    }
    state.inviteRouteMessage = String(message || "This invite is no longer valid.").trim();
    state.inviteRouteLink = "";
    state.authAccessState = "signed-out";
    state.authAccessMessage = "";
    setEmailIntegrationStatus(createEmptyEmailIntegrationStatus());
    resetEmailMailboxState();
    state.authAccessCachedGranted = false;
    persistAuthAccessCache(false);
    renderRoute();
    if (state.signedInUser && !authSignOutInFlight) {
      authSignOutInFlight = true;
      try {
        await signOutCurrentUser();
      } catch {
        // no-op
      } finally {
        authSignOutInFlight = false;
      }
    }
    return false;
  };

  try {
    if (isInviteRoute) {
      const invitedEmail = normalizeEmailAddress(inviteContext?.email);
      if (invitedEmail && invitedEmail !== email) {
        return failInviteAcceptance(`This invite was sent to ${invitedEmail}. Sign in with that email to continue.`);
      }
    }

    const useMinimalWorkspaceBundle = targetRouteId === "lead-profile";
    let bundle = await fetchWorkspaceBundleByEmail(email, {
      includeTeamMembers: !useMinimalWorkspaceBundle
    });
    if (syncId !== authSyncSequence) {
      return false;
    }
    if (!bundle.member) {
      if (isInviteRoute) {
        return failInviteAcceptance("No pending invite record was found for this email.");
      }
      return denyAccess("No invited team member record was found for this email. Create or invite the owner account in Supabase first.");
    }

    const status = normalizeTeamMemberStatus(bundle.member.status);
    if (status === "Inactive") {
      if (isInviteRoute) {
        return failInviteAcceptance("This invite is inactive. Ask your workspace administrator for a new invite link.");
      }
      return denyAccess("This team member is inactive. Contact your workspace administrator.");
    }

    if (isInviteRoute && status === "Pending Invite") {
      const expectedInviteId = String(inviteContext?.inviteId || "").trim();
      const expectedToken = String(inviteContext?.token || "").trim();
      const storedInviteId = String(bundle.member.id || "").trim();
      const storedToken = String(bundle.member.inviteToken || "").trim();
      const inviteIdMatches = Boolean(expectedInviteId && storedInviteId && expectedInviteId === storedInviteId);
      const tokenMatches = Boolean(expectedToken && storedToken && expectedToken === storedToken);
      if (!inviteIdMatches && !tokenMatches) {
        return failInviteAcceptance("This invite link is invalid or has expired. Ask your workspace administrator for a new invite.");
      }
    }

    const nowIso = new Date().toISOString();
    const needsActivation =
      status === "Pending Invite" ||
      String(bundle.member.authUserId || "").trim() !== String(user.uid || "").trim() ||
      String(bundle.member.authProvider || "").trim() !== provider;

    if (needsActivation) {
      const updatedMember = await updateSupabaseTeamMember(bundle.member.id, {
        status: "Active",
        authUserId: String(user.uid || "").trim(),
        authProvider: provider,
        lastLoginAt: nowIso,
        updatedAt: nowIso
      });
      bundle = mergeWorkspaceBundleMember(bundle, {
        ...updatedMember,
        status: "Active",
        authUserId: String(user.uid || "").trim(),
        authProvider: provider,
        lastLoginAt: nowIso,
        updatedAt: nowIso
      });
    } else {
      bundle = mergeWorkspaceBundleMember(bundle, {
        ...(bundle.member || {}),
        authUserId: String(user.uid || "").trim(),
        authProvider: provider,
        lastLoginAt: nowIso,
        status: "Active",
        updatedAt: nowIso
      });
      void updateSupabaseTeamMember(bundle.member.id, {
        authUserId: String(user.uid || "").trim(),
        authProvider: provider,
        lastLoginAt: nowIso,
        updatedAt: nowIso
      }).catch((error) => {
        console.warn("Supabase team member login stamp update failed:", error);
      });
    }

    if (syncId !== authSyncSequence) {
      return false;
    }
    applySupabaseWorkspaceBundle(bundle);
    if (useMinimalWorkspaceBundle) {
      void fetchWorkspaceBundleByEmail(email).then((fullBundle) => {
        if (syncId !== authSyncSequence || !fullBundle?.workspace?.id) {
          return;
        }
        applySupabaseWorkspaceBundle(fullBundle);
        if (state.routeId === "lead-profile") {
          renderRoute();
        }
      }).catch((error) => {
        console.warn("Supabase workspace team sync failed:", error);
      });
    }
    syncRestrictedDashboardAccessState();
    syncRestrictedCommsAccessState();
    const refreshPlan = createPostAuthRefreshPlan(targetRouteId, targetHash);
    await runBlockingPostAuthRefreshTasks(refreshPlan.blocking, syncId);
    state.authBootstrapPending = false;
    state.authAccessState = "granted";
    state.authAccessMessage = "";
    state.inviteRouteMessage = "";
    state.inviteRouteLink = "";
    state.authAccessCachedGranted = true;
    persistAuthAccessCache(true, email);
    state.lastKnownAuthEmail = email;
    persistLastKnownAuthEmail(email);
    subscribeWorkRealtime();
    subscribeMessengerRealtime();
    subscribeNotificationsRealtime();
    saveData(state.data);
    if (isInviteRoute) {
      await removePublicInviteRecord(String(inviteContext?.inviteId || bundle.member?.id || "").trim()).catch(() => null);
      clearStoredAuthReturnHash();
      clearStoredInviteContext();
      replaceRoute(defaultRouteId);
    } else if (state.routeId === "login") {
      consumeStoredAuthReturnHash();
      replaceLocationHash(targetHash);
    }
    startDeferredPostAuthRefreshTasks(refreshPlan.deferred, syncId, {
      batchRender: targetRouteId !== "dashboard"
    });
    return true;
  } catch (error) {
    if (syncId !== authSyncSequence) {
      return false;
    }
    if (isInviteRoute) {
      state.inviteRouteMessage = `Invite acceptance failed: ${String(error?.message || error || "Unknown error")}`;
      state.inviteRouteLink = "";
      state.authAccessState = "signed-out";
      state.authAccessMessage = "";
      state.authBootstrapPending = false;
      setEmailIntegrationStatus(createEmptyEmailIntegrationStatus());
      resetEmailMailboxState();
      state.authAccessCachedGranted = false;
      persistAuthAccessCache(false);
      renderRoute();
      return false;
    }
    state.authAccessState = "blocked";
    state.authAccessMessage = `Supabase access sync failed: ${String(error?.message || error || "Unknown error")}`;
    state.authBootstrapPending = false;
    setEmailIntegrationStatus(createEmptyEmailIntegrationStatus());
    resetEmailMailboxState();
    state.authAccessCachedGranted = false;
    persistAuthAccessCache(false);
    renderRoute();
    if (alertOnDeny) {
      window.alert(state.authAccessMessage);
    }
    return false;
  }
}

async function refreshSupabaseTeamWorkspace(options = {}) {
  if (!state.supabaseConfigured || !state.signedInUser?.email) {
    return false;
  }
  return syncSupabaseWorkspaceAccess(state.signedInUser, {
    alertOnDeny: options.alertOnDeny !== false,
    syncId: ++authSyncSequence
  });
}

async function refreshSupabaseSettingsProfileData(options = {}) {
  const {
    render = state.routeId === "settings-me" || state.routeId === "settings-workspace",
    alertOnError = false,
    force = false
  } = options;
  if (
    !state.supabaseConfigured ||
    !state.signedInUser?.email ||
    state.authAccessState !== "granted" ||
    state.authBootstrapPending
  ) {
    return false;
  }

  const normalizedEmail = normalizeEmailAddress(state.signedInUser.email);
  if (!normalizedEmail) {
    return false;
  }

  const now = Date.now();
  if (
    !force &&
    settingsProfileLastRefreshAt &&
    now - settingsProfileLastRefreshAt < SETTINGS_PROFILE_REFRESH_STALE_MS
  ) {
    return true;
  }
  if (settingsProfileRefreshPromise) {
    return settingsProfileRefreshPromise;
  }

  const runId = ++settingsProfileRefreshRunId;
  settingsProfileRefreshPromise = (async () => {
    try {
      const bundle = await fetchWorkspaceBundleByEmail(normalizedEmail);
      if (runId !== settingsProfileRefreshRunId || !bundle?.member || !bundle?.workspace) {
        return false;
      }
      applySupabaseWorkspaceBundle(bundle);
      settingsProfileLastRefreshAt = Date.now();
      saveData(state.data);
      if (render && (state.routeId === "settings-me" || state.routeId === "settings-workspace")) {
        requestSettingsProfileRouteRender();
      } else {
        updateHeaderMenus();
      }
      return true;
    } catch (error) {
      console.warn("Supabase profile workspace refresh failed:", error);
      if (alertOnError) {
        window.alert(`Profile refresh failed: ${String(error?.message || error || "Unknown error")}`);
      }
      return false;
    } finally {
      if (runId === settingsProfileRefreshRunId) {
        settingsProfileRefreshPromise = null;
      }
    }
  })();

  return settingsProfileRefreshPromise;
}

function clearSettingsProfileDeferredRender() {
  settingsProfileDeferredRenderPending = false;
  if (settingsProfileDeferredRenderTimer) {
    window.clearInterval(settingsProfileDeferredRenderTimer);
    settingsProfileDeferredRenderTimer = 0;
  }
}

function isSettingsProfileUiBusy() {
  if (state.routeId !== "settings-me" && state.routeId !== "settings-workspace") {
    return false;
  }
  if (document.querySelector(".modal-overlay:not([hidden])")) {
    return true;
  }
  const viewContent = document.getElementById("viewContent");
  const activeElement = document.activeElement;
  if (!viewContent || !activeElement || !viewContent.contains(activeElement)) {
    return false;
  }
  const tagName = String(activeElement.tagName || "").trim().toLowerCase();
  return ["input", "textarea", "select"].includes(tagName) || Boolean(activeElement.isContentEditable);
}

function requestSettingsProfileRouteRender() {
  if (state.routeId !== "settings-me" && state.routeId !== "settings-workspace") {
    clearSettingsProfileDeferredRender();
    return;
  }
  if (!isSettingsProfileUiBusy()) {
    clearSettingsProfileDeferredRender();
    renderRoute();
    return;
  }
  settingsProfileDeferredRenderPending = true;
  if (settingsProfileDeferredRenderTimer) {
    return;
  }
  settingsProfileDeferredRenderTimer = window.setInterval(() => {
    if (state.routeId !== "settings-me" && state.routeId !== "settings-workspace") {
      clearSettingsProfileDeferredRender();
      return;
    }
    if (isSettingsProfileUiBusy()) {
      return;
    }
    if (!settingsProfileDeferredRenderPending) {
      clearSettingsProfileDeferredRender();
      return;
    }
    clearSettingsProfileDeferredRender();
    renderRoute();
  }, 250);
}

async function pushSupabaseTeamMemberUpdate(memberId, patch) {
  if (!state.supabaseConfigured || !state.signedInUser) {
    return null;
  }
  const updated = await updateSupabaseTeamMember(memberId, patch);
  await refreshSupabaseTeamWorkspace({ alertOnDeny: false });
  await syncPublicInviteRecord(updated, {
    inviteId: String(updated?.id || memberId || "").trim(),
    workspace: state.data.workspace?.name || "Workspace",
    workspaceId: state.data.workspace?.id || updated?.workspaceId || "",
    invitedBy: resolveCurrentUserName(state.data)
  });
  return updated;
}

function triggerGoogleSignIn() {
  persistAuthReturnHash(window.location.hash);
  state.authAccessMessage = "";
  resetLoginEmailAuthState({ preserveEmail: true, preservePassword: false });
  resetInviteEmailAuthState();
  state.authActionPending = "google-sign-in";
  if (state.routeId === "login") {
    renderRoute();
  } else {
    updateHeaderMenus();
  }
  signInWithGoogle({ redirectTo: getBaseAppUrl() }).catch((error) => {
    state.authActionPending = "";
    if (state.routeId === "login") {
      renderRoute();
    } else {
      updateHeaderMenus();
    }
    window.alert(`Sign-in failed: ${error.message}`);
  });
}

async function ensureLoginEmailStatus(email) {
  const normalizedEmail = normalizeEmailAddress(email);
  if (!normalizedEmail) {
    return createEmptyLoginEmailLookupStatus();
  }

  const currentStatus =
    state.loginEmailLookupStatus && typeof state.loginEmailLookupStatus === "object"
      ? state.loginEmailLookupStatus
      : createEmptyLoginEmailLookupStatus();

  if (normalizeEmailAddress(currentStatus.email) === normalizedEmail && !currentStatus.loading) {
    return currentStatus;
  }

  const nextStatus = await fetchLoginEmailStatus(normalizedEmail);
  if (normalizeEmailAddress(state.loginEmailDraft) === normalizedEmail) {
    setLoginEmailLookupStatus(nextStatus);
    if (state.routeId === "login") {
      renderLoginRoutePreservingEmailInput();
    }
  }
  return nextStatus;
}

function assertPasswordFieldsMatch(password, confirmPassword) {
  const nextPassword = String(password || "");
  const nextConfirmPassword = String(confirmPassword || "");
  if (!nextPassword || nextPassword.length < 8) {
    throw new Error("Use at least 8 characters for your password.");
  }
  if (nextPassword !== nextConfirmPassword) {
    throw new Error("Password confirmation does not match.");
  }
  return nextPassword;
}

async function submitLoginPasswordForm(form) {
  const formData = new FormData(form);
  const email = normalizeEmailAddress(formData.get("email"));
  const password = String(formData.get("password") || "");
  if (!email) {
    window.alert("Enter the invited email you want to use.");
    const emailInput = form.querySelector("[data-login-email-input]");
    if (emailInput && typeof emailInput.focus === "function") {
      emailInput.focus();
    }
    return;
  }
  if (!password) {
    window.alert("Enter your password to sign in.");
    const passwordInput = form.querySelector("[data-login-password-input]");
    if (passwordInput && typeof passwordInput.focus === "function") {
      passwordInput.focus();
    }
    return;
  }

  let lookupStatus;
  try {
    lookupStatus = await ensureLoginEmailStatus(email);
  } catch (error) {
    window.alert(`We could not check this email right now: ${error.message}`);
    return;
  }
  if (!lookupStatus.recognized && normalizeEmailAddress(state.lastKnownAuthEmail) !== email) {
    window.alert("This email does not have workspace access yet. Use the invited email address or your invite link first.");
    return;
  }
  if (lookupStatus.pending) {
    window.alert("This invited account still needs to be set up first. Use Sign up to verify the invite and create a password.");
    return;
  }

  persistAuthReturnHash(window.location.hash);
  setLoginViewMode("signin", { preserveEmail: true, preservePassword: true, resetAuthState: false });
  state.loginEmailDraft = email;
  state.loginPasswordDraft = password;
  state.authAccessMessage = "";
  state.authActionPending = "email-password";
  renderRoute();

  try {
    await signInWithEmailPassword(email, password);
  } catch (error) {
    state.authActionPending = "";
    renderRoute();
    if (lookupStatus.pending) {
      window.alert("This invited account still needs to be set up. Use the one-time code flow first.");
      return;
    }
    window.alert(`Email sign-in failed: ${error.message}`);
  }
}

async function submitLoginSignupStartForm(form) {
  const formData = new FormData(form);
  state.loginEmailDraft = normalizeEmailAddress(formData.get("email"));
  await sendLoginEmailOtp();
}

async function sendLoginEmailOtp() {
  const email = normalizeEmailAddress(state.loginEmailDraft);
  if (!email) {
    window.alert("Enter the invited email you want to use.");
    return;
  }

  let lookupStatus;
  try {
    lookupStatus = await ensureLoginEmailStatus(email);
  } catch (error) {
    setLoginEmailLookupStatus({
      loading: false,
      email,
      recognized: false,
      active: false,
      pending: false,
      error: normalizeLoginEmailLookupErrorMessage(error?.message || error)
    });
    renderLoginRoutePreservingEmailInput();
    return;
  }
  if (!lookupStatus.pending) {
    if (lookupStatus.active) {
      window.alert("This account is already set up. Switch to Log in and use your email and password.");
      return;
    }
    window.alert("No pending workspace invite was found for this email.");
    return;
  }

  persistAuthReturnHash(window.location.hash);
  setLoginViewMode("signup", { preserveEmail: true, resetAuthState: false });
  state.loginEmailDraft = email;
  state.loginOtpDraft = "";
  state.loginPendingPasswordSetupEmail = "";
  state.loginPasswordSetupDraft = "";
  state.loginPasswordSetupConfirmDraft = "";
  clearDeferredPasswordSetup();
  state.authAccessMessage = "";
  state.authActionPending = "login-send-otp";
  renderRoute();

  try {
    await sendEmailOtp(email, { shouldCreateUser: true });
    state.authActionPending = "";
    state.loginOtpSentTo = email;
    state.loginPasswordSetupDraft = "";
    state.loginPasswordSetupConfirmDraft = "";
    renderRoute();
  } catch (error) {
    state.authActionPending = "";
    renderRoute();
    window.alert(`Verification code send failed: ${error.message}`);
  }
}

async function submitLoginOtpVerifyForm(form) {
  const formData = new FormData(form);
  const token = String(formData.get("token") || "").trim();
  const email = normalizeEmailAddress(state.loginOtpSentTo || state.loginEmailDraft);
  if (!email) {
    window.alert("Enter your invited email first.");
    return;
  }
  if (!token) {
    window.alert("Enter the verification code from your email.");
    const tokenInput = form.querySelector("[data-login-otp-input]");
    if (tokenInput && typeof tokenInput.focus === "function") {
      tokenInput.focus();
    }
    return;
  }

  persistAuthReturnHash(window.location.hash);
  setLoginViewMode("signup", { preserveEmail: true, resetAuthState: false });
  state.loginOtpDraft = token;
  state.authAccessMessage = "";
  state.authActionPending = "login-verify-otp";
  setDeferredPasswordSetup("login", email);
  renderRoute();

  try {
    const verifiedUser = await verifyEmailOtp(email, token);
    state.signedInUser = verifiedUser || state.signedInUser;
    state.authActionPending = "";
    state.authBootstrapPending = false;
    state.authAccessState = "signed-out";
    state.authAccessMessage = "";
    state.loginOtpSentTo = "";
    state.loginOtpDraft = "";
    state.loginPendingPasswordSetupEmail = email;
    renderRoute();
  } catch (error) {
    clearDeferredPasswordSetup();
    state.authActionPending = "";
    renderRoute();
    window.alert(`Verification failed: ${error.message}`);
  }
}

async function submitLoginPasswordSetupForm(form) {
  const formData = new FormData(form);
  const email = normalizeEmailAddress(state.loginPendingPasswordSetupEmail || state.signedInUser?.email || state.loginEmailDraft);
  const password = String(formData.get("password") || "");
  const confirmPassword = String(formData.get("confirmPassword") || "");
  if (!email) {
    window.alert("Your verified email session was lost. Start again with a new verification code.");
    return;
  }

  let nextPassword = "";
  try {
    nextPassword = assertPasswordFieldsMatch(password, confirmPassword);
  } catch (error) {
    window.alert(String(error?.message || error || "Password setup failed."));
    return;
  }

  state.loginPasswordSetupDraft = password;
  state.loginPasswordSetupConfirmDraft = confirmPassword;
  setLoginViewMode("signup", { preserveEmail: true, resetAuthState: false });
  state.authAccessMessage = "";
  state.authActionPending = "login-setup-password";
  renderRoute();

  try {
    await updateCurrentUserPassword(nextPassword);
    state.authActionPending = "";
    state.loginPasswordDraft = "";
    state.loginOtpDraft = "";
    state.loginOtpSentTo = "";
    state.loginPendingPasswordSetupEmail = "";
    state.loginPasswordSetupDraft = "";
    state.loginPasswordSetupConfirmDraft = "";
    clearDeferredPasswordSetup();
    await syncSupabaseWorkspaceAccess(state.signedInUser, {
      alertOnDeny: true,
      syncId: ++authSyncSequence
    });
  } catch (error) {
    state.authActionPending = "";
    renderRoute();
    window.alert(`Password setup failed: ${error.message}`);
  }
}

async function sendInviteEmailOtp() {
  const inviteContext = getInviteAcceptanceContext(window.location.hash);
  const email = normalizeEmailAddress(inviteContext?.email);
  if (!email) {
    window.alert("This invite is missing the invited email.");
    return;
  }

  persistInviteContext(inviteContext || {});
  state.invitePendingPasswordSetupEmail = "";
  state.invitePasswordSetupDraft = "";
  state.invitePasswordSetupConfirmDraft = "";
  clearDeferredPasswordSetup();
  state.inviteRouteMessage = "";
  state.inviteRouteLink = "";
  state.authActionPending = "invite-send-otp";
  renderRoute();

  try {
    await sendEmailOtp(email, { shouldCreateUser: true });
    state.authActionPending = "";
    state.inviteOtpSentTo = email;
    state.inviteOtpDraft = "";
    renderRoute();
  } catch (error) {
    state.authActionPending = "";
    renderRoute();
    window.alert(`Verification code send failed: ${error.message}`);
  }
}

async function submitInviteOtpVerifyForm(form) {
  const formData = new FormData(form);
  const token = String(formData.get("token") || "").trim();
  const inviteContext = getInviteAcceptanceContext(window.location.hash);
  const email = normalizeEmailAddress(inviteContext?.email || state.inviteOtpSentTo);
  if (!email) {
    window.alert("This invite is missing the invited email.");
    return;
  }
  if (!token) {
    window.alert("Enter the verification code from your email.");
    const tokenInput = form.querySelector("[data-invite-otp-input]");
    if (tokenInput && typeof tokenInput.focus === "function") {
      tokenInput.focus();
    }
    return;
  }

  persistInviteContext(inviteContext || {});
  state.inviteOtpDraft = token;
  state.authActionPending = "invite-verify-otp";
  state.inviteRouteMessage = "";
  state.inviteRouteLink = "";
  setDeferredPasswordSetup("invite", email);
  renderRoute();

  try {
    const verifiedUser = await verifyEmailOtp(email, token);
    state.signedInUser = verifiedUser || state.signedInUser;
    state.authActionPending = "";
    state.authBootstrapPending = false;
    state.authAccessState = "signed-out";
    state.authAccessMessage = "";
    state.inviteOtpSentTo = "";
    state.inviteOtpDraft = "";
    state.invitePendingPasswordSetupEmail = email;
    renderRoute();
  } catch (error) {
    clearDeferredPasswordSetup();
    state.authActionPending = "";
    renderRoute();
    window.alert(`Verification failed: ${error.message}`);
  }
}

async function submitInvitePasswordSetupForm(form) {
  const formData = new FormData(form);
  const inviteContext = getInviteAcceptanceContext(window.location.hash);
  const email = normalizeEmailAddress(inviteContext?.email || state.invitePendingPasswordSetupEmail || state.signedInUser?.email);
  const password = String(formData.get("password") || "");
  const confirmPassword = String(formData.get("confirmPassword") || "");
  if (!email) {
    window.alert("Your verified invite session was lost. Start again from the invite email.");
    return;
  }

  let nextPassword = "";
  try {
    nextPassword = assertPasswordFieldsMatch(password, confirmPassword);
  } catch (error) {
    window.alert(String(error?.message || error || "Password setup failed."));
    return;
  }

  state.invitePasswordSetupDraft = password;
  state.invitePasswordSetupConfirmDraft = confirmPassword;
  state.authActionPending = "invite-setup-password";
  state.inviteRouteMessage = "";
  state.inviteRouteLink = "";
  renderRoute();

  try {
    await updateCurrentUserPassword(nextPassword);
    state.authActionPending = "";
    state.inviteOtpDraft = "";
    state.inviteOtpSentTo = "";
    state.invitePendingPasswordSetupEmail = "";
    state.invitePasswordSetupDraft = "";
    state.invitePasswordSetupConfirmDraft = "";
    clearDeferredPasswordSetup();
    await syncSupabaseWorkspaceAccess(state.signedInUser, {
      alertOnDeny: true,
      syncId: ++authSyncSequence
    });
  } catch (error) {
    state.authActionPending = "";
    renderRoute();
    window.alert(`Password setup failed: ${error.message}`);
  }
}

function triggerSignOut() {
  if (!state.supabaseConfigured || authSignOutInFlight) {
    return;
  }
  state.authAccessMessage = "";
  state.authActionPending = "sign-out";
  closeTopbarMenus();
  updateHeaderMenus();
  authSignOutInFlight = true;
  signOutCurrentUser()
    .then(() => {
      applySignedOutUiState({ preserveInviteMessage: state.routeId === "invite" });
      renderRoute();
    })
    .catch((error) => {
      state.authActionPending = "";
      renderRoute();
      window.alert(`Sign-out failed: ${error.message}`);
    })
    .finally(() => {
      authSignOutInFlight = false;
      updateHeaderMenus();
    });
}

