function resolveCreateConfig(routeId) {
  const config = CREATE_CONFIG[routeId];
  if (!config) {
    return null;
  }
  if (typeof config === "string") {
    return CREATE_CONFIG[config];
  }
  return config;
}

function todayIso(daysFromNow = 0) {
  const now = new Date();
  now.setDate(now.getDate() + daysFromNow);
  return now.toISOString().slice(0, 10);
}

