function currentUserHasPermission(moduleId, action = "view", data = state.data) {
  const currentMember = getCurrentUserTeamMember(data);
  if (currentMember) {
    return memberHasPermissionCore(currentMember, moduleId, action);
  }
  const currentUser = data?.currentUser && typeof data.currentUser === "object"
    ? data.currentUser
    : { role: resolveCurrentUserRole(data) };
  return memberHasPermissionCore(currentUser, moduleId, action);
}

