function attendanceSupabaseUnavailableMessage() {
  if (!state.supabaseConfigured) {
    return "Attendance requires a configured Supabase backend.";
  }
  if (!state.signedInUser || state.authAccessState !== "granted") {
    return "Sign in with an active workspace account before using attendance.";
  }
  if (!String(state.data.workspace?.id || "").trim()) {
    return "Workspace access is still loading. Try again in a moment.";
  }
  return "";
}

function applyAttendanceSnapshotResult(snapshot, options = {}) {
  applySupabaseAttendanceSnapshot(snapshot);
  if (options.persist) {
    saveData(state.data);
  }
  if (options.render !== false) {
    renderRoute();
  }
}

async function runAttendanceSnapshotMutation(operation, options = {}) {
  const unavailableMessage = attendanceSupabaseUnavailableMessage();
  if (unavailableMessage) {
    window.alert(unavailableMessage);
    return false;
  }
  try {
    const snapshot = await operation();
    applyAttendanceSnapshotResult(snapshot, {
      render: options.render !== false,
      persist: false
    });
    return true;
  } catch (error) {
    window.alert(`${String(options.errorPrefix || "Attendance update failed")}: ${String(error?.message || error || "Unknown error")}`);
    return false;
  }
}

function isAttendanceExperienceActive() {
  const attendanceMenu = document.getElementById("attendanceMenu");
  return state.routeId === "attendance" || Boolean(attendanceMenu?.open);
}

function shouldRefreshAttendanceSnapshot(options = {}) {
  if (!state.supabaseConfigured || !state.signedInUser || state.authAccessState !== "granted") {
    return false;
  }
  if (!String(state.data.workspace?.id || "").trim()) {
    return false;
  }
  if (options.force) {
    return true;
  }
  if (!state.attendanceSnapshotLoaded) {
    return true;
  }
  const ageMs = Math.max(0, Date.now() - Number(state.attendanceSnapshotUpdatedAt || 0));
  return ageMs >= ATTENDANCE_SNAPSHOT_STALE_MS;
}

async function ensureFreshAttendanceSnapshot(options = {}) {
  const { force = false, render = false, persist = false, alertOnError = false, syncHeader = false } = options;
  if (!shouldRefreshAttendanceSnapshot({ force })) {
    return false;
  }
  if (attendanceSnapshotRefreshPromise) {
    return attendanceSnapshotRefreshPromise;
  }
  attendanceSnapshotRefreshPromise = (async () => {
    const refreshed = await refreshSupabaseAttendanceData({
      render,
      persist,
      alertOnError
    });
    if (refreshed && syncHeader && !render) {
      updateHeaderMenus();
    }
    return refreshed;
  })().finally(() => {
    attendanceSnapshotRefreshPromise = null;
  });
  return attendanceSnapshotRefreshPromise;
}

async function saveAttendancePolicyForCurrentWorkspace(policy = {}, options = {}) {
  const unavailableMessage = attendanceSupabaseUnavailableMessage();
  if (unavailableMessage) {
    window.alert(unavailableMessage);
    return false;
  }
  const workspaceId = String(state.data.workspace?.id || "").trim();
  if (!workspaceId) {
    window.alert("Attendance policy requires a workspace context.");
    return false;
  }
  try {
    const savedPolicy = await saveSupabaseAttendancePolicyForWorkspace(
      workspaceId,
      policy,
      resolveCurrentUserId(state.data)
    );
    state.data.attendancePolicy = savedPolicy && typeof savedPolicy === "object"
      ? structuredClone(savedPolicy)
      : structuredClone(policy);
    state.attendanceSnapshotLoaded = true;
    if (options.persist) {
      saveData(state.data);
    }
    if (options.render !== false) {
      renderRoute();
    }
    return true;
  } catch (error) {
    window.alert(`${String(options.errorPrefix || "Save attendance policy failed")}: ${String(error?.message || error || "Unknown error")}`);
    return false;
  }
}

async function runAttendanceAction(actionId, options = {}) {
  if (actionId === "attendance-clock-in") {
    return runAttendanceSnapshotMutation(() => clockInSupabaseAttendance(), {
      errorPrefix: "Clock in failed",
      render: options.render
    });
  }
  if (actionId === "attendance-end-break") {
    return runAttendanceSnapshotMutation(() => endSupabaseAttendanceBreak(), {
      errorPrefix: "End break failed",
      render: options.render
    });
  }
  if (actionId === "attendance-clock-out") {
    return runAttendanceSnapshotMutation(() => clockOutSupabaseAttendance(), {
      errorPrefix: "Clock out failed",
      render: options.render
    });
  }
  if (actionId === "attendance-start-break") {
    return runAttendanceSnapshotMutation(() => startSupabaseAttendanceBreak(options.breakTypeId), {
      errorPrefix: "Start break failed",
      render: options.render
    });
  }
  return false;
}

function openAttendanceClockOutConfirm(snapshot = getAttendanceSnapshot(state.data, getLiveNowIso())) {
  const status = String(snapshot?.status || "off").trim().toLowerCase();
  const onBreak = status === "on-break";
  const confirmLabel = onBreak ? "End Break + Clock Out" : "Clock Out";
  openConfirmModal({
    title: onBreak ? "End break and clock out?" : "Clock out now?",
    message: onBreak
      ? "This will end the current break and clock you out for the day."
      : "This will clock you out for the day.",
    confirmLabel,
    danger: true,
    onConfirm: async () => {
      const didClockOut = await runAttendanceAction("attendance-clock-out");
      if (didClockOut) {
        showToast(onBreak ? "Break ended. Clocked out." : "Clocked out.", { tone: "success" });
      }
    }
  });
}

function parseIsoDateLocal(value) {
  const raw = String(value || "").trim();
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) {
    return null;
  }
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  if (!year || !month || !day) {
    return null;
  }
  const date = new Date(year, month - 1, day);
  if (Number.isNaN(date.valueOf())) {
    return null;
  }
  return date;
}

function toIsoDate(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.valueOf())) {
    return "";
  }
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function formatTimeForInput(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.valueOf())) {
    return "";
  }
  const hours = String(date.getHours()).padStart(2, "0");
  const minutes = String(date.getMinutes()).padStart(2, "0");
  return `${hours}:${minutes}`;
}

function toDateTimeLocalValue(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.valueOf())) {
    return "";
  }
  return `${toIsoDate(date)}T${formatTimeForInput(date)}`;
}

function formatDateTimeLocalInput(value) {
  return toDateTimeLocalValue(value);
}

function parseDateTimeLocal(value) {
  const raw = String(value || "").trim();
  const match = raw.match(/^(\d{4}-\d{2}-\d{2})T(\d{1,2}:\d{2})$/);
  if (!match) {
    return null;
  }
  const date = parseIsoDateLocal(match[1]);
  const time = normalizeTimeValue(match[2], "");
  if (!date || !time) {
    return null;
  }
  const [hours, minutes] = time.split(":").map(Number);
  date.setHours(hours, minutes, 0, 0);
  return date;
}

function monthStartIso(value) {
  const date = parseIsoDateLocal(value);
  if (!date) {
    return "";
  }
  date.setDate(1);
  return toIsoDate(date);
}

function shiftMonthIso(value, offset = 0) {
  const base = parseIsoDateLocal(value) || parseIsoDateLocal(todayIso(0));
  if (!base) {
    return "";
  }
  base.setDate(1);
  base.setMonth(base.getMonth() + Number(offset || 0), 1);
  return toIsoDate(base);
}

function csvEscape(value) {
  const text = String(value ?? "");
  if (!text.includes(",") && !text.includes("\"") && !text.includes("\n")) {
    return text;
  }
  return `"${text.replace(/"/g, "\"\"")}"`;
}

function downloadCsvFile(lines, fileName) {
  const blob = new Blob([lines.join("\n")], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function buildLeadImportExportFileName(fileName, suffix) {
  const normalizedSuffix = String(suffix || "").trim() || "export";
  const rawName = String(fileName || "").trim();
  const baseName = rawName.replace(/\.[^.]+$/u, "").trim() || "lead-import";
  const safeBaseName = baseName
    .replace(/[<>:"/\\|?*\u0000-\u001f]/g, "-")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
  return `${safeBaseName || "lead-import"}-${normalizedSuffix}.csv`;
}

const LEAD_ACTIVE_TABLE_EXPORT_HEADERS = [
  "Lead",
  "Phone",
  "Timezone",
  "Interest",
  "Status",
  "Owner",
  "Last Touch",
  "Next Follow-up"
];

function canExportAllUnqualifiedLeads() {
  return ["Owner", "Admin", "Manager"].includes(String(resolveCurrentUserRole(state.data) || "").trim());
}

function formatLeadExportPhone(lead) {
  const values = [lead?.phone, lead?.secondaryPhone]
    .map((value) => String(value || "").trim())
    .filter(Boolean);
  return values.length ? values.join("; ") : "No phone";
}

function formatLeadExportTimezoneBucket(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "eastern") {
    return "Eastern";
  }
  if (normalized === "central") {
    return "Central";
  }
  if (normalized === "mountain") {
    return "Mountain";
  }
  if (normalized === "pacific") {
    return "Pacific";
  }
  return "Unknown";
}

function leadExportDayDiffFromToday(value) {
  const parsed = Date.parse(String(value || ""));
  if (!Number.isFinite(parsed)) {
    return null;
  }
  const date = new Date(parsed);
  const today = new Date();
  const targetDay = new Date(date.getFullYear(), date.getMonth(), date.getDate()).getTime();
  const currentDay = new Date(today.getFullYear(), today.getMonth(), today.getDate()).getTime();
  return Math.round((targetDay - currentDay) / 86400000);
}

function formatLeadExportTableDate(value) {
  const parsed = Date.parse(String(value || ""));
  if (!Number.isFinite(parsed)) {
    return "Not set";
  }
  const date = new Date(parsed);
  const now = new Date();
  const sameYear = date.getFullYear() === now.getFullYear();
  return new Intl.DateTimeFormat(
    "en-US",
    sameYear ? { month: "short", day: "numeric" } : { month: "short", day: "numeric", year: "numeric" }
  ).format(date);
}

function formatLeadExportLastTouch(value) {
  const parsed = Date.parse(String(value || ""));
  if (!Number.isFinite(parsed)) {
    return "No activity";
  }
  const diff = leadExportDayDiffFromToday(value);
  const date = new Date(parsed);
  if (diff === 0) {
    return `Today, ${new Intl.DateTimeFormat("en-US", { hour: "numeric", minute: "2-digit" }).format(date)}`;
  }
  if (diff === -1) {
    return "Yesterday";
  }
  return formatLeadExportTableDate(value);
}

function formatLeadExportNextFollowUp(value) {
  const parsed = Date.parse(String(value || ""));
  if (!Number.isFinite(parsed)) {
    return "Not set";
  }
  const diff = leadExportDayDiffFromToday(value);
  if (diff < 0) {
    return "Overdue";
  }
  if (diff === 0) {
    return "Today";
  }
  if (diff === 1) {
    return "Tomorrow";
  }
  return formatLeadExportTableDate(value);
}

function getLeadExportLastTouchValue(lead) {
  return String(lead?._lastTouchAt || "").trim();
}

function getLeadExportOwner(lead) {
  const ownerId = String(lead?.ownerId || "").trim();
  return (
    String(lead?._ownerDisplay || "").trim() ||
    String(lead?.owner || "").trim() ||
    String(findTeamMemberById(ownerId)?.name || "").trim()
  );
}

function buildActiveLeadTableExportRows(leads = []) {
  const rows = [LEAD_ACTIVE_TABLE_EXPORT_HEADERS];
  (Array.isArray(leads) ? leads : []).forEach((lead) => {
    rows.push([
      String(lead?.name || "Unnamed Lead").trim() || "Unnamed Lead",
      formatLeadExportPhone(lead),
      formatLeadExportTimezoneBucket(lead?.phoneTimezoneBucket),
      String(lead?.interest || "No interest").trim() || "No interest",
      String(lead?.status || "New").trim() || "New",
      getLeadExportOwner(lead),
      formatLeadExportLastTouch(getLeadExportLastTouchValue(lead)),
      formatLeadExportNextFollowUp(lead?.nextFollowUp)
    ]);
  });
  return rows;
}

function downloadActiveLeadTableCsv(leads = [], fileName = `unqualified-leads-${todayIso(0)}.csv`) {
  const lines = buildActiveLeadTableExportRows(leads).map((row) => row.map(csvEscape).join(","));
  downloadCsvFile(lines, fileName);
}

const LEAD_EXPORT_LOADING_OVERLAY_ID = "leadExportLoadingOverlay";
let isUnqualifiedLeadExportLoading = false;

function waitForNextPaint() {
  if (typeof window === "undefined" || typeof window.requestAnimationFrame !== "function") {
    return Promise.resolve();
  }
  return new Promise((resolve) => {
    window.requestAnimationFrame(() => resolve());
  });
}

function setUnqualifiedLeadExportLoading(isLoading) {
  if (typeof document === "undefined") {
    return;
  }
  const existingOverlay = document.getElementById(LEAD_EXPORT_LOADING_OVERLAY_ID);
  if (!isLoading) {
    existingOverlay?.remove();
    return;
  }
  if (existingOverlay) {
    return;
  }
  const overlay = document.createElement("div");
  overlay.id = LEAD_EXPORT_LOADING_OVERLAY_ID;
  overlay.className = "lead-export-loading-overlay";
  overlay.setAttribute("role", "status");
  overlay.setAttribute("aria-live", "polite");
  overlay.setAttribute("aria-label", "Preparing unqualified leads export");
  overlay.innerHTML = `
    <div class="lead-export-loading-spinner" aria-hidden="true"></div>
    <span class="lead-export-loading-label">Preparing export</span>
  `;
  document.body.appendChild(overlay);
}

async function getAllUnqualifiedLeadsForExport() {
  if (shouldUseSupabaseLeadsRouteData()) {
    const workspaceId = String(state.data.workspace?.id || "").trim();
    if (!workspaceId) {
      return [];
    }
    return fetchSupabaseAllUnqualifiedLeads(workspaceId, {
      teamMembers: state.data.teamMembers
    });
  }
  return (Array.isArray(state.data.leads) ? state.data.leads : [])
    .filter((lead) => String(lead?.status || "").trim() === "Unqualified");
}

async function openUnqualifiedLeadExportConfirm() {
  if (!canExportAllUnqualifiedLeads()) {
    window.alert("You do not have access to export all unqualified leads.");
    return;
  }
  if (isUnqualifiedLeadExportLoading) {
    return;
  }
  let leads = [];
  isUnqualifiedLeadExportLoading = true;
  setUnqualifiedLeadExportLoading(true);
  try {
    await waitForNextPaint();
    leads = await getAllUnqualifiedLeadsForExport();
  } catch (error) {
    console.error("Unqualified lead export failed:", error);
    window.alert(`Export failed: ${String(error?.message || error || "Unknown error")}`);
    return;
  } finally {
    isUnqualifiedLeadExportLoading = false;
    setUnqualifiedLeadExportLoading(false);
  }
  const count = leads.length;
  openConfirmModal({
    title: "Export unqualified leads?",
    message: `Export ${count} unqualified lead${count === 1 ? "" : "s"} using the active Leads table columns?`,
    confirmLabel: "Export",
    cancelLabel: "Cancel",
    danger: false,
    onConfirm: () => {
      downloadActiveLeadTableCsv(leads);
      return true;
    }
  });
}

function getLeadExportLabel(exportType) {
  const normalizedType = String(exportType || "").trim();
  if (normalizedType === "duplicates") {
    return "duplicate leads";
  }
  if (normalizedType === "leads") {
    return "leads";
  }
  return "unqualified leads";
}

function getSupabaseClient() {
  const services = initSupabase();
  if (!services.configured || !services.client) {
    throw new Error("Supabase is not configured.");
  }
  return services.client;
}

function parseLeadExportDateValue(value) {
  const normalized = String(value || "").trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(normalized)) {
    return null;
  }
  const [year, month, day] = normalized.split("-").map((part) => Number(part));
  const date = new Date(year, month - 1, day);
  if (date.getFullYear() !== year || date.getMonth() !== month - 1 || date.getDate() !== day) {
    return null;
  }
  return date;
}

function formatLeadExportDateValue(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function formatLeadExportDateDisplay(value) {
  const date = parseLeadExportDateValue(value);
  if (!date) {
    return "Select date";
  }
  return date.toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" });
}

function getLeadExportVisibleMonth(control) {
  const visibleValue = String(control.dataset.visibleMonth || "").trim();
  const selectedDate = parseLeadExportDateValue(control.querySelector("input")?.value);
  const baseDate = parseLeadExportDateValue(`${visibleValue}-01`) || selectedDate || new Date();
  return new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
}

function renderLeadExportDatePicker(control) {
  const input = control.querySelector("input");
  const trigger = control.querySelector("[data-lead-export-date-toggle]");
  const panel = control.querySelector("[data-lead-export-date-panel]");
  if (!input || !trigger || !panel) {
    return;
  }
  const selectedDate = parseLeadExportDateValue(input.value);
  const monthDate = getLeadExportVisibleMonth(control);
  control.dataset.visibleMonth = formatLeadExportDateValue(monthDate).slice(0, 7);
  trigger.textContent = formatLeadExportDateDisplay(input.value);
  trigger.classList.toggle("is-empty", !selectedDate);

  const firstDayIndex = monthDate.getDay();
  const daysInMonth = new Date(monthDate.getFullYear(), monthDate.getMonth() + 1, 0).getDate();
  const previousMonthDays = new Date(monthDate.getFullYear(), monthDate.getMonth(), 0).getDate();
  const cells = [];
  for (let index = 0; index < 42; index += 1) {
    const dayNumber = index - firstDayIndex + 1;
    const isCurrentMonth = dayNumber >= 1 && dayNumber <= daysInMonth;
    const displayDay = isCurrentMonth
      ? dayNumber
      : dayNumber < 1
        ? previousMonthDays + dayNumber
        : dayNumber - daysInMonth;
    const cellDate = new Date(
      monthDate.getFullYear(),
      monthDate.getMonth() + (isCurrentMonth ? 0 : dayNumber < 1 ? -1 : 1),
      displayDay
    );
    const iso = formatLeadExportDateValue(cellDate);
    const isSelected = selectedDate && iso === formatLeadExportDateValue(selectedDate);
    cells.push(
      `<button type="button" class="lead-export-calendar-day${isCurrentMonth ? "" : " is-muted"}${isSelected ? " is-selected" : ""}" data-lead-export-date-day="${iso}">${displayDay}</button>`
    );
  }

  panel.innerHTML = `
    <div class="lead-export-calendar-head">
      <button type="button" class="icon-btn" data-lead-export-date-shift="-1" aria-label="Previous month"><i class="bi bi-chevron-left"></i></button>
      <strong>${monthDate.toLocaleDateString(undefined, { month: "long", year: "numeric" })}</strong>
      <button type="button" class="icon-btn" data-lead-export-date-shift="1" aria-label="Next month"><i class="bi bi-chevron-right"></i></button>
    </div>
    <div class="lead-export-calendar-weekdays">
      <span>Su</span><span>Mo</span><span>Tu</span><span>We</span><span>Th</span><span>Fr</span><span>Sa</span>
    </div>
    <div class="lead-export-calendar-grid">${cells.join("")}</div>
    <div class="lead-export-calendar-foot">
      <button type="button" class="mini-btn" data-lead-export-date-clear>Clear</button>
      <button type="button" class="mini-btn" data-lead-export-date-today>Today</button>
    </div>
  `;
}

function setupLeadExportDatePickers(container) {
  const controls = Array.from(container.querySelectorAll("[data-lead-export-date-control]"));
  const closePanels = (exceptControl = null) => {
    controls.forEach((control) => {
      if (control !== exceptControl) {
        control.classList.remove("is-open");
      }
    });
  };
  controls.forEach((control) => renderLeadExportDatePicker(control));
  if (container.leadExportDatePickerHandler) {
    container.removeEventListener("click", container.leadExportDatePickerHandler);
  }
  container.leadExportDatePickerHandler = (event) => {
    const control = event.target.closest("[data-lead-export-date-control]");
    if (!control) {
      closePanels();
      return;
    }
    const input = control.querySelector("input");
    if (event.target.closest("[data-lead-export-date-toggle]")) {
      closePanels(control);
      control.classList.toggle("is-open");
      renderLeadExportDatePicker(control);
      return;
    }
    const shiftButton = event.target.closest("[data-lead-export-date-shift]");
    if (shiftButton) {
      const monthDate = getLeadExportVisibleMonth(control);
      monthDate.setMonth(monthDate.getMonth() + Number(shiftButton.dataset.leadExportDateShift || 0));
      control.dataset.visibleMonth = formatLeadExportDateValue(monthDate).slice(0, 7);
      renderLeadExportDatePicker(control);
      return;
    }
    const dayButton = event.target.closest("[data-lead-export-date-day]");
    if (dayButton && input) {
      input.value = String(dayButton.dataset.leadExportDateDay || "");
      control.dataset.visibleMonth = input.value.slice(0, 7);
      control.classList.remove("is-open");
      renderLeadExportDatePicker(control);
      return;
    }
    if (event.target.closest("[data-lead-export-date-clear]") && input) {
      input.value = "";
      renderLeadExportDatePicker(control);
      return;
    }
    if (event.target.closest("[data-lead-export-date-today]") && input) {
      input.value = formatLeadExportDateValue(new Date());
      control.dataset.visibleMonth = input.value.slice(0, 7);
      control.classList.remove("is-open");
      renderLeadExportDatePicker(control);
    }
  };
  container.addEventListener("click", container.leadExportDatePickerHandler);
}

function syncLeadExportAttemptFilter(form) {
  const field = form?.querySelector?.("[data-lead-export-attempt-field]");
  if (!(field instanceof HTMLElement)) {
    return;
  }
  const statusValue = String(form.querySelector("[name='leadExportStatus']")?.value || "all").trim();
  field.hidden = statusValue !== "Contacted";
  if (field.hidden) {
    const defaultInput = field.querySelector("input[name='leadExportAttemptFilter'][value='all']");
    if (defaultInput instanceof HTMLInputElement) {
      defaultInput.checked = true;
    }
  }
}

