function attendanceUserMatcherFromValue(member, fallbackName = "") {
  const fallback = String(fallbackName || "").trim().toLowerCase();
  const memberId = String(member?.id || "").trim();
  const memberName = String(member?.name || "").trim().toLowerCase();
  return (record) => {
    const recordId = String(record?.userId || "").trim();
    const recordName = String(record?.userName || "").trim().toLowerCase();
    if (recordId && memberId && recordId === memberId) {
      return true;
    }
    if (recordName && memberName && recordName === memberName) {
      return true;
    }
    if (recordName && fallback && recordName === fallback) {
      return true;
    }
    return false;
  };
}

function composeDeadlineAt(dueDate, time) {
  const safeDate = String(dueDate || "").trim() || todayIso(0);
  const safeTime = normalizeTimeValue(time, "09:00");
  return `${safeDate}T${safeTime}`;
}

function splitDeadlineAt(deadlineAt) {
  const parsed = parseDateTimeLocal(deadlineAt);
  if (parsed) {
    return {
      dueDate: toIsoDate(parsed),
      startTime: formatTimeForInput(parsed),
      deadlineAt: toDateTimeLocalValue(parsed)
    };
  }
  const fallbackDate = todayIso(0);
  return {
    dueDate: fallbackDate,
    startTime: "09:00",
    deadlineAt: `${fallbackDate}T09:00`
  };
}

function addDaysToIso(isoDate, dayOffset) {
  const source = parseIsoDateLocal(isoDate) || new Date();
  source.setDate(source.getDate() + Number(dayOffset || 0));
  return toIsoDate(source);
}

function getWeekStartMonday(referenceDate = new Date()) {
  const date = new Date(referenceDate.getFullYear(), referenceDate.getMonth(), referenceDate.getDate());
  const day = date.getDay();
  const diffToMonday = day === 0 ? -6 : 1 - day;
  date.setDate(date.getDate() + diffToMonday);
  return date;
}

function getDateForWeekdayLabel(dayLabel, referenceDate = new Date()) {
  const normalized = String(dayLabel || "").trim().slice(0, 3).toLowerCase();
  const indexByDay = { mon: 0, tue: 1, wed: 2, thu: 3, fri: 4, sat: 5, sun: 6 };
  const offset = indexByDay[normalized];
  if (offset === undefined) {
    return "";
  }
  const monday = getWeekStartMonday(referenceDate);
  monday.setDate(monday.getDate() + offset);
  return toIsoDate(monday);
}

function getWeekdayLabelFromIso(isoDate) {
  const parsed = parseIsoDateLocal(isoDate);
  if (!parsed) {
    return "";
  }
  const labels = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
  return labels[parsed.getDay()] || "";
}

function normalizeTimeValue(value, fallback = "09:00") {
  const raw = String(value || "").trim();
  const match = raw.match(/^(\d{1,2}):(\d{2})$/);
  if (!match) {
    return fallback;
  }
  const hours = Number(match[1]);
  const minutes = Number(match[2]);
  if (Number.isNaN(hours) || Number.isNaN(minutes) || hours < 0 || hours > 23 || minutes < 0 || minutes > 59) {
    return fallback;
  }
  return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}`;
}

function formatTimeSelectLabel(value) {
  const normalized = normalizeTimeValue(value, "");
  if (!normalized) {
    return "";
  }
  const [hours, minutes] = normalized.split(":").map(Number);
  const suffix = hours >= 12 ? "PM" : "AM";
  const hour12 = ((hours + 11) % 12) + 1;
  return `${hour12}:${String(minutes).padStart(2, "0")} ${suffix}`;
}

function buildAttendanceTimeOptions(stepMinutes = ATTENDANCE_TIME_STEP_MINUTES) {
  const safeStep = Math.max(5, Number(stepMinutes) || ATTENDANCE_TIME_STEP_MINUTES);
  const options = [];
  for (let minute = 0; minute < 1440; minute += safeStep) {
    const hourValue = Math.floor(minute / 60);
    const minuteValue = minute % 60;
    options.push(`${String(hourValue).padStart(2, "0")}:${String(minuteValue).padStart(2, "0")}`);
  }
  return options;
}

const ATTENDANCE_TIME_OPTIONS = buildAttendanceTimeOptions();

function formatTimezoneOptionLabel(value) {
  const timezone = String(value || "").trim();
  if (!timezone) {
    return "";
  }
  if (timezone.toLowerCase() === "local") {
    const browserTz = Intl.DateTimeFormat().resolvedOptions().timeZone || "";
    return browserTz ? `Local (${browserTz})` : "Local (Browser)";
  }
  try {
    const formatter = new Intl.DateTimeFormat("en-US", {
      hour: "2-digit",
      minute: "2-digit",
      timeZone: timezone,
      timeZoneName: "shortOffset"
    });
    const offset = formatter.formatToParts(new Date()).find((part) => part.type === "timeZoneName")?.value || "";
    const normalizedOffset = offset.replace(/^GMT/i, "UTC");
    return normalizedOffset ? `${timezone} (${normalizedOffset})` : timezone;
  } catch {
    return timezone;
  }
}

function getLiveNowMs() {
  return Date.now() + Number(state.serverTimeOffsetMs || 0);
}

function getLiveNowDate() {
  return new Date(getLiveNowMs());
}

function getLiveNowIso() {
  return getLiveNowDate().toISOString();
}

function normalizeClockTimezoneValue(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return "Local";
  }
  if (raw.toLowerCase().startsWith("local")) {
    return "Local";
  }
  return raw;
}

function getDatePartsForTimeZone(value, timeZone = "") {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.valueOf())) {
    return null;
  }
  const formatterOptions = {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  };
  if (timeZone) {
    formatterOptions.timeZone = timeZone;
  }
  const parts = new Intl.DateTimeFormat("en-US", formatterOptions).formatToParts(date).reduce((accumulator, part) => {
    if (part.type !== "literal") {
      accumulator[part.type] = part.value;
    }
    return accumulator;
  }, {});
  return {
    year: Number(parts.year || 0),
    month: Number(parts.month || 0),
    day: Number(parts.day || 0),
    hour: Number(parts.hour || 0),
    minute: Number(parts.minute || 0),
    isoDate: parts.year && parts.month && parts.day ? `${parts.year}-${parts.month}-${parts.day}` : ""
  };
}

function isValidIanaTimezone(value) {
  const zone = String(value || "").trim();
  if (!zone) {
    return false;
  }
  try {
    new Intl.DateTimeFormat("en-US", { timeZone: zone }).format(new Date());
    return true;
  } catch {
    return false;
  }
}

function resolveTopbarClockTimezone(data = state.data) {
  const candidates = [
    data?.attendancePolicy?.timezone,
    data?.workspace?.timezone,
    data?.currentUser?.timezone,
    "Local"
  ];
  for (const item of candidates) {
    const normalized = normalizeClockTimezoneValue(item);
    if (normalized === "Local") {
      return {
        timeZone: "",
        label: formatTimezoneOptionLabel("Local")
      };
    }
    if (isValidIanaTimezone(normalized)) {
      return {
        timeZone: normalized,
        label: formatTimezoneOptionLabel(normalized)
      };
    }
  }
  return {
    timeZone: "",
    label: formatTimezoneOptionLabel("Local")
  };
}

function resolveAttendanceUiTimeZone(policy = state.data?.attendancePolicy) {
  const normalized = normalizeClockTimezoneValue(policy?.timezone || state.data?.workspace?.timezone || "Local");
  return isValidIanaTimezone(normalized) ? normalized : "";
}

function formatTopbarClockTime(dateValue, timeZone = "") {
  const safeDate = dateValue instanceof Date ? dateValue : new Date(dateValue);
  if (Number.isNaN(safeDate.valueOf())) {
    return "--:--:--";
  }
  const formatterOptions = {
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  };
  if (timeZone) {
    formatterOptions.timeZone = timeZone;
  }
  return new Intl.DateTimeFormat("en-US", formatterOptions).format(safeDate);
}

function formatAttendanceTodayClockTime(dateValue, timeZone = "") {
  const safeDate = dateValue instanceof Date ? dateValue : new Date(dateValue);
  if (Number.isNaN(safeDate.valueOf())) {
    return "--:--:-- --";
  }
  const formatterOptions = {
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: true
  };
  if (timeZone) {
    formatterOptions.timeZone = timeZone;
  }
  return new Intl.DateTimeFormat("en-US", formatterOptions).format(safeDate);
}

function formatTopbarClockShortTime(dateValue, timeZone = "") {
  const safeDate = dateValue instanceof Date ? dateValue : new Date(dateValue);
  if (Number.isNaN(safeDate.valueOf())) {
    return "--:--";
  }
  const formatterOptions = {
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  };
  if (timeZone) {
    formatterOptions.timeZone = timeZone;
  }
  return new Intl.DateTimeFormat("en-US", formatterOptions).format(safeDate);
}

function formatTopbarClockOffset(dateValue, timeZone = "") {
  const safeDate = dateValue instanceof Date ? dateValue : new Date(dateValue);
  if (Number.isNaN(safeDate.valueOf())) {
    return "UTC";
  }
  try {
    const formatterOptions = {
      hour: "2-digit",
      minute: "2-digit",
      timeZoneName: "shortOffset"
    };
    if (timeZone) {
      formatterOptions.timeZone = timeZone;
    }
    const rawOffset = new Intl.DateTimeFormat("en-US", formatterOptions)
      .formatToParts(safeDate)
      .find((part) => part.type === "timeZoneName")?.value || "";
    const normalized = rawOffset.replace(/^GMT/i, "UTC");
    if (!normalized) {
      return "UTC";
    }
    const compact = normalized.replace(/^UTC([+-])0(\d)(?::00)?$/, "UTC$1$2").replace(/:00$/, "");
    return compact;
  } catch {
    return "UTC";
  }
}

function attendancePolicyTimezoneOptionValues(selectedValue) {
  const normalizedSelected = String(selectedValue || "Local").trim() || "Local";
  return ATTENDANCE_TIMEZONE_OPTIONS.includes(normalizedSelected)
    ? ATTENDANCE_TIMEZONE_OPTIONS
    : [normalizedSelected, ...ATTENDANCE_TIMEZONE_OPTIONS];
}

function attendancePolicyTimeOptionsMarkup(fieldKey, selectedValue) {
  const normalizedSelected = normalizeTimeValue(selectedValue, ATTENDANCE_TIME_OPTIONS[0] || "00:00");
  const optionValues = ATTENDANCE_TIME_OPTIONS.includes(normalizedSelected)
    ? ATTENDANCE_TIME_OPTIONS
    : [...ATTENDANCE_TIME_OPTIONS, normalizedSelected].sort((left, right) => timeToMinutes(left) - timeToMinutes(right));
  return optionValues
    .map((value) => {
      const isSelected = value === normalizedSelected;
      return `
        <button
          type="button"
          class="attendance-policy-time-option ${isSelected ? "is-selected" : ""}"
          data-action="attendance-policy-time-set"
          data-id="${escapeModalText(`${fieldKey}|${value}`)}"
          data-att-time-option
          data-value="${escapeModalText(value)}"
        >
          ${escapeModalText(formatTimeSelectLabel(value))}
        </button>
      `;
    })
    .join("");
}

function attendancePolicyTimezoneListMarkup(selectedValue, query = "") {
  const normalizedSelected = String(selectedValue || "Local").trim() || "Local";
  const normalizedQuery = normalizeForMatch(query);
  const candidates = attendancePolicyTimezoneOptionValues(normalizedSelected).filter((value) => {
    if (!normalizedQuery) {
      return true;
    }
    const zoneText = normalizeForMatch(value);
    const labelText = normalizeForMatch(formatTimezoneOptionLabel(value));
    return zoneText.includes(normalizedQuery) || labelText.includes(normalizedQuery);
  });
  if (!candidates.length) {
    return "<p class='task-meta'>No timezone matches.</p>";
  }
  return candidates
    .map((value) => {
      const isSelected = value === normalizedSelected;
      return `
        <button
          type="button"
          class="attendance-policy-timezone-option ${isSelected ? "is-selected" : ""}"
          data-action="attendance-policy-timezone-select"
          data-id="${escapeModalText(value)}"
          data-att-timezone-option
        >
          ${escapeModalText(formatTimezoneOptionLabel(value))}
        </button>
      `;
    })
    .join("");
}

function attendancePolicyTimeControlMarkup(fieldKey, inputName, selectedValue) {
  const normalizedSelected = normalizeTimeValue(selectedValue, ATTENDANCE_TIME_OPTIONS[0] || "00:00");
  return `
    <div class="attendance-policy-time-control" data-att-time-control="${escapeModalText(fieldKey)}">
      <input type="hidden" name="${escapeModalText(inputName)}" value="${escapeModalText(normalizedSelected)}" data-att-time-input="${escapeModalText(fieldKey)}" />
      <button
        type="button"
        class="attendance-policy-time-trigger"
        data-action="attendance-policy-time-toggle"
        data-id="${escapeModalText(fieldKey)}"
        data-att-time-trigger="${escapeModalText(fieldKey)}"
        aria-expanded="false"
      >
        <span data-att-time-label="${escapeModalText(fieldKey)}">${escapeModalText(formatTimeSelectLabel(normalizedSelected))}</span>
        <i class="bi bi-chevron-down" aria-hidden="true"></i>
      </button>
      <div class="attendance-policy-time-popover" data-att-time-popover="${escapeModalText(fieldKey)}" hidden>
        <div class="attendance-policy-time-list">
          ${attendancePolicyTimeOptionsMarkup(fieldKey, normalizedSelected)}
        </div>
      </div>
    </div>
  `;
}

function attendancePolicyTimezoneControlMarkup(selectedValue) {
  const normalizedSelected = String(selectedValue || "Local").trim() || "Local";
  return `
    <div class="attendance-policy-timezone-control" data-att-timezone-control>
      <input type="hidden" name="timezone" value="${escapeModalText(normalizedSelected)}" data-att-timezone-input />
      <button
        type="button"
        class="attendance-policy-timezone-trigger"
        data-action="attendance-policy-timezone-toggle"
        data-att-timezone-trigger
        aria-expanded="false"
      >
        <span data-att-timezone-label>${escapeModalText(formatTimezoneOptionLabel(normalizedSelected))}</span>
        <i class="bi bi-chevron-down" aria-hidden="true"></i>
      </button>
      <div class="attendance-policy-timezone-popover" data-att-timezone-popover hidden>
        <input type="text" class="attendance-policy-timezone-search" placeholder="Search timezone" data-att-timezone-search />
        <div class="attendance-policy-timezone-list" data-att-timezone-list>
          ${attendancePolicyTimezoneListMarkup(normalizedSelected, "")}
        </div>
      </div>
    </div>
  `;
}

function syncAttendancePolicyUi(form) {
  if (!form || form.dataset.mode !== "attendance-policy-compose") {
    return;
  }
  const openTimeKey = String(form.dataset.attendancePolicyTimeOpen || "").trim();
  form.querySelectorAll("[data-att-time-control]").forEach((control) => {
    const key = String(control.dataset.attTimeControl || "").trim();
    if (!key) {
      return;
    }
    const inputNode = control.querySelector(`[data-att-time-input="${key}"]`);
    const labelNode = control.querySelector(`[data-att-time-label="${key}"]`);
    const triggerNode = control.querySelector(`[data-att-time-trigger="${key}"]`);
    const popoverNode = control.querySelector(`[data-att-time-popover="${key}"]`);
    const safeValue = normalizeTimeValue(inputNode?.value, ATTENDANCE_TIME_OPTIONS[0] || "00:00");
    if (inputNode) {
      inputNode.value = safeValue;
    }
    if (labelNode) {
      labelNode.textContent = formatTimeSelectLabel(safeValue);
    }
    const isOpen = openTimeKey === key;
    if (popoverNode) {
      popoverNode.hidden = !isOpen;
    }
    if (triggerNode) {
      triggerNode.classList.toggle("is-open", isOpen);
      triggerNode.setAttribute("aria-expanded", isOpen ? "true" : "false");
    }
    control.querySelectorAll("[data-att-time-option]").forEach((option) => {
      const optionValue = String(option.dataset.value || "");
      option.classList.toggle("is-selected", optionValue === safeValue);
    });
  });

  const timezoneInput = form.querySelector("[data-att-timezone-input]");
  const timezoneLabel = form.querySelector("[data-att-timezone-label]");
  const timezoneTrigger = form.querySelector("[data-att-timezone-trigger]");
  const timezonePopover = form.querySelector("[data-att-timezone-popover]");
  const timezoneSearch = form.querySelector("[data-att-timezone-search]");
  const timezoneList = form.querySelector("[data-att-timezone-list]");
  const selectedTimezone = String(timezoneInput?.value || "Local").trim() || "Local";
  if (timezoneInput) {
    timezoneInput.value = selectedTimezone;
  }
  if (timezoneLabel) {
    timezoneLabel.textContent = formatTimezoneOptionLabel(selectedTimezone);
  }
  const timezoneOpen = form.dataset.attendancePolicyTimezoneOpen === "1";
  if (timezonePopover) {
    timezonePopover.hidden = !timezoneOpen;
  }
  if (timezoneTrigger) {
    timezoneTrigger.classList.toggle("is-open", timezoneOpen);
    timezoneTrigger.setAttribute("aria-expanded", timezoneOpen ? "true" : "false");
  }
  if (timezoneList) {
    timezoneList.innerHTML = attendancePolicyTimezoneListMarkup(selectedTimezone, String(timezoneSearch?.value || ""));
  }
}
function parseLegacyTimeRange(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return { start: "", end: "" };
  }
  const parts = raw.split("-").map((part) => normalizeTimeValue(part.trim(), ""));
  if (parts.length >= 2 && parts[0] && parts[1]) {
    return { start: parts[0], end: parts[1] };
  }
  if (parts[0]) {
    return { start: parts[0], end: "" };
  }
  return { start: "", end: "" };
}

function timeToMinutes(value) {
  const normalized = normalizeTimeValue(value, "");
  if (!normalized) {
    return -1;
  }
  const [hours, minutes] = normalized.split(":").map(Number);
  return hours * 60 + minutes;
}

function addMinutesToTime(value, minutesToAdd) {
  const start = timeToMinutes(value);
  if (start < 0) {
    return "09:30";
  }
  const next = Math.max(0, Math.min(1439, start + Number(minutesToAdd || 0)));
  const hours = Math.floor(next / 60);
  const minutes = next % 60;
  return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}`;
}

function formatTaskTimeRange(startTime, endTime) {
  const start = normalizeTimeValue(startTime, "");
  const end = normalizeTimeValue(endTime, "");
  if (start && end) {
    return `${start} - ${end}`;
  }
  return start || end || "";
}

function formatTaskTimeWindowLabel(task, options = {}) {
  const start = normalizeTimeValue(task?.startTime, "");
  const end = normalizeTimeValue(task?.endTime, "");
  const includeDate = Boolean(options.includeDate);
  const formatClock = (timeValue) => {
    if (!timeValue) {
      return "";
    }
    const parsed = parseDateTimeLocal(composeDeadlineAt(task?.dueDate, timeValue));
    if (!parsed) {
      return timeValue;
    }
    return new Intl.DateTimeFormat("en-US", {
      hour: "numeric",
      minute: "2-digit"
    }).format(parsed);
  };

  const startLabel = formatClock(start);
  const endLabel = formatClock(end);
  const windowLabel = startLabel && endLabel ? `${startLabel} - ${endLabel}` : startLabel || endLabel;
  if (!includeDate) {
    return windowLabel;
  }

  const dateLabel = getTaskDisplayDate(task);
  if (!windowLabel) {
    return dateLabel;
  }
  return `${dateLabel} | ${windowLabel}`;
}

function getLinkedTaskRecord(task) {
  const linkType = canonicalTaskType(task?.linkType, "");
  const linkId = String(task?.linkId || "").trim();
  if (!linkType || !linkId) {
    return null;
  }
  if (linkType === "Lead") {
    return getLeadById(linkId);
  }
  if (linkType === "Contact") {
    return getContactById(linkId);
  }
  if (linkType === "Account") {
    return getAccountById(linkId);
  }
  if (linkType === "Deal") {
    return getDealById(linkId);
  }
  return null;
}

function resolveTaskCallContext(task) {
  const linkedRecord = getLinkedTaskRecord(task);
  const linkedType = canonicalTaskType(task?.linkType, "");
  const fallbackLabel = String(task?.linkLabel || task?.accountName || "").trim();
  const phoneFromTask = String(task?.callPhone || "").trim();
  let name = fallbackLabel || "No linked record";
  let detail = linkedType || "No CRM link";
  let phone = phoneFromTask;

  if (linkedType === "Lead" && linkedRecord) {
    const primaryContact = getPrimaryLeadContactCore(linkedRecord, getLeadContextCore(state.data, linkedRecord, normalizeForMatch));
    name = String(primaryContact?.name || linkedRecord.name || fallbackLabel).trim() || "Lead";
    detail = [linkedRecord.company || "", "Lead"].filter(Boolean).join(" | ") || "Lead";
    phone = phone || String(primaryContact?.phone || linkedRecord.phone || linkedRecord.secondaryPhone || "").trim();
  } else if (linkedType === "Contact" && linkedRecord) {
    name = String(linkedRecord.name || fallbackLabel).trim() || "Contact";
    detail = [linkedRecord.account || "", linkedRecord.role || "", "Contact"].filter(Boolean).join(" | ") || "Contact";
    phone = phone || String(linkedRecord.phone || "").trim();
  } else if (linkedType === "Account" && linkedRecord) {
    const primaryContact = getPrimaryAccountContactCore(state.data, linkedRecord, { requirePhone: true }, normalizeForMatch, normalizePhoneValue);
    name = String(primaryContact?.name || linkedRecord.name || fallbackLabel).trim() || "Account";
    detail = [linkedRecord.name || "", primaryContact ? "Primary contact" : "Account"].filter(Boolean).join(" | ") || "Account";
    phone = phone || String(primaryContact?.phone || linkedRecord.supportPhone || "").trim();
  } else if (linkedType === "Deal" && linkedRecord) {
    const dealContact = String(linkedRecord.contactId || "").trim() ? getContactById(String(linkedRecord.contactId || "").trim()) : null;
    name = String(dealContact?.name || linkedRecord.contactName || linkedRecord.name || fallbackLabel).trim() || "Deal";
    detail = [linkedRecord.account || "", "Deal"].filter(Boolean).join(" | ") || "Deal";
    phone = phone || String(dealContact?.phone || "").trim();
  }

  return {
    linkedType,
    linkedRecord,
    name,
    detail,
    phone,
    scheduleMode: getTaskScheduleMode(task),
    scheduleLabel: getTaskScheduleMode(task) === "window" ? "Call window" : "Exact time"
  };
}

function getTaskDisplayDate(task) {
  if (task?.dueDate) {
    const parsed = parseIsoDateLocal(task.dueDate);
    if (parsed) {
      return new Intl.DateTimeFormat("en-US", {
        weekday: "short",
        month: "short",
        day: "numeric"
      }).format(parsed);
    }
  }
  return String(task?.day || "No day");
}

function getTaskDisplayTime(task) {
  if (task?.deadlineAt) {
    const parsed = parseDateTimeLocal(task.deadlineAt);
    if (parsed) {
      return new Intl.DateTimeFormat("en-US", {
        hour: "numeric",
        minute: "2-digit"
      }).format(parsed);
    }
  }
  const startTime = normalizeTimeValue(task?.startTime, "");
  if (startTime) {
    const parsed = parseDateTimeLocal(composeDeadlineAt(task?.dueDate, startTime));
    if (parsed) {
      return new Intl.DateTimeFormat("en-US", {
        hour: "numeric",
        minute: "2-digit"
      }).format(parsed);
    }
  }
  return String(task?.time || "No time");
}

function getTaskDueDateTime(task) {
  const deadline = parseDateTimeLocal(task?.deadlineAt);
  if (deadline) {
    return deadline;
  }
  const date = parseIsoDateLocal(task?.dueDate);
  if (!date) {
    return null;
  }
  const startTime = normalizeTimeValue(task?.startTime, "09:00");
  const [hours, minutes] = startTime.split(":").map(Number);
  date.setHours(hours, minutes, 0, 0);
  return date;
}

function isTaskOverdue(task) {
  if (!task || String(task.status) === "Completed") {
    return false;
  }
  const due = getTaskDueDateTime(task);
  if (!due) {
    return false;
  }
  return due.valueOf() < Date.now();
}

function normalizeTaskRecord(task, projectById) {
  const next = { ...task };
  const parsedLegacyTime = parseLegacyTimeRange(next.time);

  next.title = String(next.title || "").trim() || "Untitled Task";
  next.assignee = String(next.assignee || "").trim() || state.data.currentUser.name;
  next.assigneeId = String(next.assigneeId || "").trim();
  if (!next.assigneeId && next.assignee) {
    next.assigneeId = resolveTeamMemberIdByName(next.assignee, false);
  }
  if (!next.assignee && next.assigneeId) {
    next.assignee = String(findTeamMemberById(next.assigneeId)?.name || "").trim();
  }
  next.status = TASK_STATUS_FLOW.includes(next.status) ? next.status : "New";
  const normalizedPriority = String(next.priority || "").toLowerCase();
  next.priority = ["high", "medium", "low"].includes(normalizedPriority) ? normalizedPriority : "low";

  const legacyDate = getDateForWeekdayLabel(next.day);
  const rawDueDate = String(next.dueDate || "").trim() || legacyDate || todayIso(0);
  const rawTime = next.startTime || parsedLegacyTime.start || "09:00";
  const parsedDeadline = parseDateTimeLocal(next.deadlineAt);
  if (parsedDeadline) {
    next.dueDate = toIsoDate(parsedDeadline);
    next.startTime = formatTimeForInput(parsedDeadline);
  } else {
    next.dueDate = rawDueDate;
    next.startTime = normalizeTimeValue(rawTime, "09:00");
  }
  next.endTime = normalizeTimeValue(next.endTime, "");
  if (next.endTime && timeToMinutes(next.endTime) <= timeToMinutes(next.startTime)) {
    next.endTime = "";
  }
  next.deadlineAt = composeDeadlineAt(next.dueDate, next.startTime);
  next.day = getWeekdayLabelFromIso(next.dueDate) || String(next.day || "Mon");
  next.time = formatTaskTimeRange(next.startTime, next.endTime) || next.startTime;

  next.notes = String(next.notes || "").trim();
  next.callPhone = String(next.callPhone || "").trim();
  next.recurrence = TASK_RECURRENCE_FLOW.includes(String(next.recurrence || "none").toLowerCase())
    ? String(next.recurrence || "none").toLowerCase()
    : "none";

  const reminderMinutes = Number(next.reminderMinutes);
  next.reminderMinutes = Number.isFinite(reminderMinutes) && reminderMinutes >= 0 ? reminderMinutes : 15;

  const slaHours = Number(next.slaHours);
  next.slaHours = Number.isFinite(slaHours) && slaHours > 0 ? slaHours : "";

  next.createdAt = String(next.createdAt || "").trim() || new Date().toISOString();
  if (next.status === "Completed") {
    next.completedAt = String(next.completedAt || "").trim() || new Date().toISOString();
  } else {
    next.completedAt = "";
  }
  next.permissions = normalizeTaskPermissions(next.permissions);
  next.backlogState = ["queue", "scheduled"].includes(String(next.backlogState || "").toLowerCase())
    ? String(next.backlogState || "").toLowerCase()
    : "scheduled";

  next.projectId = String(next.projectId || "").trim();
  next.projectName = String(next.projectName || "").trim();
  if (next.projectId && projectById.has(next.projectId)) {
    next.projectName = projectById.get(next.projectId).name;
  } else if (next.projectName) {
    const exact = [...projectById.values()].find(
      (project) => String(project.name || "").toLowerCase() === next.projectName.toLowerCase()
    );
    if (exact) {
      next.projectId = exact.id;
      next.projectName = exact.name;
    }
  } else {
    next.projectId = "";
    next.projectName = "";
  }

  const rawLinkType = String(next.linkType || "").trim();
  next.linkType = TASK_LINK_TYPES.includes(rawLinkType) ? rawLinkType : "";
  next.linkId = String(next.linkId || "").trim();
  next.linkLabel = String(next.linkLabel || "").trim();

  if (next.projectId && next.projectName) {
    next.linkType = "Project";
    next.linkId = next.projectId;
    next.linkLabel = next.projectName;
  }

  const linkedProject = next.projectId && projectById.has(next.projectId) ? projectById.get(next.projectId) : null;
  const projectAccountName = linkedProject
    ? String(linkedProject.accountName || linkedProject.account || "").trim()
    : "";
  next.accountName = String(next.accountName || next.account || "").trim() || projectAccountName || "";
  next.account = next.accountName;

  const explicitTaskType = canonicalTaskType(next.taskType, "");
  if (explicitTaskType) {
    next.taskType = explicitTaskType;
  } else if (next.recurrence !== "none") {
    next.taskType = "Recurring";
  } else if (next.linkType) {
    next.taskType = next.linkType;
  } else {
    next.taskType = "General";
  }
  if (!isCallTaskType(next.taskType)) {
    next.endTime = "";
    next.callPhone = "";
    next.time = next.startTime;
  }

  return next;
}

function normalizeProjectRecord(project) {
  const next = { ...project };
  next.name = String(next.name || "").trim() || "Untitled Project";
  next.ownerId = String(next.ownerId || "").trim();
  if (!next.ownerId && next.owner) {
    next.ownerId = resolveTeamMemberIdByName(next.owner, false);
  }
  next.owner = String(next.owner || "").trim() || state.data.currentUser.name;
  if (!next.owner && next.ownerId) {
    next.owner = String(findTeamMemberById(next.ownerId)?.name || "").trim();
  }
  next.status = normalizeProjectStatus(next.status);
  const progressRaw = Number(next.progress);
  next.progress = Number.isFinite(progressRaw) ? Math.max(0, Math.min(100, Math.round(progressRaw))) : 0;
  next.deadline = parseIsoDateLocal(String(next.deadline || "").trim()) ? String(next.deadline).trim() : todayIso(14);
  next.accountId = String(next.accountId || "").trim();
  next.accountName = String(next.accountName || next.account || "").trim();
  next.account = next.accountName;
  next.teamMemberIds = parseProjectTeamMembers(next.teamMemberIds);
  if (!next.teamMemberIds.length && Array.isArray(next.teamMembers)) {
    next.teamMemberIds = next.teamMembers.map((name) => resolveTeamMemberIdByName(name, false)).filter(Boolean);
  }
  next.teamMembers = next.teamMemberIds
    .map((memberId) => String(findTeamMemberById(memberId)?.name || "").trim())
    .filter(Boolean);
  next.description = String(next.description || "").trim();
  next.risks = String(next.risks || "").trim();
  next.activity = Array.isArray(next.activity)
    ? next.activity
        .map((entry) => ({
          id: String(entry?.id || createId("pactivity")),
          type: String(entry?.type || "update").trim() || "update",
          actor: String(entry?.actor || "System").trim() || "System",
          actorId: String(entry?.actorId || "").trim(),
          text: String(entry?.text || "").trim() || "Updated project",
          details: entry?.details && typeof entry.details === "object" ? { ...entry.details } : {},
          taskId: String(entry?.taskId || "").trim(),
          taskTitle: String(entry?.taskTitle || "").trim(),
          createdAt: String(entry?.createdAt || "").trim() || new Date().toISOString()
        }))
        .sort((a, b) => Date.parse(String(b.createdAt || "")) - Date.parse(String(a.createdAt || "")))
    : [];
  next.createdAt = String(next.createdAt || "").trim() || new Date().toISOString();
  next.updatedAt = String(next.updatedAt || "").trim() || next.createdAt;
  return next;
}

function normalizeProjectCollection(data) {
  data.projects = (Array.isArray(data.projects) ? data.projects : []).map((project) => normalizeProjectRecord(project));
}

function normalizeTaskCollection(data) {
  const projects = Array.isArray(data.projects) ? data.projects : [];
  const projectById = new Map(projects.map((project) => [project.id, project]));
  data.tasks = (Array.isArray(data.tasks) ? data.tasks : []).map((task) => {
    const normalized = normalizeTaskRecord(task, projectById);
    ensureTaskDetailCollections(normalized);
    return normalized;
  });
}

function buildWaitingListFromTasks(tasks = []) {
  const today = todayIso(0);
  const tomorrow = todayIso(1);
  return (Array.isArray(tasks) ? tasks : [])
    .filter((task) => String(task.backlogState || "").toLowerCase() === "queue")
    .map((task) => {
      const dueDate = String(task.dueDate || "").trim();
      let status = "none";
      let label = "";
      if (dueDate) {
        if (dueDate < today) {
          status = "overdue";
          label = "Overdue";
        } else if (dueDate === today) {
          status = "today";
          label = "Today";
        } else if (dueDate === tomorrow) {
          status = "tomorrow";
          label = "Tomorrow";
        } else {
          label = dueDate;
        }
      }
      return {
        id: task.id,
        title: task.title,
        owner: task.assignee || "Unassigned",
        linkedType: task.linkType || task.taskType || "Task",
        due: {
          dueDate,
          status,
          label
        }
      };
    });
}

function syncWorkCollections(data) {
  normalizeProjectCollection(data);
  normalizeTaskCollection(data);
  data.waitingList = buildWaitingListFromTasks(data.tasks);
}

function ensureTaskDetailCollections(task) {
  if (!task) {
    return task;
  }
  task.comments = Array.isArray(task.comments)
    ? task.comments
        .map((comment) => ({
          id: String(comment?.id || createId("tcomment")),
          author: String(comment?.author || "").trim() || "Unknown",
          text: String(comment?.text || "").trim(),
          createdAt: String(comment?.createdAt || "").trim() || new Date().toISOString()
        }))
        .filter((comment) => comment.text)
    : [];
  task.attachments = Array.isArray(task.attachments)
    ? task.attachments
        .map((file) => ({
          id: String(file?.id || createId("tfile")),
          name: String(file?.name || "").trim(),
          size: Number(file?.size || 0),
          type: String(file?.type || "").trim(),
          storagePath: String(file?.storagePath || "").trim(),
          addedBy: String(file?.addedBy || "").trim() || resolveCurrentUserName(state.data),
          addedById: String(file?.addedById || "").trim(),
          createdAt: String(file?.createdAt || "").trim() || new Date().toISOString(),
          canDelete: file?.canDelete === undefined ? true : Boolean(file?.canDelete)
        }))
        .filter((file) => file.name)
    : [];
  task.checklist = Array.isArray(task.checklist)
    ? task.checklist
        .map((item) => ({
          id: String(item?.id || createId("tcheck")),
          label: String(item?.label || "").trim(),
          done: Boolean(item?.done),
          createdAt: String(item?.createdAt || "").trim() || new Date().toISOString(),
          completedAt: Boolean(item?.done)
            ? String(item?.completedAt || "").trim() || new Date().toISOString()
            : ""
        }))
        .filter((item) => item.label)
    : [];
  task.activity = Array.isArray(task.activity)
    ? task.activity
        .map((entry) => ({
          id: String(entry?.id || createId("tactivity")),
          type: String(entry?.type || "").trim() || "update",
          actor: String(entry?.actor || "").trim() || "System",
          text: String(entry?.text || "").trim(),
          createdAt: String(entry?.createdAt || "").trim() || new Date().toISOString()
        }))
        .filter((entry) => entry.text)
    : [];
  task.updatedAt = String(task.updatedAt || "").trim() || String(task.createdAt || "").trim() || new Date().toISOString();
  if (!task.activity.length) {
    task.activity.push({
      id: createId("tactivity"),
      type: "created",
      actor: String(task.assignee || "").trim() || "System",
      text: "Task created",
      createdAt: String(task.createdAt || "").trim() || new Date().toISOString()
    });
  }
  return task;
}

function recordTaskActivity(task, text, type = "update", actor = resolveCurrentUserName(state.data)) {
  if (!task || !text) {
    return;
  }
  ensureTaskDetailCollections(task);
  task.updatedAt = new Date().toISOString();
  task.activity.unshift({
    id: createId("tactivity"),
    type: String(type || "update").trim() || "update",
    actor: String(actor || "").trim() || "System",
    text: String(text || "").trim(),
    createdAt: task.updatedAt
  });
}

function formatTaskSheetDateTime(value) {
  const parsed = Date.parse(String(value || ""));
  if (!Number.isFinite(parsed)) {
    return "";
  }
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit"
  }).format(new Date(parsed));
}

function formatTaskSheetFileSize(value) {
  const size = Number(value || 0);
  if (!Number.isFinite(size) || size <= 0) {
    return "0 KB";
  }
  if (size >= 1024 * 1024) {
    return `${(size / (1024 * 1024)).toFixed(1)} MB`;
  }
  return `${Math.max(1, Math.round(size / 1024))} KB`;
}

function normalizeTaskAttachmentMimeType(value) {
  return String(value || "").trim().toLowerCase();
}

function getTaskAttachmentExtension(name) {
  const normalized = String(name || "").trim().toLowerCase();
  const index = normalized.lastIndexOf(".");
  if (index < 0 || index === normalized.length - 1) {
    return "";
  }
  return normalized.slice(index + 1);
}

function getTaskAttachmentPreviewKind(file) {
  const mimeType = normalizeTaskAttachmentMimeType(file?.type);
  const extension = getTaskAttachmentExtension(file?.name);
  if (mimeType.startsWith("image/") || ["png", "jpg", "jpeg", "webp"].includes(extension)) {
    return "image";
  }
  if (mimeType === "application/pdf" || extension === "pdf") {
    return "pdf";
  }
  if (mimeType.startsWith("text/") || ["txt", "md", "json", "csv", "log"].includes(extension)) {
    return "text";
  }
  return "none";
}

function canPreviewTaskAttachment(file) {
  return getTaskAttachmentPreviewKind(file) !== "none";
}

function getTaskAttachmentIconClass(file) {
  const previewKind = getTaskAttachmentPreviewKind(file);
  if (previewKind === "image") {
    return "bi-file-earmark-image";
  }
  if (previewKind === "pdf") {
    return "bi-file-earmark-pdf";
  }
  if (previewKind === "text") {
    return "bi-file-earmark-text";
  }
  const extension = getTaskAttachmentExtension(file?.name);
  if (["doc", "docx"].includes(extension)) {
    return "bi-file-earmark-word";
  }
  if (["xls", "xlsx", "csv"].includes(extension)) {
    return "bi-file-earmark-spreadsheet";
  }
  return "bi-file-earmark";
}

function syncTaskAttachmentThumbnailCache() {
  const validAttachmentIds = new Set();
  for (const task of Array.isArray(state.data.tasks) ? state.data.tasks : []) {
    for (const attachment of Array.isArray(task.attachments) ? task.attachments : []) {
      const attachmentId = String(attachment?.id || "").trim();
      if (attachmentId) {
        validAttachmentIds.add(attachmentId);
      }
    }
  }
  for (const attachmentId of [...taskAttachmentThumbnailCache.keys()]) {
    if (!validAttachmentIds.has(attachmentId)) {
      taskAttachmentThumbnailCache.delete(attachmentId);
    }
  }
  for (const attachmentId of [...pendingTaskAttachmentThumbnailIds]) {
    if (!validAttachmentIds.has(attachmentId)) {
      pendingTaskAttachmentThumbnailIds.delete(attachmentId);
    }
  }
}

function getTaskAttachmentThumbnailUrl(attachmentId = "") {
  const normalizedId = String(attachmentId || "").trim();
  if (!normalizedId) {
    return "";
  }
  const cached = taskAttachmentThumbnailCache.get(normalizedId);
  if (!cached || typeof cached !== "object") {
    return "";
  }
  if (!Number.isFinite(Number(cached.expiresAt)) || Number(cached.expiresAt) <= Date.now()) {
    taskAttachmentThumbnailCache.delete(normalizedId);
    return "";
  }
  return String(cached.url || "").trim();
}

function buildTaskAttachmentThumbnailMarkup(file) {
  const thumbnailUrl = getTaskAttachmentThumbnailUrl(file?.id);
  if (thumbnailUrl && getTaskAttachmentPreviewKind(file) === "image") {
    return `<img src="${escapeModalText(thumbnailUrl)}" alt="" class="task-sheet-file-thumb" loading="lazy" />`;
  }
  return `<i class="bi ${getTaskAttachmentIconClass(file)}" aria-hidden="true"></i>`;
}

function patchTaskAttachmentThumbnailNodes(file) {
  const attachmentId = String(file?.id || "").trim();
  if (!attachmentId) {
    return;
  }
  const nodes = [...document.querySelectorAll(".task-sheet-file-icon[data-attachment-thumb-id]")].filter(
    (node) => String(node?.dataset?.attachmentThumbId || "").trim() === attachmentId
  );
  if (!nodes.length) {
    return;
  }
  const hasThumbnail = Boolean(getTaskAttachmentThumbnailUrl(attachmentId));
  const nextMarkup = buildTaskAttachmentThumbnailMarkup(file);
  nodes.forEach((node) => {
    node.classList.toggle("has-thumb", hasThumbnail);
    node.innerHTML = nextMarkup;
  });
}

async function ensureTaskAttachmentThumbnail(file) {
  const attachmentId = String(file?.id || "").trim();
  const storagePath = String(file?.storagePath || "").trim();
  if (!attachmentId || !storagePath || getTaskAttachmentPreviewKind(file) !== "image") {
    return;
  }
  if (getTaskAttachmentThumbnailUrl(attachmentId) || pendingTaskAttachmentThumbnailIds.has(attachmentId)) {
    return;
  }

  pendingTaskAttachmentThumbnailIds.add(attachmentId);
  try {
    const expiresInSeconds = 600;
    const url = await createSupabaseTaskAttachmentSignedUrl(storagePath, expiresInSeconds);
    if (!url) {
      return;
    }
    taskAttachmentThumbnailCache.set(attachmentId, {
      url,
      expiresAt: Date.now() + expiresInSeconds * 1000
    });
    patchTaskAttachmentThumbnailNodes(file);
  } catch (error) {
    // Leave the generic file icon in place if the thumbnail cannot be generated.
  } finally {
    pendingTaskAttachmentThumbnailIds.delete(attachmentId);
  }
}

function warmTaskAttachmentThumbnails(attachments = []) {
  attachments.forEach((file) => {
    void ensureTaskAttachmentThumbnail(file);
  });
}

function findTaskAttachmentRecord(attachmentId = "") {
  const normalizedId = String(attachmentId || "").trim();
  if (!normalizedId) {
    return { task: null, attachment: null };
  }
  for (const task of Array.isArray(state.data.tasks) ? state.data.tasks : []) {
    const attachment = (Array.isArray(task.attachments) ? task.attachments : []).find((entry) => entry.id === normalizedId);
    if (attachment) {
      return { task, attachment };
    }
  }
  return { task: null, attachment: null };
}

function resetTaskAttachmentPreviewState() {
  taskAttachmentPreviewSequence += 1;
  state.attachmentPreview = createEmptyTaskAttachmentPreview();
}

function reminderLabel(minutes) {
  const amount = Number(minutes || 0);
  if (!amount) {
    return "No reminder";
  }
  if (amount < 60) {
    return `${amount} min before`;
  }
  if (amount % 60 === 0) {
    const hours = amount / 60;
    return `${hours} hr${hours === 1 ? "" : "s"} before`;
  }
  return `${amount} min before`;
}

function recurrenceLabel(value) {
  const normalized = String(value || "none").toLowerCase();
  if (normalized === "daily") {
    return "Daily";
  }
  if (normalized === "weekly") {
    return "Weekly";
  }
  if (normalized === "monthly") {
    return "Monthly";
  }
  return "No recurrence";
}

function ensureMetricsObject() {
  if (!state.data.metrics || typeof state.data.metrics !== "object") {
    state.data.metrics = {};
  }
}

function refreshDerivedMetrics() {
  syncWorkCollections(state.data);
  ensureMetricsObject();
  ensureProfileCollections(state.data);
  ensureAttendanceCollections(state.data);
  ensureMessagingCollections(state.data);
  ensureCallsCollections(state.data);
  const activeDeals = state.data.deals.filter((deal) => deal.stage !== "Won" && deal.stage !== "Lost");
  state.data.metrics.openDeals = activeDeals.length;
  state.data.metrics.pipelineValue = activeDeals.reduce((sum, deal) => {
    const numericValue = getDealValueNumber(deal.value);
    return numericValue === null ? sum : sum + numericValue;
  }, 0);
  state.data.metrics.tasksDueThisWeek = state.data.tasks.length;
  state.data.metrics.meetingsBooked = state.data.tasks.filter((task) =>
    /meeting|call|kickoff/i.test(task.title)
  ).length;
}

function persistDataAndRefresh() {
  clearDashboardCommandModelCache();
  refreshDerivedMetrics();
  syncSelectedTaskIds();
  saveData(state.data);
  renderRoute();
  if (state.activeTaskDetailId) {
    const activeTask = (state.data.tasks || []).find((task) => task.id === state.activeTaskDetailId);
    if (activeTask) {
      renderTaskDetailSheet();
    } else {
      closeTaskDetailSheet();
    }
  }
}

function syncSelectedTaskIds() {
  const validIds = new Set((state.data.tasks || []).map((task) => task.id));
  state.selectedTaskIds = new Set([...state.selectedTaskIds].filter((id) => validIds.has(id)));
}

function getVisibleLeadRowsForSelection() {
  const pageRows = Array.isArray(state.leadsPageData?.rows) ? state.leadsPageData.rows : [];
  if (pageRows.length) {
    return pageRows;
  }
  return Array.isArray(state.data.leads) ? state.data.leads : [];
}

function syncSelectedLeadIds() {
  const validIds = new Set(
    getVisibleLeadRowsForSelection()
      .map((lead) => String(lead?.id || "").trim())
      .filter(Boolean)
  );
  state.selectedLeadIds = new Set([...state.selectedLeadIds].filter((id) => validIds.has(id)));
}

function clearLeadSelection() {
  state.selectedLeadIds.clear();
}

function getSelectedLeads() {
  if (!state.selectedLeadIds.size) {
    return [];
  }
  const selectedIds = state.selectedLeadIds;
  const seen = new Set();
  return [...getVisibleLeadRowsForSelection(), ...(state.data.leads || [])].filter((lead) => {
    const leadId = String(lead?.id || "").trim();
    if (!leadId || seen.has(leadId) || !selectedIds.has(leadId)) {
      return false;
    }
    seen.add(leadId);
    return true;
  });
}

function syncLeadSelectionUi() {
  const headerCheckbox = document.getElementById("leadSelectAll");
  if (headerCheckbox instanceof HTMLInputElement) {
    headerCheckbox.indeterminate = headerCheckbox.dataset.indeterminate === "true";
  }
}

function clearTaskSelection() {
  state.selectedTaskIds.clear();
}

function getSelectedTasks() {
  if (!state.selectedTaskIds.size) {
    return [];
  }
  const selectedIds = state.selectedTaskIds;
  return state.data.tasks.filter((task) => selectedIds.has(task.id));
}

function shiftTaskDueDate(task, dayOffset) {
  if (!task) {
    return;
  }
  const previousDueDate = String(task.dueDate || "").trim();
  task.dueDate = addDaysToIso(task.dueDate, dayOffset);
  task.deadlineAt = composeDeadlineAt(task.dueDate, task.startTime || "09:00");
  task.day = getWeekdayLabelFromIso(task.dueDate) || task.day;
  if (String(task.dueDate || "").trim() !== previousDueDate) {
    recordTaskActivity(task, `Due date moved to ${formatLeadDate(task.dueDate)}`, "schedule");
  }
}

function getNextRecurringDueDate(currentDueDate, recurrence) {
  const normalized = String(recurrence || "none").toLowerCase();
  if (normalized === "daily") {
    return addDaysToIso(currentDueDate, 1);
  }
  if (normalized === "weekly") {
    return addDaysToIso(currentDueDate, 7);
  }
  if (normalized === "monthly") {
    const parsed = parseIsoDateLocal(currentDueDate);
    const source = parsed || new Date();
    source.setMonth(source.getMonth() + 1);
    return toIsoDate(source);
  }
  return "";
}

function spawnRecurringTask(task) {
  const recurrence = String(task?.recurrence || "none").toLowerCase();
  if (!task || recurrence === "none") {
    return;
  }

  const nextDueDate = getNextRecurringDueDate(task.dueDate, recurrence);
  if (!nextDueDate) {
    return;
  }

  const nextTask = {
    ...task,
    id: createId("task"),
    status: "New",
    dueDate: nextDueDate,
    deadlineAt: composeDeadlineAt(nextDueDate, task.startTime || "09:00"),
    day: getWeekdayLabelFromIso(nextDueDate),
    time: task.startTime || "09:00",
    completedAt: "",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    comments: [],
    attachments: [],
    checklist: [],
    activity: []
  };
  ensureTaskDetailCollections(nextTask);
  recordTaskActivity(nextTask, `Recurring task created from ${task.title}`, "created");

  state.data.tasks.unshift(nextTask);
}

function setTaskStatus(task, nextStatus) {
  if (!task || !nextStatus || task.status === nextStatus) {
    return false;
  }
  if (state.supabaseConfigured) {
    return false;
  }

  const previousStatus = task.status;
  task.status = nextStatus;
  task.updatedAt = new Date().toISOString();

  if (nextStatus === "Completed") {
    task.completedAt = new Date().toISOString();
    if (previousStatus !== "Completed") {
      spawnRecurringTask(task);
    }
  } else {
    task.completedAt = "";
  }
  recordTaskActivity(task, `Status changed from ${previousStatus} to ${nextStatus}`, "status");

  return true;
}

function clearDropTargets() {
  document.querySelectorAll(".drop-target-active").forEach((element) => {
    element.classList.remove("drop-target-active");
  });
}

function resetDragState() {
  if (dragState.sourceEl) {
    dragState.sourceEl.classList.remove("is-dragging");
  }
  clearDropTargets();
  dragState.type = "";
  dragState.id = "";
  dragState.sourceEl = null;
  dragState.touchMoved = false;
  dragState.startX = 0;
  dragState.startY = 0;
}

function getTaskQuickContextAction(task) {
  if (!canTaskUpdateProgress(task)) {
    return null;
  }
  const status = String(task?.status || "").trim();
  if (status === "Completed") {
    return { label: "Reopen", action: "task-reopen" };
  }
  if (status === "In progress") {
    return { label: "Mark Done", action: "task-mark-done" };
  }
  return { label: "Start", action: "task-start" };
}

function getContextMenuItems(cardType, recordId) {
  if (cardType === "calls-row") {
    const row = getCallsContextRow(recordId);
    if (!row) {
      return [];
    }
    const items = [
      { label: "Open details", action: "calls-open-item", id: recordId, icon: "bi-layout-text-window-reverse" }
    ];
    if (row.phone) {
      items.push(
        { label: "Call back", action: "calls-context-call", id: recordId, icon: "bi-telephone-outbound" },
        { label: "Send to dialer", action: "calls-context-dialer", id: recordId, icon: "bi-grid-3x3-gap" },
        { label: "Copy number", action: "calls-context-copy-number", id: recordId, icon: "bi-clipboard" }
      );
    }
    if (row.contact?.id) {
      items.push(
        { divider: true },
        { label: "Open contact", action: "calls-context-open-contact", id: recordId, icon: "bi-person-lines-fill" }
      );
    }
    if (row.itemType === "call" && row.callLog?.id) {
      items.push(
        { divider: true },
        { label: "Delete call log", action: "calls-context-delete-log", id: recordId, icon: "bi-trash", danger: true }
      );
    }
    return items;
  }

  if (cardType === "crm-page-size") {
    const routeKey = String(recordId || state.routeId || "").trim();
    if (!["leads", "contacts", "accounts", "deals"].includes(routeKey)) {
      return [];
    }
    const currentSize = getCrmPageSizeState(routeKey);
    return getCrmPageSizeOptions(routeKey).map((size) => ({
      label: `${size}`,
      action: "crm-table-page-size",
      id: String(size),
      active: currentSize === size
    }));
  }

  if (cardType === "calls-performance-page-size") {
    const currentSize = normalizeCallsPerformanceTablePageSize(state.callsPerformanceTablePageSize);
    return [10, 20, 50].map((size) => ({
      label: `${size}`,
      action: "calls-performance-table-page-size",
      id: String(size),
      active: currentSize === size
    }));
  }

  if (cardType === "attendance-page-size") {
    const currentSize = normalizeAttendanceTablePageSize(state.attendanceTablePageSize);
    return [10, 20, 50].map((size) => ({
      label: `${size}`,
      action: "attendance-table-page-size",
      id: String(size),
      active: currentSize === size
    }));
  }

  if (cardType === "task") {
    const task = state.data.tasks.find((item) => item.id === recordId);
    if (!task) {
      return [];
    }
    const quick = getTaskQuickContextAction(task);
    const items = [{ label: "Open Task", action: "task-open", id: task.id }];
    const actionItems = [];
    if (canTaskEditCore(task)) {
      actionItems.push({ label: "Edit Task", action: "task-edit", id: task.id });
    }
    if (quick) {
      actionItems.push({ label: quick.label, action: quick.action, id: task.id });
      actionItems.push({ label: "Next Status", action: "task-next-status", id: task.id });
    }
    if (canTaskDelete(task)) {
      if (actionItems.length) {
        actionItems.push({ divider: true });
      }
      actionItems.push({ label: "Delete Task", action: "task-delete", id: task.id, danger: true });
    }
    if (actionItems.length) {
      items.push({ divider: true }, ...actionItems);
    }
    return items;
  }

  if (cardType === "lead") {
    const lead = getLeadById(recordId);
    if (!lead) {
      return [];
    }
    const canConvert = String(lead.status || "").trim() === "Qualified";
    return [
      ...(canConvert ? [{ label: "Convert to Deal", action: "lead-convert", id: lead.id, icon: "bi-arrow-up-right-circle", active: true }] : []),
      { label: "Open Lead", action: "lead-open", id: lead.id, icon: "bi-box-arrow-up-right" },
      { label: "Open in New Tab", action: "lead-open-new-tab", id: lead.id, icon: "bi-copy" },
      { label: "Edit", action: "lead-edit", id: lead.id, icon: "bi-pencil-square" },
      { divider: true },
      { label: "Log Call", action: "lead-log-call", id: lead.id, icon: "bi-telephone" },
      { label: "Schedule Call", action: "lead-schedule-call", id: lead.id, icon: "bi-calendar-plus" },
      { label: "Create Callback", action: "lead-create-callback", id: lead.id, icon: "bi-telephone-inbound" },
      { label: "Send Email", action: "lead-send-email", id: lead.id, icon: "bi-envelope" },
      { label: "Archive", action: "lead-archive", id: lead.id, icon: "bi-archive" },
      { divider: true },
      { label: "More actions", action: "lead-more-actions", id: lead.id, icon: "bi-sliders" }
    ];
  }

  if (cardType === "deal") {
    const deal = state.data.deals.find((item) => item.id === recordId);
    if (!deal) {
      return [];
    }
    const normalizedStage = normalizeDealStage(deal.stage);
    const nextStageLabel =
      normalizedStage === "Prospecting"
        ? "Move to Qualified"
        : normalizedStage === "Qualified"
          ? "Move to Proposal"
          : normalizedStage === "Proposal"
            ? "Move to Negotiation"
            : normalizedStage === "Negotiation"
              ? "Move to Closed Won"
              : "Move Forward";
    const progressItem =
      normalizedStage === "Lost"
        ? {
            label: "Reopen Deal",
            action: "deal-reopen",
            id: deal.id,
            icon: "bi-arrow-counterclockwise"
          }
        : normalizedStage === "Won"
          ? null
          : {
              label: nextStageLabel,
              action: "deal-next-stage",
              id: deal.id,
              icon: "bi-arrow-right-circle"
            };
    return [
      { label: "Open Deal", action: "deal-open", id: deal.id, icon: "bi-box-arrow-up-right" },
      { label: "Edit Deal", action: "deal-edit", id: deal.id, icon: "bi-pencil-square" },
      ...(!dealHasValue(deal.value)
        ? [{ label: "Set Value", action: "deal-set-value", id: deal.id, icon: "bi-currency-dollar" }]
        : []),
      { divider: true },
      { label: "Schedule Call", action: "deal-schedule-call", id: deal.id, icon: "bi-calendar-plus" },
      { label: "Create Callback", action: "deal-create-callback", id: deal.id, icon: "bi-telephone-inbound" },
      ...(progressItem ? [{ divider: true }, progressItem] : []),
      { divider: true },
      { label: "More actions", action: "deal-more-actions", id: deal.id, icon: "bi-sliders" }
    ];
  }

  if (cardType === "contact") {
    const contact = getContactById(recordId);
    if (!contact) {
      return [];
    }
    return [
      { label: "Open Contact", action: "contact-open", id: contact.id, icon: "bi-box-arrow-up-right" },
      { label: "Edit", action: "contact-edit", id: contact.id, icon: "bi-pencil-square" },
      { divider: true },
      { label: "Log Call", action: "contact-log-call", id: contact.id, icon: "bi-telephone" },
      { label: "Schedule Call", action: "contact-schedule-call", id: contact.id, icon: "bi-calendar-plus" },
      { label: "Create Callback", action: "contact-create-callback", id: contact.id, icon: "bi-telephone-inbound" },
      { label: "Send Email", action: "contact-send-email", id: contact.id, icon: "bi-envelope" },
      { label: "Send SMS", action: "contact-send-sms", id: contact.id, icon: "bi-chat-dots" },
      { divider: true },
      { label: "More actions", action: "contact-more-actions", id: contact.id, icon: "bi-sliders" }
    ];
  }

  if (cardType === "account") {
    const account = getAccountById(recordId);
    if (!account) {
      return [];
    }
    return [
      { label: "Open Account", action: "account-open", id: account.id, icon: "bi-box-arrow-up-right" },
      { label: "Edit", action: "account-edit", id: account.id, icon: "bi-pencil-square" },
      { divider: true },
      { label: "Log Call", action: "account-log-call", id: account.id, icon: "bi-telephone" },
      { label: "Schedule Call", action: "account-schedule-call", id: account.id, icon: "bi-calendar-plus" },
      { label: "Create Callback", action: "account-create-callback", id: account.id, icon: "bi-telephone-inbound" },
      { label: "Send Email", action: "account-send-email", id: account.id, icon: "bi-envelope" },
      { divider: true },
      { label: "More actions", action: "account-more-actions", id: account.id, icon: "bi-sliders" }
    ];
  }

  if (cardType === "project") {
    const project = state.data.projects.find((item) => item.id === recordId);
    if (!project) {
      return [];
    }
    return [
      { label: "Edit Project", action: "project-edit", id: project.id },
      { divider: true },
      { label: "Add 10% Progress", action: "project-progress", id: project.id },
      { divider: true },
      { label: "Delete Project", action: "project-delete", id: project.id, danger: true }
    ];
  }

  return [];
}

function closeContextMenu() {
  const menu = document.getElementById("contextMenu");
  if (!menu) {
    return;
  }
  menu.hidden = true;
  menu.innerHTML = "";
  contextMenuState.open = false;
  contextMenuState.cardType = "";
  contextMenuState.recordId = "";
}

function openContextMenu(cardType, recordId, pointerX, pointerY) {
  const menu = document.getElementById("contextMenu");
  if (!menu) {
    return;
  }

  const items = getContextMenuItems(cardType, recordId);
  if (!items.length) {
    closeContextMenu();
    return;
  }

  menu.innerHTML = items
    .map((item) => {
      if (item.divider) {
        return "<div class='context-menu-divider' role='separator'></div>";
      }
      const icon = item.icon ? `<i class="bi ${item.icon} context-menu-item-icon" aria-hidden="true"></i>` : "";
      return `
        <button
          class="context-menu-item ${item.danger ? "is-danger" : ""} ${item.active ? "is-active" : ""}"
          type="button"
          data-action="${item.action}"
          data-id="${item.id}"
        >
          <span class="context-menu-item-content">${icon}<span>${item.label}</span></span>
        </button>
      `;
    })
    .join("");

  menu.hidden = false;
  menu.style.left = "0px";
  menu.style.top = "0px";

  const pad = 8;
  const maxLeft = Math.max(pad, window.innerWidth - menu.offsetWidth - pad);
  const maxTop = Math.max(pad, window.innerHeight - menu.offsetHeight - pad);
  const left = Math.min(Math.max(pointerX, pad), maxLeft);
  const top = Math.min(Math.max(pointerY, pad), maxTop);

  menu.style.left = `${left}px`;
  menu.style.top = `${top}px`;

  contextMenuState.open = true;
  contextMenuState.cardType = cardType;
  contextMenuState.recordId = recordId;
}

function resetTableActionsDropdownPosition(menuEl) {
  const dropdown = menuEl?.querySelector(".table-actions-dropdown");
  if (!dropdown) {
    return;
  }
  dropdown.style.position = "";
  dropdown.style.top = "";
  dropdown.style.left = "";
  dropdown.style.right = "";
  dropdown.style.maxHeight = "";
  dropdown.style.overflowY = "";
  dropdown.style.zIndex = "";
}

function positionTableActionsDropdown(menuEl) {
  if (!menuEl || !menuEl.open) {
    resetTableActionsDropdownPosition(menuEl);
    return;
  }
  const dropdown = menuEl.querySelector(".table-actions-dropdown");
  const toggle = menuEl.querySelector(".table-menu-toggle");
  if (!dropdown || !toggle) {
    return;
  }

  dropdown.style.position = "fixed";
  dropdown.style.top = "0px";
  dropdown.style.left = "0px";
  dropdown.style.right = "auto";
  dropdown.style.maxHeight = "";
  dropdown.style.overflowY = "";
  dropdown.style.zIndex = "1200";

  const rect = toggle.getBoundingClientRect();
  const margin = 8;
  const gap = 4;
  const width = Math.max(dropdown.offsetWidth, 140);
  const fullHeight = dropdown.offsetHeight;
  const viewportHeight = window.innerHeight;
  const viewportWidth = window.innerWidth;

  let left = rect.right - width;
  if (left < margin) {
    left = margin;
  }
  if (left + width > viewportWidth - margin) {
    left = Math.max(margin, viewportWidth - width - margin);
  }

  let menuHeight = fullHeight;
  const maxHeight = Math.max(140, viewportHeight - margin * 2);
  if (menuHeight > maxHeight) {
    menuHeight = maxHeight;
    dropdown.style.maxHeight = `${maxHeight}px`;
    dropdown.style.overflowY = "auto";
  }

  let top = rect.bottom + gap;
  if (top + menuHeight > viewportHeight - margin) {
    top = rect.top - menuHeight - gap;
  }
  if (top < margin) {
    top = margin;
  }

  dropdown.style.left = `${Math.round(left)}px`;
  dropdown.style.top = `${Math.round(top)}px`;
}

function parseCallsContextRowId(recordId) {
  const [itemType = "", ...rest] = String(recordId || "").split(":");
  return {
    itemType: String(itemType || "").trim().toLowerCase(),
    itemId: rest.join(":").trim()
  };
}

function getCallsContextRow(recordId) {
  const { itemType, itemId } = parseCallsContextRowId(recordId);
  if (!itemType || !itemId) {
    return null;
  }

  if (itemType === "contact") {
    const contact = getContactById(itemId);
    if (!contact) {
      return null;
    }
    return {
      itemType,
      itemId,
      id: String(contact.id || "").trim(),
      phone: normalizePhoneValue(contact.phone || ""),
      name: String(contact.name || "Unknown contact").trim(),
      linkedType: "Contact",
      linkedId: String(contact.id || "").trim(),
      linkedLabel: String(contact.name || "").trim(),
      contact,
      note: `Contact follow-up: ${String(contact.name || "").trim() || "Contact"}${contact.account ? ` @ ${contact.account}` : ""}`
    };
  }

  if (itemType === "call") {
    const callLog = (state.data.callLogs || []).find((entry) => String(entry?.id || "").trim() === itemId) || null;
    if (!callLog) {
      return null;
    }
    const direction = String(callLog.direction || "").trim().toLowerCase();
    const phone = normalizePhoneValue(direction === "inbound" ? callLog.fromNumber : callLog.toNumber || callLog.fromNumber || "");
    const contact =
      (String(callLog.linkedEntityType || "").trim().toLowerCase() === "contact" && getContactById(String(callLog.linkedEntityId || "").trim())) ||
      findContactByPhone(phone) ||
      null;
    const name = String(callLog.counterpartyName || callLog.linkedLabel || contact?.name || phone || "Unknown caller").trim();
    return {
      itemType,
      itemId,
      id: String(callLog.id || "").trim(),
      phone,
      name,
      linkedType: String(callLog.linkedEntityType || (contact ? "Contact" : "")).trim(),
      linkedId: String(callLog.linkedEntityId || contact?.id || "").trim(),
      linkedLabel: String(callLog.linkedLabel || contact?.name || name).trim(),
      contact,
      callLog,
      note: `Call back: ${name}${contact?.account ? ` @ ${contact.account}` : ""}`
    };
  }

  if (itemType === "voicemail") {
    const voicemail = (state.data.voicemails || []).find((entry) => String(entry?.id || "").trim() === itemId) || null;
    if (!voicemail) {
      return null;
    }
    const phone = normalizePhoneValue(voicemail.fromNumber || voicemail.toNumber || "");
    const contact = findContactByPhone(phone) || null;
    const name = String(voicemail.callerName || contact?.name || phone || "Voicemail").trim();
    return {
      itemType,
      itemId,
      id: String(voicemail.id || "").trim(),
      phone,
      name,
      linkedType: contact ? "Contact" : "",
      linkedId: String(contact?.id || "").trim(),
      linkedLabel: String(contact?.name || name).trim(),
      contact,
      voicemail,
      note: `Voicemail callback: ${name}${contact?.account ? ` @ ${contact.account}` : ""}`
    };
  }

  return null;
}

function openCallsContextRow(recordId) {
  const { itemType, itemId } = parseCallsContextRowId(recordId);
  if (!itemType || !itemId) {
    return false;
  }
  state.selectedCallWorkspaceItemType = itemType;
  state.selectedCallWorkspaceItemId = itemId;
  if (state.routeId !== "comms-calls") {
    setRoute("comms-calls");
  } else {
    renderRoute();
  }
  return true;
}

function sendCallsContextRowToDialer(recordId, options = {}) {
  const row = getCallsContextRow(recordId);
  if (!row?.phone) {
    window.alert("No phone number found for this item.");
    return false;
  }
  const contactConversation = row.contact ? selectConversationForContact(row.contact, { createIfMissing: true }) : null;
  const opened = openQuickDialer({
    phone: row.phone,
    displayName: row.name,
    targetType: "direct",
    targetId: String(contactConversation?.id || "").trim(),
    linkedType: row.linkedType,
    linkedId: row.linkedId,
    linkedLabel: row.linkedLabel,
    note: row.note
  });
  if (!opened) {
    return false;
  }
  if (options.start) {
    void startCallFromDraft();
  }
  return true;
}

function closeTableActionMenus(exceptMenu = null) {
  document.querySelectorAll(".table-actions-menu[open]").forEach((menuEl) => {
    if (exceptMenu && menuEl === exceptMenu) {
      return;
    }
    menuEl.open = false;
    resetTableActionsDropdownPosition(menuEl);
  });
}

function closeConversationRowMenus(exceptMenu = null) {
  document.querySelectorAll(".conversation-row-menu[open]").forEach((menuEl) => {
    if (exceptMenu && menuEl === exceptMenu) {
      return;
    }
    menuEl.open = false;
  });
}

