function isCommunicationsRoute(routeId) {
  return routeId === "communications" || String(routeId || "").startsWith("comms-");
}

function getCommsModeForRoute(routeId) {
  if (routeId === "comms-email") {
    return "email";
  }
  if (routeId === "comms-sms") {
    return "sms";
  }
  if (routeId === "comms-calls") {
    return "call";
  }
  return "internal";
}

function getActiveNavRouteIds(currentRouteId) {
  const ids = new Set([currentRouteId]);
  if (currentRouteId === "account-profile") {
    ids.add("accounts");
  }
  if (currentRouteId === "deal-profile") {
    ids.add("deals");
  }
  if (currentRouteId === "lead-profile") {
    ids.add("leads");
  }
  if (currentRouteId === "settings-me" || currentRouteId === "settings-workspace") {
    ids.add("settings");
  }
  if (currentRouteId === "team-member-profile") {
    ids.add("team");
  }
  navSections.forEach((section) => {
    section.routes.forEach((route) => {
      if (!route.children?.length) {
        return;
      }
      if (route.children.some((child) => child.id === currentRouteId)) {
        ids.add(route.id);
      }
    });
  });
  return ids;
}

function sectionKeyFromTitle(title) {
  return String(title || "section")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function sidebarMarkup() {
  const brandLabel = normalizeSystemAppLabel(state.data.workspace?.appLabel);
  const brandLogoUrl = sanitizeHtml(resolveBrandLogoUrl(state.data.workspace?.logoUrl));
  const safeBrandLabel = sanitizeHtml(brandLabel);
  const dashboardLocked =
    state.supabaseConfigured &&
    Boolean(state.signedInUser) &&
    state.authAccessState === "granted" &&
    !canAccessDashboard();
  const sections = navSections
    .map((section) => {
      const sectionKey = sectionKeyFromTitle(section.title);
      const sectionCollapsed = Boolean(state.sidebarSectionCollapsed[sectionKey]);
      const singleParentWithChildren =
        section.routes.length === 1 && Boolean(section.routes[0]?.children?.length);
      const navItems = section.routes
        .map((route) => {
          const hasChildren = Boolean(route.children?.length);
          const showNodeToggle = hasChildren && !singleParentWithChildren;
          const nodeCollapsed = showNodeToggle ? Boolean(state.sidebarNodeCollapsed[route.id]) : false;
          const routeLocked = isCommsRouteLocked(route.id) || (dashboardLocked && route.id === "dashboard");
          const lockedLabel =
            dashboardLocked && route.id === "dashboard"
              ? `${route.label} locked for your role`
              : `${route.label} locked, admins only`;
          const routeLabelMarkup = `
            <span class="nav-item-copy">
              <span class="nav-item-label">${route.label}</span>
              ${
                routeLocked
                  ? `<span class="nav-item-badge is-locked"><i class="bi bi-lock-fill" aria-hidden="true"></i><span>Locked</span></span>`
                  : ""
              }
            </span>
          `;
          const childItems = hasChildren
            ? route.children
                .map(
                  (child) => {
                    const childLocked = isCommsRouteLocked(child.id);
                    return `
                    <button
                      class="nav-item nav-item-sub ${childLocked ? "is-locked" : ""}"
                      data-route="${child.id}"
                      data-tooltip="${childLocked ? `${child.label} locked` : child.label}"
                      aria-label="${childLocked ? `${child.label} locked, admins only` : child.label}"
                    >
                      <span class="nav-item-icon"><i class="${child.icon}" aria-hidden="true"></i></span>
                      <span class="nav-item-copy">
                        <span class="nav-item-label">${child.label}</span>
                        ${
                          childLocked
                            ? `<span class="nav-item-badge is-locked"><i class="bi bi-lock-fill" aria-hidden="true"></i><span>Locked</span></span>`
                            : ""
                        }
                      </span>
                    </button>
                  `;
                  }
                )
                .join("")
            : "";

          return `
            <div class="nav-node ${hasChildren ? "has-children" : ""} ${nodeCollapsed ? "is-collapsed" : ""}">
              <div class="nav-node-head">
                <button
                  class="nav-item nav-item-parent ${routeLocked ? "is-locked" : ""}"
                  data-route="${route.id}"
                  data-tooltip="${routeLocked ? `${route.label} locked` : route.label}"
                  aria-label="${routeLocked ? lockedLabel : route.label}"
                >
                  <span class="nav-item-icon"><i class="${route.icon}" aria-hidden="true"></i></span>
                  ${routeLabelMarkup}
                </button>
                ${
                  showNodeToggle
                    ? `
                      <button
                        class="nav-node-toggle"
                        type="button"
                        data-action="sidebar-node-toggle"
                        data-id="${route.id}"
                        aria-label="${nodeCollapsed ? "Expand menu" : "Collapse menu"}"
                      >
                        <i class="bi ${nodeCollapsed ? "bi-chevron-right" : "bi-chevron-down"}" aria-hidden="true"></i>
                      </button>
                    `
                    : ""
                }
              </div>
              ${
                hasChildren
                  ? `<div class="nav-subgroup ${showNodeToggle && nodeCollapsed ? "is-collapsed" : ""}">${childItems}</div>`
                  : ""
              }
            </div>
          `;
        })
        .join("");

      return `
        <section class="sidebar-section ${sectionCollapsed ? "is-collapsed" : ""}">
          <button
            class="sidebar-section-toggle"
            type="button"
            data-action="sidebar-section-toggle"
            data-id="${sectionKey}"
            aria-label="${sectionCollapsed ? "Expand section" : "Collapse section"}"
          >
            <span class="sidebar-section-title">${section.title}</span>
            <i class="bi ${sectionCollapsed ? "bi-chevron-right" : "bi-chevron-down"}" aria-hidden="true"></i>
          </button>
          <div class="sidebar-section-body ${sectionCollapsed ? "is-collapsed" : ""}">
            <div class="nav-group">${navItems}</div>
          </div>
        </section>
      `;
    })
    .join("");

  return `
    <aside class="sidebar">
      <header class="brand brand-head">
        <div class="brand-left">
          <div class="brand-mark">
            <img src="${brandLogoUrl}" alt="${safeBrandLabel}" />
          </div>
          <div class="brand-meta">
            <h2 class="brand-title">${safeBrandLabel}</h2>
          </div>
        </div>
        <button
          class="panel-toggle-btn panel-toggle-btn-sidebar"
          id="sidebarPanelToggle"
          type="button"
          aria-label="Collapse sidebar"
        >
          <svg class="sidebar-toggle-icon" id="sidebarPanelToggleIcon" aria-hidden="true" viewBox="0 0 16 16" focusable="false">
            <rect x="1.25" y="2" width="13.5" height="12" rx="2.4" fill="none" stroke="currentColor" stroke-width="1.4"></rect>
            <rect x="2.6" y="3.35" width="2.5" height="9.3" rx="1" fill="currentColor" opacity="0.16"></rect>
            <line x1="6.25" y1="3.35" x2="6.25" y2="12.65" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"></line>
          </svg>
        </button>
      </header>
      ${sections}
    </aside>
  `;
}

