function isStandaloneInviteRoute(routeId = state.routeId) {
  return isStandalonePublicRoute(routeId);
}

function getWaitingItemDueInfo(item) {
  const explicitDue = String(item?.dueDate || item?.nextFollowUp || "").trim();
  const linkedTypeRaw = String(item?.linkedType || "").trim();
  const linkedDateMatch = linkedTypeRaw.match(/\b(\d{4}-\d{2}-\d{2})\b/);
  const dueDate = explicitDue || linkedDateMatch?.[1] || "";
  if (!parseIsoDateLocal(dueDate)) {
    return { dueDate: "", status: "none", label: "" };
  }
  const today = todayIso(0);
  if (dueDate < today) {
    return { dueDate, status: "overdue", label: "Overdue" };
  }
  if (dueDate === today) {
    return { dueDate, status: "today", label: "Today" };
  }
  if (dueDate === todayIso(1)) {
    return { dueDate, status: "tomorrow", label: "Tomorrow" };
  }
  return { dueDate, status: "upcoming", label: formatLeadDate(dueDate) };
}

function getWaitingFilterCounts(items) {
  const counts = { all: items.length, overdue: 0, today: 0, tomorrow: 0 };
  items.forEach((item) => {
    const status = String(item?.due?.status || "");
    if (status === "overdue") {
      counts.overdue += 1;
    } else if (status === "today") {
      counts.today += 1;
    } else if (status === "tomorrow") {
      counts.tomorrow += 1;
    }
  });
  return counts;
}

function waitingFilterMarkup(items, activeFilter = "all") {
  const counts = getWaitingFilterCounts(items);
  if (!counts.overdue && !counts.today && !counts.tomorrow) {
    return "";
  }
  const filterOrder = [
    { id: "all", label: "All", count: counts.all },
    { id: "overdue", label: "Overdue", count: counts.overdue },
    { id: "today", label: "Today", count: counts.today },
    { id: "tomorrow", label: "Tomorrow", count: counts.tomorrow }
  ];
  return filterOrder
    .filter((entry) => entry.id === "all" || entry.count > 0)
    .map(
      (entry) => `
        <button
          type="button"
          class="waiting-filter-chip ${activeFilter === entry.id ? "is-active" : ""}"
          data-action="waiting-filter"
          data-id="${entry.id}"
        >
          <span>${entry.label}</span>
          <small>${entry.count}</small>
        </button>
      `
    )
    .join("");
}

function waitingListMarkup(items, activeFilter = "all") {
  if (!items || items.length === 0) {
    return "<p class='task-meta'>No pending items.</p>";
  }

  const filteredItems =
    activeFilter === "all"
      ? items
      : items.filter((item) => String(item?.due?.status || "") === activeFilter);

  if (!filteredItems.length) {
    return "<p class='task-meta'>No items in this filter.</p>";
  }

  return filteredItems
    .map((item) => {
      const linkedTypeRaw = String(item.linkedType || "").trim();
      const linkedTypeClean = item.due.dueDate
        ? linkedTypeRaw.replace(/\b[Dd]ue\s*\d{4}-\d{2}-\d{2}\b/g, "").replace(/\s+\|\s+/g, " | ").trim()
        : linkedTypeRaw;
      const metaLine = [item.owner, linkedTypeClean].filter(Boolean).join(" | ");
      return `
        <article class="waiting-item">
          <div class="waiting-item-main">
            <strong>${escapeModalText(item.title || "Untitled")}</strong>
            ${metaLine ? `<p>${escapeModalText(metaLine)}</p>` : ""}
          </div>
          ${
            item.due.status !== "none"
              ? `<span class="waiting-due-pill is-${item.due.status}">${escapeModalText(item.due.label)}</span>`
              : ""
          }
        </article>
      `;
    })
    .join("");
}

function getTopbarNotifications() {
  const today = todayIso(0);
  const workspaceNames = new Set(
    [state.data.currentUser?.name, ...(state.data.teamMembers || []).map((member) => member?.name)]
      .map((value) => normalizeForMatch(value))
      .filter(Boolean)
  );
  const workspaceDirectUnread = (state.data.directThreads || []).reduce((sum, thread) => {
    const members = Array.isArray(thread?.members) ? thread.members : [];
    const normalizedMembers = members.map((value) => normalizeForMatch(value)).filter(Boolean);
    const isWorkspaceThread = normalizedMembers.length
      ? normalizedMembers.every((memberName) => workspaceNames.has(memberName))
      : workspaceNames.has(normalizeForMatch(thread?.name));
    return isWorkspaceThread ? sum + Number(thread.unread || 0) : sum;
  }, 0);
  const unreadMessages =
    (state.data.channels || []).reduce((sum, channel) => sum + Number(channel.unread || 0), 0) +
    workspaceDirectUnread;
  const overdueTasks = (state.data.tasks || []).filter((task) => {
    if (String(task.status || "") === "Completed") {
      return false;
    }
    const dueDate = String(task.dueDate || "").trim();
    return dueDate && dueDate < today;
  }).length;
  const dueTodayTasks = (state.data.tasks || []).filter((task) => {
    if (String(task.status || "") === "Completed") {
      return false;
    }
    return String(task.dueDate || "").trim() === today;
  }).length;
  const followUpsToday = (state.data.leads || []).filter((lead) => String(lead.nextFollowUp || "").trim() === today).length;

  const items = [];
  if (unreadMessages > 0) {
    items.push({
      title: `${unreadMessages} unread message${unreadMessages === 1 ? "" : "s"}`,
      meta: "Communications",
      section: "today",
      badge: "Unread",
      tone: "info",
      route: "comms-messenger",
      count: unreadMessages
    });
  }
  if (overdueTasks > 0) {
    items.push({
      title: `${overdueTasks} overdue task${overdueTasks === 1 ? "" : "s"}`,
      meta: "Work",
      section: "overdue",
      badge: "Overdue",
      tone: "danger",
      route: "my-work",
      count: overdueTasks
    });
  }
  if (dueTodayTasks > 0) {
    items.push({
      title: `${dueTodayTasks} task${dueTodayTasks === 1 ? "" : "s"} due today`,
      meta: "Work",
      section: "today",
      badge: "Today",
      tone: "warning",
      route: "my-work",
      count: dueTodayTasks
    });
  }
  if (followUpsToday > 0) {
    items.push({
      title: `${followUpsToday} lead follow-up${followUpsToday === 1 ? "" : "s"} today`,
      meta: "CRM",
      section: "leads",
      badge: "Today",
      tone: "crm",
      route: "leads",
      count: followUpsToday
    });
  }

  return items;
}

function attendanceStatusTone(status) {
  const normalized = String(status || "").trim().toLowerCase();
  if (normalized === "working") {
    return "working";
  }
  if (normalized === "on-break") {
    return "on-break";
  }
  return "off";
}

function attendanceOverBreakEntries(record, policy, referenceNowIso = "") {
  const usage = getAttendanceBreakUsage(record, policy, referenceNowIso || getLiveNowIso());
  return getAttendancePolicyBreakTypes(policy)
    .map((entry) => {
      const usageEntry = usage.get(entry.id) || { minutes: 0, count: 0 };
      const allowedMinutes = Math.max(0, Number(entry.durationMinutes || 0));
      const overMinutes = Math.max(0, Number(usageEntry.minutes || 0) - allowedMinutes);
      return overMinutes > 0
        ? {
            ...entry,
            usedMinutes: Number(usageEntry.minutes || 0),
            allowedMinutes,
            overMinutes
          }
        : null;
    })
    .filter(Boolean);
}

function renderAttendanceQuickPanelLegacy(snapshot, referenceNowIso = "") {
  const nowIso = String(referenceNowIso || getLiveNowIso()).trim() || getLiveNowIso();
  const policy = snapshot?.policy && typeof snapshot.policy === "object" ? snapshot.policy : defaultAttendancePolicy();
  const timeZone = resolveAttendanceUiTimeZone(policy);
  const timeLabel = formatTopbarClockShortTime(nowIso, timeZone);
  const status = String(snapshot?.status || "off").trim().toLowerCase();
  const statusLabel = String(snapshot?.statusLabel || "Off").trim() || "Off";
  const statusTone = attendanceStatusTone(status);
  const summaryLog = snapshot?.summaryLog || null;
  const activeLog = snapshot?.activeLog || null;
  const firstInLabel = summaryLog?.clockInAt ? formatAttendanceTime(summaryLog.clockInAt, timeZone) : "--";
  const lastOutLabel = summaryLog?.clockOutAt ? formatAttendanceTime(summaryLog.clockOutAt, timeZone) : "--";
  const openBreak = getAttendanceOpenBreak(activeLog);
  const openBreakType = openBreak ? getAttendanceBreakTypeForEntry(openBreak, policy) : null;
  const breakLimitSeconds = Math.max(0, Number(openBreakType?.durationMinutes || 0) * 60);
  const breakElapsedSeconds = Math.max(0, Number(snapshot?.breakElapsedSeconds || 0));
  const breakRemainingSeconds = Math.max(0, breakLimitSeconds - breakElapsedSeconds);
  const breakOverrunSeconds = Math.max(0, breakElapsedSeconds - breakLimitSeconds);
  const overBreakEntries = attendanceOverBreakEntries(summaryLog, policy, nowIso);
  const currentOverBreak = openBreakType
    ? overBreakEntries.find((entry) => String(entry.id || "") === String(openBreakType.id || ""))
    : null;
  const shiftLabel = `${String(policy.shiftStart || "09:00")} - ${String(policy.shiftEnd || "18:00")}`;
  const quickMeta =
    status === "on-break"
      ? `${openBreakType?.label || "Break"} · ${formatAttendanceDurationClock(breakElapsedSeconds)}`
      : status === "working"
        ? `${formatAttendanceDurationClock(Number(snapshot?.workedSeconds || 0))} worked`
        : summaryLog?.clockOutAt
          ? `Out ${lastOutLabel}`
          : "Open attendance controls";
  const subCopy =
    status === "on-break"
      ? breakOverrunSeconds > 0
        ? `Over break by ${formatAttendanceDurationClock(breakOverrunSeconds)}`
        : `Break limit ${formatAttendanceDurationClock(breakLimitSeconds)} · ${formatAttendanceDurationClock(breakRemainingSeconds)} left`
      : status === "working"
        ? `First in ${firstInLabel} · Shift ${shiftLabel}`
        : `Shift ${shiftLabel} · Local ${timeLabel}`;
  const canClockIn = status === "off";
  const canStartBreak = status === "working";
  const canEndBreak = status === "on-break";
  const canClockOut = status === "working" || status === "on-break";
  const clockOutLabel = status === "on-break" ? "End Break + Clock Out" : "Clock Out";
  const alertMarkup =
    currentOverBreak || overBreakEntries.length
      ? `
        <p class="topbar-attendance-sub is-warning">
          ${escapeModalText(
            currentOverBreak
              ? `${currentOverBreak.label} over by ${formatAttendanceDuration(currentOverBreak.overMinutes)}`
              : `${overBreakEntries[0].label} over by ${formatAttendanceDuration(overBreakEntries[0].overMinutes)}`
          )}
        </p>
      `
      : "";

  return `
    <p class="topbar-attendance-title">Attendance</p>
    <div class="topbar-attendance-meta-row">
      <span class="topbar-attendance-state is-${statusTone}">${escapeModalText(statusLabel)}</span>
      <span>${escapeModalText(timeLabel)}</span>
    </div>
    <p class="topbar-attendance-sub">${escapeModalText(subCopy)}</p>
    ${alertMarkup}
    <div class="topbar-attendance-actions">
      <button class="topbar-menu-item" type="button" data-action="attendance-clock-in" ${canClockIn ? "" : "disabled"}>Clock In</button>
      <button class="topbar-menu-item" type="button" data-action="attendance-start-break" ${canStartBreak ? "" : "disabled"}>Start Break</button>
      <button class="topbar-menu-item" type="button" data-action="attendance-end-break" ${canEndBreak ? "" : "disabled"}>End Break</button>
      <button class="topbar-menu-item" type="button" data-action="attendance-clock-out" ${canClockOut ? "" : "disabled"}>${escapeModalText(
        clockOutLabel
      )}</button>
    </div>
    <button class="topbar-menu-item topbar-user-action topbar-attendance-open" type="button" data-route="attendance">
      <i class="bi bi-arrow-up-right-square" aria-hidden="true"></i>
      <span>Open Attendance</span>
    </button>
  `;
}

