function getAttendanceQuickPanelPresentation(snapshot, referenceNowIso = "") {
  const nowIso = String(referenceNowIso || getLiveNowIso()).trim() || getLiveNowIso();
  const policy = snapshot?.policy && typeof snapshot.policy === "object" ? snapshot.policy : defaultAttendancePolicy();
  const timeZone = resolveAttendanceUiTimeZone(policy);
  const timeLabel = formatTopbarClockShortTime(nowIso, timeZone);
  const status = String(snapshot?.status || "off").trim().toLowerCase();
  const summaryLog = snapshot?.summaryLog || null;
  const activeLog = snapshot?.activeLog || null;
  const firstInLabel = summaryLog?.clockInAt ? formatAttendanceTime(summaryLog.clockInAt, timeZone) : "--";
  const lastOutLabel = summaryLog?.clockOutAt ? formatAttendanceTime(summaryLog.clockOutAt, timeZone) : "--";
  const openBreak = getAttendanceOpenBreak(activeLog);
  const openBreakType = openBreak ? getAttendanceBreakTypeForEntry(openBreak, policy) : null;
  const breakLimitSeconds = Math.max(0, Number(openBreakType?.durationMinutes || 0) * 60);
  const breakElapsedSeconds = Math.max(0, Number(snapshot?.breakElapsedSeconds || 0));
  const breakRemainingSeconds = Math.max(0, breakLimitSeconds - breakElapsedSeconds);
  const breakOverrunSeconds = Math.max(0, breakElapsedSeconds - breakLimitSeconds);
  const overBreakEntries = attendanceOverBreakEntries(summaryLog, policy, nowIso);
  const currentOverBreak = openBreakType
    ? overBreakEntries.find((entry) => String(entry.id || "") === String(openBreakType.id || ""))
    : null;
  const isOverBreak = status === "on-break" && (breakOverrunSeconds > 0 || Boolean(currentOverBreak));
  const statusTone = isOverBreak ? "overbreak" : attendanceStatusTone(status);
  const statusLabel = isOverBreak
    ? "Overbreak"
    : String(snapshot?.statusLabel || "Off").trim() || "Off";
  const shiftLabel = `${String(policy.shiftStart || "09:00")} - ${String(policy.shiftEnd || "18:00")}`;
  const workedSeconds = Math.max(0, Number(snapshot?.workedSeconds || 0));
  const headline =
    status === "on-break"
      ? "On break"
      : status === "working"
        ? "On shift"
        : summaryLog?.clockOutAt
          ? "Clocked out"
          : "Ready to clock in";
  const heroLine =
    status === "on-break"
      ? `${openBreakType?.label || "Break"} · ${formatAttendanceDurationClock(breakElapsedSeconds)}`
      : status === "working"
        ? `${formatAttendanceDurationClock(workedSeconds)} worked`
        : "";
  const subLine =
    status === "on-break"
      ? isOverBreak
        ? `Over by ${formatAttendanceDurationClock(breakOverrunSeconds)}`
        : `Shift ${shiftLabel}`
      : status === "working"
        ? `First in ${firstInLabel}`
        : summaryLog?.clockOutAt
          ? `Last out ${lastOutLabel}`
          : `Shift ${shiftLabel}`;

  let primaryActionMarkup = "";
  let dangerActionMarkup = "";
  if (status === "off") {
    primaryActionMarkup = buildAttendanceQuickPanelActionButton(
      "attendance-clock-in",
      "Clock In",
      "bi-play-circle",
      "primary"
    );
  } else if (status === "working") {
    primaryActionMarkup = buildAttendanceQuickPanelActionButton(
      "attendance-start-break",
      "Start Break",
      "bi-pause-circle",
      "primary"
    );
    dangerActionMarkup = buildAttendanceQuickPanelActionButton(
      "attendance-clock-out",
      "Clock Out",
      "bi-box-arrow-right",
      "danger"
    );
  } else if (status === "on-break") {
    primaryActionMarkup = buildAttendanceQuickPanelActionButton(
      "attendance-end-break",
      "End Break",
      "bi-play-circle",
      "primary"
    );
    dangerActionMarkup = buildAttendanceQuickPanelActionButton(
      "attendance-clock-out",
      "End Break + Clock Out",
      "bi-box-arrow-right",
      "danger"
    );
  }

  return {
    breakLabel: openBreakType?.label || "Break",
    dangerActionMarkup,
    headline,
    heroLine,
    isOverBreak,
    overrunLabel: formatAttendanceDurationClock(breakOverrunSeconds),
    primaryActionMarkup,
    status,
    statusLabel,
    statusTone,
    subLine,
    timeLabel
  };
}

