    loginPasswordDraft: state.loginPasswordDraft,
    loginOtpDraft: state.loginOtpDraft,
    loginOtpSentTo: state.loginOtpSentTo,
    loginPendingPasswordSetupEmail: state.loginPendingPasswordSetupEmail,
    loginPasswordSetupDraft: state.loginPasswordSetupDraft,
    loginPasswordSetupConfirmDraft: state.loginPasswordSetupConfirmDraft,
    loginEmailLookupStatus: { ...state.loginEmailLookupStatus },
    postLoginRouteLabel: getStoredAuthReturnRouteLabel(),
    inviteContext: getInviteAcceptanceContext(window.location.hash),
    inviteLookupStatus: { ...state.inviteLookupStatus },
    inviteRouteMessage: state.inviteRouteMessage,
    inviteRouteLink: state.inviteRouteLink,
    inviteOtpDraft: state.inviteOtpDraft,
    inviteOtpSentTo: state.inviteOtpSentTo,
    invitePendingPasswordSetupEmail: state.invitePendingPasswordSetupEmail,
    invitePasswordSetupDraft: state.invitePasswordSetupDraft,
    invitePasswordSetupConfirmDraft: state.invitePasswordSetupConfirmDraft,
    searchTerm: state.searchTerm,
    uiTheme: state.uiTheme,
    selectedConversationKey: state.selectedConversationKey,
    selectedEmailMessageId: state.selectedEmailMessageId,
    selectedCallWorkspaceItemId: state.selectedCallWorkspaceItemId,
    selectedCallWorkspaceItemType: state.selectedCallWorkspaceItemType,
    commsFilter: state.commsFilter,
    commsMode: state.commsMode,
    commsLocked: isCommsRouteLocked(routeId, state.data),
    callsLiveLocked: String(routeId || "").trim() === "comms-calls" && !canAccessCallsLive(state.data),
    dashboardLocked:
      state.supabaseConfigured &&
      Boolean(state.signedInUser) &&
      state.authAccessState === "granted" &&
      !canAccessDashboard(state.data),
    commsContextCollapsed: state.commsContextCollapsed,
    commsAdvancedOpen: state.commsAdvancedOpen,
    messengerTyping: Array.isArray(state.messengerTyping) ? [...state.messengerTyping] : [],
    messengerEditMessageId: state.messengerEditMessageId,
