    attendanceHistoryStatus: state.attendanceHistoryStatus,
    attendanceHistoryDateStart: state.attendanceHistoryDateStart,
    attendanceHistoryDateEnd: state.attendanceHistoryDateEnd,
    attendanceHistorySelectedLogId: state.attendanceHistorySelectedLogId,
    attendanceTablePage: state.attendanceTablePage,
    attendanceTablePageSize: state.attendanceTablePageSize,
