    leadProfileData: structuredClone(state.leadProfileData || createEmptyLeadProfileData()),
    accountProfileData: structuredClone(state.accountProfileData || createEmptyCrmEntityProfileData()),
    dealProfileData: structuredClone(state.dealProfileData || createEmptyCrmEntityProfileData()),
    crmSnapshotLoaded: state.crmSnapshotLoaded,
