    leadBulkStatusPopoverStyle: state.leadBulkStatusPopoverStyle,
    leadStatusSavingId: state.leadStatusSavingId,
    leadStatusSavingIds: [...state.leadStatusSavingIds],
    leadBulkStatusSaving: state.leadBulkStatusSaving,
    leadBulkStatusTarget: state.leadBulkStatusTarget,
    leadArchivingIds: [...state.leadArchivingIds],
    leadArchiveHiddenIds: [...state.leadArchiveHiddenIds],
    leadFiltersOpen: state.leadFiltersOpen,
    crmSortKey: getCrmSortState(routeId).key,
    crmSortDir: getCrmSortState(routeId).dir,
    crmPage: getCrmPageState(routeId),
    crmPageSize: getCrmPageSizeState(routeId),
    calendarMode: state.calendarMode,
    calendarDate: state.calendarDate,
    calendarMiniCollapsed: state.calendarMiniCollapsed,
    calendarSideCollapsed: state.calendarSideCollapsed,
    kanbanFiltersOpen: state.kanbanFiltersOpen,
