    callsView: state.callsView,
    callsSchedulerDate: state.callsSchedulerDate,
    callsSchedulerMode: state.callsSchedulerMode,
    callsSchedulerWindow: state.callsSchedulerWindow,
    callsSchedulerScope: state.callsSchedulerScope,
    callsSchedulerOwnerId: state.callsSchedulerOwnerId,
    callsSchedulerType: state.callsSchedulerType,
