async function createFollowUpTaskFromLead(lead) {
  if (!lead) {
    return null;
  }
  const dueDate = parseIsoDateLocal(String(lead.nextFollowUp || "").trim())
    ? String(lead.nextFollowUp).trim()
    : todayIso(1);
  const startTime = "09:00";
  const assigneeId = String(lead.ownerId || resolveTeamMemberIdByName(lead.owner) || state.data.currentUser.id || "").trim();
  if (isSupabaseWorkWriteEnabled()) {
    applyWorkSnapshotResult(
      await createSupabaseTask({
        title: `Follow up with ${lead.name}`,
        assigneeId,
        dueDate,
        startTime,
        priority: "low",
        linkType: "Lead",
        linkId: lead.id,
        linkLabel: lead.name,
        accountName: lead.company,
        taskType: "Lead",
        reminderMinutes: 15,
        recurrence: "none",
        notes: String(lead.notes || "").trim(),
        backlogState: "scheduled"
      })
    );
    return null;
  }
  if (blockConnectedModeLocalFallback("Creating follow-up tasks")) {
    return null;
  }
  const task = {
    id: createId("task"),
    createdAt: new Date().toISOString(),
    title: `Follow up with ${lead.name}`,
    assigneeId,
    assignee: String(lead.owner || state.data.currentUser.name).trim() || state.data.currentUser.name,
    dueDate,
    deadlineAt: composeDeadlineAt(dueDate, startTime),
    startTime,
    endTime: "",
    time: startTime,
    day: getWeekdayLabelFromIso(dueDate) || "Mon",
    status: "New",
    priority: "low",
    projectId: "",
    projectName: "",
    linkType: "Lead",
    linkId: lead.id,
    linkLabel: lead.name,
    accountName: lead.company,
    account: lead.company,
    taskType: "Lead",
    callPhone: "",
    reminderMinutes: 15,
    recurrence: "none",
    slaHours: "",
    notes: String(lead.notes || "").trim(),
    completedAt: ""
  };
  state.data.tasks.unshift(task);
  return task;
}

async function submitLeadComposeForm(form, submitIntent = "create", submitter = null) {
  if (!(form instanceof HTMLFormElement) || form.dataset.submitting === "1") {
    return;
  }
  setManagedFormSubmittingState(form, true, submitter);
  try {
    clearFormFeedback(form);
    const formData = new FormData(form);
    const name = String(formData.get("name") || "").trim();
    const company = String(formData.get("company") || "").trim();
    const sourceRaw = String(formData.get("source") || "").trim();
    const source = LEAD_SOURCE_OPTIONS.includes(sourceRaw) ? sourceRaw : "Inbound";
    const statusRaw = String(formData.get("status") || "").trim();
    const owner = String(formData.get("owner") || "").trim() || state.data.currentUser.name;
    const nextFollowUp = String(formData.get("nextFollowUp") || "").trim();
    const interest = String(formData.get("interest") || "").trim();
    const email = String(formData.get("email") || "").trim();
    const phone = String(formData.get("phone") || "").trim();
    const secondaryPhone = String(formData.get("secondaryPhone") || "").trim();
    const role = String(formData.get("role") || "").trim();
    const notes = String(formData.get("notes") || "").trim();
    const tagsRaw = String(formData.get("tags") || "").trim();
    const tags = tagsRaw
      ? tagsRaw
          .split(",")
          .map((tag) => tag.trim())
          .filter(Boolean)
      : [];
    const editingId = String(form.dataset.leadId || "").trim();
    const existing = editingId ? getLeadById(editingId) : null;
    const status = LEAD_STATUS_OPTIONS.includes(statusRaw) ? statusRaw : String(existing?.status || "New").trim() || "New";
    const nowIso = new Date().toISOString();
    const leadMetaPatch = {
      assignedAt: resolveLeadAssignedAtValue(existing, owner, nowIso)
    };

    if (!name) {
      showFormFeedback(form, "Lead name is required.", { fieldSelector: "input[name='name']" });
      return;
    }
    if (!parseIsoDateLocal(nextFollowUp)) {
      form.dataset.leadFollowUpOpen = "1";
      syncLeadFollowUpUi(form, { preserveMonth: true });
      showFormFeedback(form, "Choose a valid next follow-up date.", { fieldSelector: "[data-lead-followup-trigger]" });
      return;
    }

    if (isSupabaseCrmWriteEnabled()) {
      try {
        const payload = buildSupabaseLeadPayload(
          {
            name,
            company,
            source,
            status,
            owner,
            nextFollowUp,
            email,
            phone,
            secondaryPhone,
            interest,
            role,
            notes,
            tags
          },
          {
            existing,
            includeCreatedBy: !existing,
            meta: leadMetaPatch,
            ...(existing ? { archivedAt: existing.archivedAt || null } : {})
          }
        );
        const persisted =
          existing && existing.id
            ? await updateSupabaseLead(existing.id, payload)
            : await createSupabaseLead(payload);
        await refreshSupabaseCrmData({ render: false, persist: false, alertOnError: false });
        const savedLead = getLeadById(String(persisted?.id || existing?.id || "").trim()) || existing;
        if (existing) {
          pushLeadActivity({
            leadId: existing.id,
            type: "lead-updated",
            text: "Lead details were updated."
          });
        }
        if (String(submitIntent || "create") === "create-task" && savedLead) {
          await createFollowUpTaskFromLead(savedLead);
        }
        closeModal();
        persistDataAndRefresh();
        if (!existing && savedLead) {
          if (state.routeId !== "leads") {
            setRoute("leads");
            window.setTimeout(() => openLeadDrawerModal(savedLead.id), 80);
            return;
          }
          window.setTimeout(() => openLeadDrawerModal(savedLead.id), 0);
        }
        return;
      } catch (error) {
        showFormFeedback(form, `${existing ? "Update" : "Create"} lead failed: ${error.message}`);
        return;
      }
    }

    if (blockConnectedModeLocalFallback(existing ? "Updating leads" : "Creating leads", { form })) {
      return;
    }

    const lead = existing || {
      id: createId("lead"),
      createdAt: nowIso,
      archived: false
    };

    lead.name = name;
    lead.company = company;
    lead.source = source;
    lead.status = status;
    lead.owner = owner;
    lead.nextFollowUp = nextFollowUp;
    lead.email = email;
    lead.phone = phone;
    lead.secondaryPhone = secondaryPhone;
    lead.interest = interest;
    lead.role = role;
    lead.notes = notes;
    lead.tags = tags;
    lead.meta = buildCrmMutationMeta(existing || lead, leadMetaPatch);
    lead.updatedAt = nowIso;

    if (!existing) {
      state.data.leads.unshift(lead);
      pushLeadActivity({
        leadId: lead.id,
        type: "lead-created",
        text: "Lead was created."
      });
    } else {
      pushLeadActivity({
        leadId: lead.id,
        type: "lead-updated",
        text: "Lead details were updated."
      });
    }

    if (String(submitIntent || "create") === "create-task") {
      await createFollowUpTaskFromLead(lead);
    }

    closeModal();
    persistDataAndRefresh();

    if (!existing) {
      if (state.routeId !== "leads") {
        setRoute("leads");
        window.setTimeout(() => openLeadDrawerModal(lead.id), 80);
        return;
      }
      window.setTimeout(() => openLeadDrawerModal(lead.id), 0);
    }
  } finally {
    setManagedFormSubmittingState(form, false);
  }
}

function openLeadEditModal(leadId) {
  openLeadComposerModal(leadId);
}

async function submitLeadEditForm(form, submitIntent = "create", submitter = null) {
  await submitLeadComposeForm(form, submitIntent, submitter);
}

function getContactFollowUpPresetIso(presetId) {
  const id = String(presetId || "").trim().toLowerCase();
  if (id === "today" || id === "tomorrow" || id === "late-week" || id === "in-week") {
    return getLeadFollowUpPresetIso(id);
  }
  return "";
}

function getContactFollowUpPresetId(isoDate) {
  const safe = parseIsoDateLocal(isoDate) ? isoDate : "";
  if (!safe) {
    return "tomorrow";
  }
  if (safe === todayIso(0)) {
    return "today";
  }
  if (safe === todayIso(1)) {
    return "tomorrow";
  }
  if (safe === getLeadFollowUpPresetIso("late-week")) {
    return "late-week";
  }
  if (safe === todayIso(7)) {
    return "in-week";
  }
  return "tomorrow";
}

function getContactSuggestions(selectedContactId = "", query = "") {
  const selectedId = String(selectedContactId || "").trim();
  const normalizedQuery = normalizeForMatch(query);
  return (state.data.contacts || [])
    .filter((contact) => {
      const haystack = [contact.name, contact.email, contact.phone, contact.account].map((item) => normalizeForMatch(item)).join(" ");
      return !normalizedQuery || haystack.includes(normalizedQuery);
    })
    .sort((left, right) => left.name.localeCompare(right.name))
    .map((contact) => ({
      id: String(contact.id || "").trim(),
      label: String(contact.name || "Contact").trim() || "Contact",
      meta: [contact.email, contact.phone, contact.account].filter(Boolean).join(" | "),
      selected: String(contact.id || "").trim() === selectedId
    }))
    .slice(0, 8);
}

function getContactAccountSuggestions(selectedAccount = "", query = "") {
  const options = new Set();
  (state.data.accounts || []).forEach((account) => {
    const name = String(account.name || "").trim();
    if (name) {
      options.add(name);
    }
  });
  (state.data.contacts || []).forEach((contact) => {
    const accountName = String(contact.account || "").trim();
    if (accountName) {
      options.add(accountName);
    }
  });
  const selected = String(selectedAccount || "").trim();
  if (selected) {
    options.add(selected);
  }
  const normalizedQuery = normalizeForMatch(query);
  return [...options]
    .filter((name) => !normalizedQuery || normalizeForMatch(name).includes(normalizedQuery))
    .sort((a, b) => a.localeCompare(b))
    .slice(0, 8);
}

function buildContactRoleOptionsMarkup(selectedRole = "") {
  const selected = CONTACT_ROLE_OPTIONS.includes(String(selectedRole || "").trim())
    ? String(selectedRole || "").trim()
    : "Primary Contact";
  return CONTACT_ROLE_OPTIONS.map((role) => {
    const isSelected = role === selected;
    return `
      <button
        type="button"
        class="contact-picker-option ${isSelected ? "is-selected" : ""}"
        data-action="contact-role-select"
        data-id="${escapeModalText(role)}"
      >
        ${escapeModalText(role)}
      </button>
    `;
  }).join("");
}

function buildContactOwnerOptionsMarkup(selectedOwner = "") {
  const selected = String(selectedOwner || "").trim();
  return getTaskAssigneeCandidates(selected)
    .map((candidate) => {
      const displayMeta = String(candidate.meta || "")
        .split("|")
        .map((part) => part.trim())
        .filter(Boolean)
        .join(" | ");
      const isSelected = candidate.name === selected;
      const searchText = `${candidate.name} ${displayMeta}`.toLowerCase();
      return `
        <button
          type="button"
          class="task-assignee-option ${isSelected ? "is-selected" : ""}"
          data-action="contact-owner-select"
          data-id="${escapeModalText(candidate.name)}"
          data-contact-owner-option
          data-search-text="${escapeModalText(searchText)}"
        >
          <span class="task-assignee-avatar">${escapeModalText(initialsFromName(candidate.name))}</span>
          <span class="task-assignee-meta">
            <strong>${escapeModalText(candidate.name)}</strong>
            <small>${escapeModalText(displayMeta)}</small>
          </span>
          <i class="bi bi-check2" aria-hidden="true"></i>
        </button>
      `;
    })
    .join("");
}

function getContactComposeDraftFromForm(form) {
  const name = String(form?.elements?.name?.value || "").trim();
  const account = String(form?.elements?.account?.value || "").trim();
  const email = String(form?.elements?.email?.value || "").trim();
  const phone = String(form?.elements?.phone?.value || "").trim();
  return { name, account, email, phone };
}

function getContactDuplicateSignature(values) {
  const nameKey = normalizeForMatch(values?.name);
  const accountKey = normalizeForMatch(values?.account);
  const emailKey = String(values?.email || "")
    .trim()
    .toLowerCase();
  const phoneKey = phoneDigitsOnly(values?.phone);
  return [nameKey, accountKey, emailKey, phoneKey].join("|");
}

function findContactDuplicates(values, options = {}) {
  const signature = getContactDuplicateSignature(values);
  if (!signature.replaceAll("|", "")) {
    return [];
  }
  const excludedId = String(options.excludeId || "").trim();
  const nameKey = normalizeForMatch(values?.name);
  const accountKey = normalizeForMatch(values?.account);
  const emailKey = String(values?.email || "")
    .trim()
    .toLowerCase();
  const phoneKey = phoneDigitsOnly(values?.phone);

  return (state.data.contacts || [])
    .map((contact) => {
      if (excludedId && String(contact.id || "").trim() === excludedId) {
        return null;
      }
      const reasons = [];
      const contactNameKey = normalizeForMatch(contact.name);
      const contactAccountKey = normalizeForMatch(contact.account);
      const contactEmailKey = String(contact.email || "")
        .trim()
        .toLowerCase();
      const contactPhoneKey = phoneDigitsOnly(contact.phone);

      if (emailKey && contactEmailKey && contactEmailKey === emailKey) {
        reasons.push("same email");
      }
      if (phoneKey && contactPhoneKey && (contactPhoneKey === phoneKey || contactPhoneKey.endsWith(phoneKey) || phoneKey.endsWith(contactPhoneKey))) {
        reasons.push("same phone");
      }
      if (nameKey && accountKey && contactNameKey === nameKey && contactAccountKey === accountKey) {
        reasons.push("same name + account");
      }
      if (!reasons.length) {
        return null;
      }

      return {
        id: contact.id,
        name: String(contact.name || ""),
        account: String(contact.account || ""),
        role: String(contact.role || ""),
        reasons
      };
    })
    .filter(Boolean)
    .slice(0, 4);
}

function syncContactOwnerUi(form) {
  if (!form || form.dataset.mode !== "contact-compose") {
    return;
  }
  const ownerInput = form.querySelector("input[name='owner']");
  if (!ownerInput) {
    return;
  }
  const selectedName = String(ownerInput.value || "").trim() || state.data.currentUser.name;
  ownerInput.value = selectedName;
  const selectedCandidate =
    getTaskAssigneeCandidates(selectedName).find((candidate) => candidate.name === selectedName) || {
      name: selectedName,
      meta: "Owner"
    };

  const labelNode = form.querySelector("[data-contact-owner-label]");
  if (labelNode) {
    labelNode.textContent = selectedCandidate.name;
  }
  const subtitleNode = form.querySelector("[data-contact-owner-subtitle]");
  if (subtitleNode) {
    subtitleNode.textContent = String(selectedCandidate.meta || "")
      .split("|")
      .map((part) => part.trim())
      .filter(Boolean)
      .join(" | ");
  }
  const avatarNode = form.querySelector("[data-contact-owner-avatar]");
  if (avatarNode) {
    avatarNode.textContent = initialsFromName(selectedCandidate.name);
  }

  const open = form.dataset.contactOwnerOpen === "1";
  const popover = form.querySelector("[data-contact-owner-popover]");
  const trigger = form.querySelector("[data-contact-owner-trigger]");
  if (popover) {
    popover.hidden = !open;
  }
  if (trigger) {
    trigger.classList.toggle("is-open", open);
  }

  const searchInput = form.querySelector("[data-contact-owner-search]");
  const query = String(searchInput?.value || "")
    .trim()
    .toLowerCase();
  form.querySelectorAll("[data-contact-owner-option]").forEach((option) => {
    const optionId = String(option.dataset.id || "");
    option.classList.toggle("is-selected", optionId === selectedName);
    const searchable = String(option.dataset.searchText || "");
    option.hidden = Boolean(query) && !searchable.includes(query);
  });
}

function syncContactAccountUi(form) {
  if (!form || form.dataset.mode !== "contact-compose") {
    return;
  }
  const accountInput = form.querySelector("input[name='account']");
  if (!accountInput) {
    return;
  }
  const selectedAccount = String(accountInput.value || "").trim();
  accountInput.value = selectedAccount;

  const labelNode = form.querySelector("[data-contact-account-label]");
  if (labelNode) {
    labelNode.textContent = selectedAccount || "Select account";
  }

  const open = form.dataset.contactAccountOpen === "1";
  const popover = form.querySelector("[data-contact-account-popover]");
  const trigger = form.querySelector("[data-contact-account-trigger]");
  if (popover) {
    popover.hidden = !open;
  }
  if (trigger) {
    trigger.classList.toggle("is-open", open);
  }

  const searchInput = form.querySelector("[data-contact-account-search]");
  const query = String(searchInput?.value || "").trim();
  const options = getContactAccountSuggestions(selectedAccount, query);
  const list = form.querySelector("[data-contact-account-list]");
  if (!list) {
    return;
  }
  const normalizedQuery = normalizeForMatch(query);
  const hasExactMatch = options.some((name) => normalizeForMatch(name) === normalizedQuery);
  const selectedKey = normalizeForMatch(selectedAccount);

  list.innerHTML = [
    ...options.map(
      (name) => `
        <button
          type="button"
          class="contact-picker-option ${normalizeForMatch(name) === selectedKey ? "is-selected" : ""}"
          data-action="contact-account-select"
          data-id="${escapeModalText(name)}"
          data-contact-account-option
        >
          ${escapeModalText(name)}
        </button>
      `
    ),
    ...(query && !hasExactMatch
      ? [
          `
            <button
              type="button"
              class="contact-picker-option is-create"
              data-action="contact-account-create"
              data-id="${escapeModalText(query)}"
              data-contact-account-option
            >
              + Create "${escapeModalText(query)}"
            </button>
          `
        ]
      : []),
    ...(!options.length && !query ? ["<p class='task-meta'>No account suggestions.</p>"] : [])
  ].join("");
}

function syncContactRoleUi(form) {
  if (!form || form.dataset.mode !== "contact-compose") {
    return;
  }
  const roleInput = form.querySelector("input[name='role']");
  if (!roleInput) {
    return;
  }
  const selectedRole = CONTACT_ROLE_OPTIONS.includes(String(roleInput.value || "").trim())
    ? String(roleInput.value || "").trim()
    : "Primary Contact";
  roleInput.value = selectedRole;

  const labelNode = form.querySelector("[data-contact-role-label]");
  if (labelNode) {
    labelNode.textContent = selectedRole;
  }

  const open = form.dataset.contactRoleOpen === "1";
  const popover = form.querySelector("[data-contact-role-popover]");
  const trigger = form.querySelector("[data-contact-role-trigger]");
  if (popover) {
    popover.hidden = !open;
  }
  if (trigger) {
    trigger.classList.toggle("is-open", open);
  }

  const list = form.querySelector("[data-contact-role-list]");
  if (list) {
    list.innerHTML = buildContactRoleOptionsMarkup(selectedRole);
  }
}

function syncContactComposerUi(form) {
  if (!form || form.dataset.mode !== "contact-compose") {
    return;
  }

  const channelInput = form.querySelector("input[name='preferredChannel']");
  if (channelInput) {
    const safeChannel = CONTACT_CHANNEL_OPTIONS.includes(String(channelInput.value || "").trim())
      ? String(channelInput.value || "").trim()
      : "Email";
    channelInput.value = safeChannel;
    form.querySelectorAll("[data-contact-channel]").forEach((button) => {
      button.classList.toggle("is-active", String(button.dataset.id || "") === safeChannel);
    });
  }

  const followUpInput = form.querySelector("input[name='followUpDate']");
  if (followUpInput) {
    const safeDate = parseIsoDateLocal(followUpInput.value) ? followUpInput.value : todayIso(1);
    followUpInput.value = safeDate;
    const activePreset = getContactFollowUpPresetId(safeDate);
    form.querySelectorAll("[data-contact-followup-preset]").forEach((button) => {
      button.classList.toggle("is-active", String(button.dataset.id || "") === activePreset);
    });
    const preview = form.querySelector("[data-contact-followup-preview]");
    if (preview) {
      preview.textContent = formatLeadFollowUpPreview(safeDate);
    }
  }

  syncContactAccountUi(form);
  syncContactRoleUi(form);
  syncContactOwnerUi(form);

  const detailsOpen = form.dataset.contactComposeMoreOpen === "1";
  const detailsBody = form.querySelector("[data-contact-more-body]");
  const detailsToggle = form.querySelector("[data-contact-more-toggle]");
  if (detailsBody) {
    detailsBody.hidden = !detailsOpen;
  }
  if (detailsToggle) {
    detailsToggle.classList.toggle("is-open", detailsOpen);
    detailsToggle.setAttribute("aria-expanded", detailsOpen ? "true" : "false");
  }

  const duplicateWrap = form.querySelector("[data-contact-duplicate-wrap]");
  const duplicateList = form.querySelector("[data-contact-duplicate-list]");
  if (duplicateWrap && duplicateList) {
    const draft = getContactComposeDraftFromForm(form);
    const currentSignature = getContactDuplicateSignature(draft);
    const ignoredSignature = String(form.dataset.contactComposeIgnoredSignature || "");
    const duplicates =
      ignoredSignature === currentSignature
        ? []
        : findContactDuplicates(draft, { excludeId: String(form.dataset.contactId || "") });
    duplicateWrap.hidden = !duplicates.length;
    duplicateList.innerHTML = duplicates
      .map(
        (item) => `
          <article class="lead-duplicate-item">
            <div>
              <p class="task-title">${escapeModalText(item.name)} (${escapeModalText(item.account)})</p>
              <p class="task-meta">${escapeModalText(item.reasons.join(", "))} | ${escapeModalText(item.role || "Contact")}</p>
            </div>
            <button type="button" class="mini-btn" data-action="contact-compose-open-existing" data-id="${item.id}">Use existing</button>
          </article>
        `
      )
      .join("");
  }
}

