function buildMessengerNicknameModalMarkup(selectedConversation, participantNames, selectedParticipantName) {
  const conversationKeyValue = conversationKey(selectedConversation?.targetType || "", selectedConversation?.targetId || "");
  const selectedName = String(selectedParticipantName || "").trim();
  const participantListMarkup = participantNames.length
    ? participantNames
        .map((name) => {
          const normalizedName = String(name || "").trim();
          const nickname = getMessengerNicknameSelectionState(conversationKeyValue, normalizedName);
          const isEditing = normalizedName.toLowerCase() === selectedName.toLowerCase();
          const primaryLabel = nickname || normalizedName;
          const secondaryLabel = nickname ? normalizedName : "Set nickname";
          if (isEditing) {
            return `
              <div class="messenger-customize-person is-editing" data-participant="${escapeModalText(normalizedName)}">
                <span class="messenger-customize-person-avatar">${escapeModalText(normalizedName.slice(0, 1).toUpperCase() || "?")}</span>
                <label class="messenger-customize-person-edit">
                  <input
                    type="hidden"
                    name="participantName"
                    value="${escapeModalText(normalizedName)}"
                  />
                  <input
                    type="text"
                    name="nicknameValue"
                    value="${escapeModalText(nickname)}"
                    placeholder="Set nickname"
                    autocomplete="off"
                  />
                </label>
                <button
                  type="submit"
                  class="messenger-customize-person-action is-confirm"
                  aria-label="Save nickname"
                >
                  <i class="bi bi-check2"></i>
                </button>
              </div>
            `;
          }
          return `
            <button
              type="button"
              class="messenger-customize-person"
              data-action="messenger-nickname-select"
              data-id="${escapeModalText(normalizedName)}"
              aria-label="Edit nickname for ${escapeModalText(normalizedName)}"
            >
              <span class="messenger-customize-person-avatar">${escapeModalText(normalizedName.slice(0, 1).toUpperCase() || "?")}</span>
              <span class="messenger-customize-person-copy">
                <strong>${escapeModalText(primaryLabel)}</strong>
                <span>${escapeModalText(secondaryLabel)}</span>
              </span>
              <span class="messenger-customize-person-action" aria-hidden="true">
                <i class="bi bi-pencil"></i>
              </span>
            </button>
          `;
        })
        .join("")
    : "<p class='task-meta'>No participants found.</p>";
  return `
    <section class="messenger-customize-modal messenger-customize-modal-nickname" data-selected-participant="${escapeModalText(selectedName)}">
      <div class="messenger-customize-person-list">
        ${participantListMarkup}
      </div>
    </section>
  `;
}

