async function startDirectChatWithMemberId(memberId) {
  const teammate = getWorkspaceChatCandidates().find((member) => String(member.id || "") === String(memberId || ""));
  if (!teammate) {
    window.alert("That teammate is no longer available for direct chat.");
    return;
  }
  if (isSupabaseMessengerEnabled()) {
    try {
      const conversationId = await createSupabaseDirectConversation(teammate.id);
      closeModal({ reopenTaskSheet: false });
      state.selectedConversationKey = conversationKey("direct", conversationId);
      state.commsFilter = "direct";
      await refreshSupabaseMessengerData({ render: false, alertOnError: false, conversationId });
      renderRoute();
    } catch (error) {
      window.alert(`Could not start the direct chat: ${String(error?.message || error || "Unknown error")}`);
    }
    return;
  }

  if (blockConnectedModeLocalFallback("Starting direct chats")) {
    return;
  }

  const direct = ensureNamedDirectThreadCore(
    state.data,
    teammate.name,
    state.data.currentUser?.name,
    normalizeForMatch,
    true
  );
  if (!direct) {
    window.alert("Could not start the direct chat.");
    return;
  }

  closeModal({ reopenTaskSheet: false });
  state.selectedConversationKey = conversationKey("direct", direct.id);
  state.commsFilter = "direct";
  persistDataAndRefresh();
}

function startNewGroupChat() {
  openNewGroupChatModal();
}

async function submitNewGroupChatForm(form) {
  clearFormFeedback(form);
  const formData = new FormData(form);
  const name = String(formData.get("groupChatName") || "").trim();
  if (!name) {
    showFormFeedback(form, "Group name is required.", { fieldSelector: "input[name='groupChatName']" });
    return;
  }

  if (isSupabaseMessengerEnabled()) {
    const memberIds = (state.data.teamMembers || [])
      .filter((member) => normalizeTeamMemberStatus(member?.status) === "Active")
      .map((member) => String(member.id || "").trim())
      .filter(Boolean);
    try {
      const conversationId = await createSupabaseGroupConversation(name, memberIds);
      closeModal({ reopenTaskSheet: false });
      state.selectedConversationKey = conversationKey("channel", conversationId);
      state.commsFilter = "gc";
      await refreshSupabaseMessengerData({ render: false, alertOnError: false, conversationId });
      renderRoute();
    } catch (error) {
      showFormFeedback(form, `Could not start the group chat: ${String(error?.message || error || "Unknown error")}`, {
        fieldSelector: "input[name='groupChatName']"
      });
    }
    return;
  }

  if (blockConnectedModeLocalFallback("Starting group chats")) {
    return;
  }

  const existing = (state.data.channels || []).find((channel) => normalizeForMatch(channel?.name) === normalizeForMatch(name));
  if (existing) {
    closeModal({ reopenTaskSheet: false });
    state.selectedConversationKey = conversationKey("channel", existing.id);
    state.commsFilter = "gc";
    renderRoute();
    return;
  }

  if (!Array.isArray(state.data.channels)) {
    state.data.channels = [];
  }

  const timestamp = new Date().toISOString();
  const channel = {
    id: createId("chan"),
    name,
    type: "Team",
    topic: "",
    unread: 0,
    pinned: false,
    muted: false,
    createdAt: timestamp,
    updatedAt: timestamp
  };

  state.data.channels.unshift(channel);
  closeModal({ reopenTaskSheet: false });
  state.selectedConversationKey = conversationKey("channel", channel.id);
  state.commsFilter = "gc";
  persistDataAndRefresh();
}

