function syncContactViewUi(modalForm) {
  if (!modalForm || modalForm.dataset.mode !== "contact-view") {
    return;
  }
  const validTabs = ["overview", "activity", "tasks", "deals", "comms"];
  const nextTab = String(modalForm.dataset.contactViewTab || "").trim().toLowerCase();
  const activeTab = validTabs.includes(nextTab) ? nextTab : "activity";
  modalForm.dataset.contactViewTab = activeTab;

  modalForm.querySelectorAll("[data-contact-view-tab]").forEach((button) => {
    const isActive = String(button.dataset.id || "").toLowerCase() === activeTab;
    button.classList.toggle("is-active", isActive);
    button.setAttribute("aria-selected", isActive ? "true" : "false");
  });

  modalForm.querySelectorAll("[data-contact-view-panel]").forEach((panel) => {
    panel.hidden = String(panel.dataset.contactViewPanel || "").toLowerCase() !== activeTab;
  });
}

