async function submitLeadFollowUpForm(form) {
  const lead = getLeadById(form?.dataset.leadId);
  if (!lead) {
    window.alert("Lead not found.");
    return;
  }
  const formData = new FormData(form);
  const nextFollowUp = String(formData.get("nextFollowUp") || "").trim();
  if (!parseIsoDateLocal(nextFollowUp)) {
    window.alert("Choose a valid follow-up date.");
    return;
  }

  if (isSupabaseCrmWriteEnabled()) {
    try {
      await updateSupabaseLead(
        lead.id,
        buildSupabaseLeadPayload(
          {
            name: lead.name,
            company: lead.company,
            source: lead.source,
            status: lead.status,
            owner: lead.owner,
            nextFollowUp,
            email: lead.email || "",
            phone: lead.phone || "",
            secondaryPhone: lead.secondaryPhone || "",
            interest: lead.interest || "",
            role: lead.role || "",
            notes: lead.notes || "",
            tags: lead.tags || []
          },
          { existing: lead, archivedAt: lead.archived ? lead.archivedAt : null }
        )
      );
      await refreshSupabaseCrmData({ render: false, persist: false, alertOnError: false });
      const refreshedLead = getLeadById(lead.id) || lead;
      const note = String(formData.get("note") || "").trim();
      pushLeadActivity({
        leadId: refreshedLead.id,
        type: "lead-followup-updated",
        text: note ? `Follow-up moved to ${nextFollowUp}. ${note}` : `Follow-up moved to ${nextFollowUp}.`
      });
      closeModal({ reopenTaskSheet: false });
      persistDataAndRefresh();
      return;
    } catch (error) {
      window.alert(`Update follow-up failed: ${error.message}`);
      return;
    }
  }

  if (blockConnectedModeLocalFallback("Updating lead follow-up")) {
    return;
  }

  lead.nextFollowUp = nextFollowUp;
  const note = String(formData.get("note") || "").trim();
  pushLeadActivity({
    leadId: lead.id,
    type: "lead-followup-updated",
    text: note ? `Follow-up moved to ${nextFollowUp}. ${note}` : `Follow-up moved to ${nextFollowUp}.`
  });
  closeModal({ reopenTaskSheet: false });
  persistDataAndRefresh();
}

