async function submitLeadReassignForm(form) {
  const lead = getLeadById(form?.dataset.leadId);
  if (!lead) {
    window.alert("Lead not found.");
    return;
  }
  const formData = new FormData(form);
  const owner = String(formData.get("owner") || "").trim();
  if (!owner) {
    window.alert("Owner is required.");
    return;
  }
  const previousOwner = lead.owner;
  const nowIso = new Date().toISOString();
  const nextAssignedAt = resolveLeadAssignedAtValue(lead, owner, nowIso);
  const resetAttemptMeta = {
    assignedAt: nextAssignedAt,
    attemptCount: 0,
    lastAttemptAt: "",
    lastAttemptReason: "",
    attemptLimitAt: "",
    attemptLimitRemovalDueAt: "",
    attemptLimitRemovalState: "",
    attemptLimitRemovedFromActiveAt: "",
    attemptLimitRemovedFromActiveReason: ""
  };

  if (isSupabaseCrmWriteEnabled()) {
    try {
      await updateSupabaseLead(
        lead.id,
        buildSupabaseLeadPayload(
          {
            name: lead.name,
            company: lead.company,
            source: lead.source,
            status: lead.status,
            owner,
            nextFollowUp: lead.nextFollowUp,
            email: lead.email || "",
            phone: lead.phone || "",
            secondaryPhone: lead.secondaryPhone || "",
            interest: lead.interest || "",
            role: lead.role || "",
            notes: lead.notes || "",
            tags: lead.tags || []
          },
          {
            existing: lead,
            archivedAt: lead.archived ? lead.archivedAt : null,
            meta: resetAttemptMeta
          }
        )
      );
      await refreshSupabaseCrmData({ render: false, persist: false, alertOnError: false });
      const reason = String(formData.get("reason") || "").trim();
      pushLeadActivity({
        leadId: lead.id,
        type: "lead-owner-reassigned",
        text: reason
          ? `Owner changed from ${previousOwner} to ${owner}. ${reason}`
          : `Owner changed from ${previousOwner} to ${owner}.`
      });
      closeModal();
      persistDataAndRefresh();
      return;
    } catch (error) {
      window.alert(`Reassign owner failed: ${error.message}`);
      return;
    }
  }

  if (blockConnectedModeLocalFallback("Reassigning lead owners")) {
    return;
  }

  lead.owner = owner;
  lead.meta = buildCrmMutationMeta(lead, resetAttemptMeta);
  const reason = String(formData.get("reason") || "").trim();
  pushLeadActivity({
    leadId: lead.id,
    type: "lead-owner-reassigned",
    text: reason
      ? `Owner changed from ${previousOwner} to ${owner}. ${reason}`
      : `Owner changed from ${previousOwner} to ${owner}.`
  });
  closeModal();
  persistDataAndRefresh();
}

