const CALLS_SCHEDULER_SLOT_MINUTES = 30;

function addMinutesToClockTime(value, minutes) {
  const normalized = normalizeTimeValue(value || "09:00", "09:00");
  const [hours, mins] = normalized.split(":").map((part) => Number.parseInt(part, 10) || 0);
  const next = new Date(2000, 0, 1, hours, mins + Number(minutes || 0), 0, 0);
  return `${String(next.getHours()).padStart(2, "0")}:${String(next.getMinutes()).padStart(2, "0")}`;
}

function getCallsSchedulerTaskDurationMinutes(task) {
  const start = normalizeTimeValue(task?.startTime || splitDeadlineAt(task?.deadlineAt).startTime, "09:00");
  const end = normalizeTimeValue(task?.endTime || "", "");
  if (start && end) {
    const [startHour = 9, startMinute = 0] = start.split(":").map((part) => Number.parseInt(part, 10) || 0);
    const [endHour = startHour, endMinute = startMinute] = end.split(":").map((part) => Number.parseInt(part, 10) || 0);
    const startTotal = startHour * 60 + startMinute;
    const endTotal = endHour * 60 + endMinute;
    if (endTotal > startTotal) {
      return endTotal - startTotal;
    }
  }
  return isCallbackTaskType(task?.taskType) ? 30 : 45;
}

function isCallsSchedulerQueuedTask(task) {
  return String(task?.backlogState || "").trim().toLowerCase() === "queue" || !String(task?.dueDate || "").trim();
}

function parseCallsSchedulerDropValue(value) {
  const [rawDate = "", rawTime = ""] = String(value || "").split("|");
  const dueDate = parseIsoDateLocal(rawDate) ? rawDate : "";
  const startTime = /^\d{2}:\d{2}$/.test(String(rawTime || "").trim()) ? String(rawTime).trim() : "";
  if (!dueDate || !startTime) {
    return null;
  }
  return { dueDate, startTime };
}

function getCallsSchedulerConflictTask(taskId, dueDate, startTime, endTime, assigneeId = "", assigneeName = "") {
  const normalizedDueDate = String(dueDate || "").trim();
  const normalizedStart = normalizeTimeValue(startTime || "", "");
  const normalizedEnd = normalizeTimeValue(endTime || "", "");
  if (!normalizedDueDate || !normalizedStart || !normalizedEnd) {
    return null;
  }
  const [startHour = 0, startMinute = 0] = normalizedStart.split(":").map((part) => Number.parseInt(part, 10) || 0);
  const [endHour = 0, endMinute = 0] = normalizedEnd.split(":").map((part) => Number.parseInt(part, 10) || 0);
  const startTotal = startHour * 60 + startMinute;
  const endTotal = endHour * 60 + endMinute;
  if (endTotal <= startTotal) {
    return null;
  }
  const normalizedAssigneeId = String(assigneeId || "").trim();
  const normalizedAssigneeName = String(assigneeName || "").trim().toLowerCase();
  return (state.data.tasks || []).find((task) => {
    if (!task || String(task.id || "").trim() === String(taskId || "").trim()) {
      return false;
    }
    if (!isCallTaskType(task.taskType) || String(task.status || "").trim() === "Completed" || isCallsSchedulerQueuedTask(task)) {
      return false;
    }
    if (String(task.dueDate || "").trim() !== normalizedDueDate) {
      return false;
    }
    const taskAssigneeId = String(task.assigneeId || "").trim();
    const taskAssigneeName = String(task.assignee || "").trim().toLowerCase();
    const sameAssignee =
      (normalizedAssigneeId && taskAssigneeId && normalizedAssigneeId === taskAssigneeId) ||
      (!normalizedAssigneeId && normalizedAssigneeName && normalizedAssigneeName === taskAssigneeName);
    if (!sameAssignee) {
      return false;
    }
    const taskStart = normalizeTimeValue(task.startTime || splitDeadlineAt(task.deadlineAt).startTime, "09:00");
    const taskEnd = normalizeTimeValue(task.endTime || addMinutesToClockTime(taskStart, getCallsSchedulerTaskDurationMinutes(task)), "");
    const [taskStartHour = 0, taskStartMinute = 0] = taskStart.split(":").map((part) => Number.parseInt(part, 10) || 0);
    const [taskEndHour = 0, taskEndMinute = 0] = taskEnd.split(":").map((part) => Number.parseInt(part, 10) || 0);
    const taskStartTotal = taskStartHour * 60 + taskStartMinute;
    const taskEndTotal = taskEndHour * 60 + taskEndMinute;
    return startTotal < taskEndTotal && endTotal > taskStartTotal;
  }) || null;
}

async function persistCallsSchedulerPlacement(task, changes = {}) {
  if (!task || !canTaskEditCore(task)) {
    return false;
  }
  const currentStart = normalizeTimeValue(task.startTime || splitDeadlineAt(task.deadlineAt).startTime, "09:00");
  const nextDueDate = parseIsoDateLocal(String(changes.dueDate || "").trim()) ? String(changes.dueDate).trim() : String(task.dueDate || "").trim();
  const nextStart = normalizeTimeValue(changes.startTime || currentStart, currentStart);
  const nextEndDefault = addMinutesToClockTime(nextStart, getCallsSchedulerTaskDurationMinutes(task));
  const nextEnd = normalizeTimeValue(changes.endTime !== undefined ? changes.endTime : task.endTime || nextEndDefault, nextEndDefault);
  const nextBacklogState = String(changes.backlogState || task.backlogState || "scheduled").trim().toLowerCase() || "scheduled";
  const nextPayload = {
    dueDate: nextDueDate,
    startTime: nextStart,
    endTime: nextEnd,
    backlogState: nextBacklogState
  };

  if (String(task.dueDate || "").trim() === nextDueDate && currentStart === nextStart && normalizeTimeValue(task.endTime || "", "") === nextEnd && String(task.backlogState || "").trim().toLowerCase() === nextBacklogState) {
    return false;
  }

  const assigneeId = String(task.assigneeId || "").trim();
  const assigneeName = String(task.assignee || "").trim();
  const conflictTask = getCallsSchedulerConflictTask(task.id, nextDueDate, nextStart, nextEnd, assigneeId, assigneeName);
  if (conflictTask) {
    showToast(
      `Blocked: overlaps with ${String(conflictTask.title || conflictTask.linkLabel || "another scheduled call").trim()}.`,
      { tone: "danger" }
    );
    return false;
  }

  if (isSupabaseWorkWriteEnabled()) {
    applyWorkSnapshotResult(await updateSupabaseTask(task.id, nextPayload), { render: false });
  } else {
    if (blockConnectedModeLocalFallback("Rescheduling calls")) {
      return false;
    }
    task.dueDate = nextDueDate;
    task.startTime = nextStart;
    task.endTime = nextEnd;
    task.deadlineAt = composeDeadlineAt(nextDueDate, nextStart);
    task.time = formatTaskTimeRange(nextStart, nextEnd) || nextStart;
    task.day = getWeekdayLabelFromIso(nextDueDate) || task.day;
    task.backlogState = nextBacklogState;
    task.updatedAt = new Date().toISOString();
    recordTaskActivity(task, "Call schedule updated", "updated");
  }
  return true;
}

function openTaskComposerWithPrefill(prefill = null) {
  state.taskComposePrefill = prefill && typeof prefill === "object" ? { ...prefill } : null;
  closeModal();
  openTaskComposerModal();
}

function getPrimaryDealContact(deal) {
  if (!deal) {
    return null;
  }
  const directContactId = String(deal.contactId || "").trim();
  if (directContactId) {
    return getContactById(directContactId);
  }
  const contactName = String(deal.contactName || "").trim();
  const accountKey = normalizeForMatch(String(deal.account || "").trim());
  if (contactName) {
    const directMatch =
      (state.data.contacts || []).find(
        (contact) =>
          normalizeForMatch(contact.name) === normalizeForMatch(contactName) &&
          (!accountKey || normalizeForMatch(contact.account) === accountKey)
      ) ||
      (state.data.contacts || []).find((contact) => normalizeForMatch(contact.name) === normalizeForMatch(contactName));
    if (directMatch) {
      return directMatch;
    }
  }
  const account =
    String(deal.account || "").trim() &&
    (state.data.accounts || []).find((item) => normalizeForMatch(item.name) === normalizeForMatch(deal.account));
  return account ? getPrimaryAccountContact(account, { requirePhone: true }) || getPrimaryAccountContact(account) : null;
}

function buildLeadCallTaskPrefill(lead, taskType = "Call") {
  const normalizedTaskType = canonicalTaskType(taskType, "Call");
  const leadContext = getLeadContext(lead);
  const contact = getPrimaryLeadContact(lead, leadContext);
  const accountName = String(leadContext.account?.name || lead.company || "").trim();
  const targetName = String(contact?.name || lead.name || "Lead").trim() || "Lead";
  return buildTaskComposerPrefill({
    title: `${normalizedTaskType === "Callback" ? "Callback" : "Call"} ${targetName}`,
    ownerId: lead.ownerId,
    owner: lead.owner,
    dueDate: parseIsoDateLocal(String(lead.nextFollowUp || "").trim()) ? String(lead.nextFollowUp).trim() : todayIso(1),
    startTime: normalizedTaskType === "Callback" ? "14:00" : "09:00",
    priority: normalizedTaskType === "Callback" ? "medium" : "low",
    taskType: normalizedTaskType,
    callPhone: normalizePhoneValue(lead.phone || lead.secondaryPhone || contact?.phone || ""),
    linkType: "Lead",
    linkId: lead.id,
    linkLabel: lead.name,
    accountName,
    reminderMinutes: 15,
    notes: [`Lead: ${lead.name}`, accountName ? `Account: ${accountName}` : "", lead.source ? `Source: ${lead.source}` : ""]
      .filter(Boolean)
      .join("\n")
  });
}

