function prefillTaskComposerFromLead(lead) {
  if (!lead) {
    return;
  }
  const modalForm = document.getElementById("modalForm");
  if (!modalForm || modalForm.dataset.mode !== "task-compose") {
    return;
  }
  const titleInput = modalForm.querySelector("input[name='title']");
  const assigneeInput = modalForm.querySelector("input[name='assignee']");
  const deadlineInput = modalForm.querySelector("input[name='deadlineAt']");
  const notesInput = modalForm.querySelector("textarea[name='notes']");

  if (titleInput && !String(titleInput.value || "").trim()) {
    titleInput.value = `Follow up with ${lead.name}`;
  }

  if (assigneeInput) {
    assigneeInput.value = resolveTaskComposerAssigneeId(lead.ownerId, lead.owner);
  }

  const followUpDate = parseIsoDateLocal(String(lead.nextFollowUp || "").trim())
    ? String(lead.nextFollowUp).trim()
    : todayIso(1);
  if (deadlineInput) {
    const currentTime = splitDeadlineAt(deadlineInput.value).startTime || "09:00";
    deadlineInput.value = composeDeadlineAt(followUpDate, currentTime);
  }

  if (notesInput && !String(notesInput.value || "").trim()) {
    const source = String(lead.source || "").trim();
    notesInput.value = `Lead: ${lead.name} @ ${lead.company}${source ? ` (${source})` : ""}`;
  }

  modalForm.dataset.taskDeadlineMonth = followUpDate.slice(0, 7);
  syncTaskAssigneeUi(modalForm);
  syncTaskDeadlineUi(modalForm, { preserveMonth: true });
  syncTaskAdvancedUi(modalForm);
}

