function getAttendanceBreakStartOptions(activeLog, policy, nowIso = getLiveNowIso()) {
  const breakTypes = getAttendancePolicyBreakTypes(policy);
  const usage = getAttendanceBreakUsage(activeLog, policy, nowIso);
  const nowParts = getDatePartsForTimeZone(nowIso, resolveAttendanceUiTimeZone(policy));
  const nowMinutes = nowParts ? nowParts.hour * 60 + nowParts.minute : new Date(nowIso).getHours() * 60 + new Date(nowIso).getMinutes();
  return breakTypes.map((entry) => {
    const current = usage.get(entry.id) || { count: 0, minutes: 0 };
    const remainingCount = Math.max(0, Number(entry.maxPerDay || 1) - Number(current.count || 0));
    const inWindow = isAttendanceWithinWindow(nowMinutes, entry.windowStart, entry.windowEnd);
    const canStart = remainingCount > 0 && inWindow;
    return {
      ...entry,
      usedCount: Number(current.count || 0),
      usedMinutes: Number(current.minutes || 0),
      remainingCount,
      inWindow,
      canStart
    };
  });
}

