async function submitTeamInviteForm(form, submitter = null) {
  if (!(form instanceof HTMLFormElement) || form.dataset.submitting === "1") {
    return;
  }
  setManagedFormSubmittingState(form, true, submitter);
  try {
    if (!canManageTeamMembers()) {
      showFormFeedback(form, "Only owners or admins can invite team members.");
      return;
    }

    clearFormFeedback(form);
    ensureProfileCollections(state.data);
    const formData = new FormData(form);
    const name = String(formData.get("name") || "").trim();
    const email = String(formData.get("email") || "").trim().toLowerCase();
    const team = String(formData.get("team") || "").trim() || "General";
    const allowedRoles = getAssignableTeamRoles();
    const requestedRole = String(formData.get("role") || "").trim();
    const role = allowedRoles.includes(requestedRole) ? requestedRole : allowedRoles.includes("Member") ? "Member" : allowedRoles[0] || "Member";
    const timezone = String(formData.get("timezone") || state.data.workspace?.timezone || "Local").trim() || "Local";

    if (!name || !email) {
      showFormFeedback(form, "Full name and work email are required.", {
        fieldSelector: !name ? "input[name='name']" : "input[name='email']"
      });
      return;
    }

    const existingLocalMember = (state.data.teamMembers || []).find(
      (member) => String(member.email || "").trim().toLowerCase() === email
    );

    const nowIso = new Date().toISOString();
    const inviteToken = createId("invite");
    const member = {
      id: createId("member"),
      name,
      email,
      team,
      role,
      workload: 0,
      status: "Pending Invite",
      title: `${team} | ${role}`,
      manager: "",
      timezone,
      shift: `${String(state.data.attendancePolicy?.shiftStart || "09:00")}-${String(state.data.attendancePolicy?.shiftEnd || "18:00")}`,
      scope: role.toLowerCase() === "owner" || role.toLowerCase() === "admin" ? "all" : role.toLowerCase() === "manager" ? "team" : "own",
      queueEligible: true,
      defaultOwner: false,
      invitedAt: nowIso,
      inviteLastSentAt: nowIso,
      inviteToken,
      authProvider: "",
      authUserId: "",
      lastLoginAt: "",
      updatedAt: nowIso,
      updatedBy: resolveCurrentUserName(state.data),
      permissions: buildPermissionTemplate(role)
    };

    if (isSupabaseTeamWriteEnabled()) {
      const workspaceId = String(state.data.workspace?.id || "").trim();
      if (!workspaceId) {
        showFormFeedback(
          form,
          "Workspace is not linked to Supabase yet. Sign in with an invited owner/admin account first."
        );
        return;
      }
      try {
        const existingMember = await fetchWorkspaceTeamMemberByEmail(workspaceId, email);
        let insertedMember = null;
        let inviteSuccessMessage = "Invite created.";
        if (existingMember?.id) {
          const existingStatus = normalizeTeamMemberStatus(existingMember.status);
          if (existingStatus === "Active") {
            showToast("This team member is already active in the workspace.", {
              tone: "warning",
              duration: 5200
            });
            state.selectedTeamMemberId = String(existingMember.id || "");
            closeModal();
            await refreshSupabaseTeamWorkspace({ alertOnDeny: false });
            renderRoute();
            return;
          }
          insertedMember = await updateSupabaseTeamMember(existingMember.id, {
            name,
            role,
            team,
            timezone,
            status: "Pending Invite",
            inviteToken,
            invitedAt: existingMember.invitedAt || nowIso,
            inviteLastSentAt: nowIso,
            updatedAt: nowIso
          });
          inviteSuccessMessage = "Invite refreshed.";
        } else {
          insertedMember = await createSupabaseTeamInvite({
            workspaceId,
            name,
            email,
            role,
            team,
            timezone,
            status: "Pending Invite",
            inviteToken,
            invitedAt: nowIso,
            inviteLastSentAt: nowIso,
            authProvider: "",
            authUserId: "",
            lastLoginAt: "",
            updatedAt: nowIso
          });
        }
        closeModal();
        await refreshSupabaseTeamWorkspace({ alertOnDeny: false });
        state.selectedTeamMemberId = String(insertedMember?.id || "");
        await syncPublicInviteRecord(
          {
            ...insertedMember,
            name,
            email,
            role,
            team,
            workspace: state.data.workspace?.name || "Workspace",
            invitedBy: resolveCurrentUserName(state.data)
          },
          {
            inviteId: String(insertedMember?.id || "").trim(),
            workspaceId
          }
        );
        await deliverTeamInvite(
          {
            ...insertedMember,
            name,
            email,
            role,
            team,
            workspace: state.data.workspace?.name || "Workspace",
            invitedBy: resolveCurrentUserName(state.data)
          },
          inviteSuccessMessage
        );
        renderRoute();
        return;
      } catch (error) {
        showFormFeedback(form, `Invite failed: ${error.message}`);
        return;
      }
    }

    if (blockConnectedModeLocalFallback("Inviting team members", { form })) {
      return;
    }

    if (existingLocalMember) {
      const existingStatus = normalizeTeamMemberStatus(existingLocalMember.status);
      if (existingStatus === "Active") {
        showFormFeedback(form, "This team member is already active in the workspace.", {
          fieldSelector: "input[name='email']"
        });
        return;
      }

      existingLocalMember.name = name;
      existingLocalMember.email = email;
      existingLocalMember.team = team;
      existingLocalMember.role = role;
      existingLocalMember.timezone = timezone;
      existingLocalMember.status = "Pending Invite";
      existingLocalMember.title = `${team} | ${role}`;
      existingLocalMember.scope =
        role.toLowerCase() === "owner" || role.toLowerCase() === "admin"
          ? "all"
          : role.toLowerCase() === "manager"
            ? "team"
            : "own";
      existingLocalMember.invitedAt = existingLocalMember.invitedAt || nowIso;
      existingLocalMember.inviteLastSentAt = nowIso;
      existingLocalMember.inviteToken = inviteToken;
      existingLocalMember.authProvider = "";
      existingLocalMember.authUserId = "";
      existingLocalMember.lastLoginAt = "";
      existingLocalMember.updatedAt = nowIso;
      existingLocalMember.updatedBy = resolveCurrentUserName(state.data);
      existingLocalMember.permissions = buildPermissionTemplate(role);
      state.selectedTeamMemberId = existingLocalMember.id;
      closeModal();
      persistDataAndRefresh();
      return;
    }

    state.data.teamMembers.unshift(member);
    state.selectedTeamMemberId = member.id;
    closeModal();
    persistDataAndRefresh();
  } finally {
    setManagedFormSubmittingState(form, false);
  }
}

