function getLiveMyProfileIdentity() {
  const form = document.getElementById("myProfileForm");
  const currentUser = state.data.currentUser && typeof state.data.currentUser === "object" ? state.data.currentUser : {};
  const currentMember = getCurrentUserTeamMember(state.data);
  const nameField = form instanceof HTMLFormElement ? form.querySelector("input[name='name']") : null;
  const emailField = form instanceof HTMLFormElement ? form.querySelector("input[name='email']") : null;
  const titleField = form instanceof HTMLFormElement ? form.querySelector("input[name='title']") : null;
  const fullName =
    String(nameField instanceof HTMLInputElement ? nameField.value : currentUser.name || currentMember?.name || "").trim() ||
    "Workspace User";
  const email =
    String(emailField instanceof HTMLInputElement ? emailField.value : currentUser.email || currentMember?.email || "").trim() ||
    "No email set";
  const title =
    String(titleField instanceof HTMLInputElement ? titleField.value : currentUser.title || currentMember?.title || "").trim() ||
    "No title set";
  return {
    fullName,
    email,
    title,
    initials: initialsFromName(fullName)
  };
}

function getProfileAvatarViewModel() {
  const currentUser = state.data.currentUser && typeof state.data.currentUser === "object" ? state.data.currentUser : {};
  const currentMember = getCurrentUserTeamMember(state.data);
  const baseAvatarUrl = String(currentUser.avatarUrl || currentMember?.avatarUrl || "").trim();
  return {
    baseAvatarUrl,
    avatarUrl: baseAvatarUrl,
    hasBaseAvatar: Boolean(baseAvatarUrl),
    hasDraftFile: false,
    removePending: false
  };
}

function buildProfileAvatarPreviewMarkup(avatarUrl, fullName, initials) {
  if (avatarUrl) {
    return `<img src="${escapeModalText(avatarUrl)}" alt="${escapeModalText(fullName)}" />`;
  }
  return `<span class="my-profile-avatar-fallback">${escapeModalText(initials)}</span>`;
}

function syncProfileAvatarEditorModal(form) {
  if (!(form instanceof HTMLFormElement)) {
    return;
  }
  const identity = getLiveMyProfileIdentity();
  const previewNode = form.querySelector("[data-profile-avatar-modal-preview]");
  const statusNode = form.querySelector("[data-profile-avatar-modal-status]");
  const secondaryButton = form.querySelector("[data-action='profile-avatar-secondary']");
  const removeField = form.querySelector("input[name='avatarRemove']");
  const fileField = form.querySelector("input[name='avatarFile']");
  const baseAvatarUrl = String(form.dataset.baseAvatarUrl || "").trim();
  const previewUrl = String(form.dataset.previewUrl || "").trim();
  const removeAvatar = removeField instanceof HTMLInputElement && removeField.value === "1";
  const fileSelected = fileField instanceof HTMLInputElement && Boolean(fileField.files?.length);
  const effectiveAvatarUrl = removeAvatar ? "" : previewUrl || baseAvatarUrl;

  if (previewNode instanceof HTMLElement) {
    previewNode.innerHTML = buildProfileAvatarPreviewMarkup(effectiveAvatarUrl, identity.fullName, identity.initials);
  }

  if (secondaryButton instanceof HTMLButtonElement) {
    if (removeAvatar) {
      secondaryButton.hidden = false;
      secondaryButton.textContent = "Keep photo";
    } else if (previewUrl) {
      secondaryButton.hidden = false;
      secondaryButton.textContent = baseAvatarUrl ? "Use current photo" : "Clear selection";
    } else if (baseAvatarUrl) {
      secondaryButton.hidden = false;
      secondaryButton.textContent = "Remove photo";
    } else {
      secondaryButton.hidden = true;
      secondaryButton.textContent = "Remove photo";
    }
  }

  if (statusNode instanceof HTMLElement) {
    if (removeAvatar) {
      statusNode.textContent = "Your current photo will be removed when you save this change.";
    } else if (previewUrl || fileSelected) {
      statusNode.textContent = "A new photo is selected. Save to replace the current photo.";
    } else if (baseAvatarUrl) {
      statusNode.textContent = "Your current photo is active.";
    } else {
      statusNode.textContent = "No profile photo has been added yet.";
    }
  }
}

async function syncProfileAvatarEditorModalFromFile(input) {
  if (!(input instanceof HTMLInputElement)) {
    return;
  }
  const form = input.form;
  if (!(form instanceof HTMLFormElement) || form.dataset.mode !== "profile-avatar") {
    return;
  }
  const file = input.files?.[0] || null;
  const removeField = form.querySelector("input[name='avatarRemove']");
  if (!(removeField instanceof HTMLInputElement)) {
    return;
  }
  removeField.value = "0";
  if (!file) {
    form.dataset.previewUrl = "";
    syncProfileAvatarEditorModal(form);
    return;
  }
  try {
    form.dataset.previewUrl = await readFileAsDataUrl(file);
    syncProfileAvatarEditorModal(form);
  } catch (error) {
    form.dataset.previewUrl = "";
    syncProfileAvatarEditorModal(form);
    showFormFeedback(form, error instanceof Error ? error.message : "Profile image could not be read.");
  }
}

function syncInlineProfileAvatarPreview() {
  const previewNode = document.querySelector("[data-profile-avatar-preview]");
  const trigger = document.querySelector("[data-profile-avatar-trigger]");
  const nameNode = document.querySelector("[data-profile-identity-name]");
  const emailNode = document.querySelector("[data-profile-identity-email]");
  const titleNode = document.querySelector("[data-profile-identity-title]");
  if (!(previewNode instanceof HTMLElement) || !(trigger instanceof HTMLElement)) {
    return;
  }
  const identity = getLiveMyProfileIdentity();
  const avatar = getProfileAvatarViewModel();
  previewNode.innerHTML = buildProfileAvatarPreviewMarkup(avatar.avatarUrl, identity.fullName, identity.initials);
  trigger.setAttribute("aria-label", avatar.avatarUrl ? "Change profile photo" : "Add profile photo");
  if (nameNode instanceof HTMLElement) {
    nameNode.textContent = identity.fullName;
  }
  if (emailNode instanceof HTMLElement) {
    emailNode.textContent = identity.email;
  }
  if (titleNode instanceof HTMLElement) {
    titleNode.textContent = identity.title;
  }
}

