async function submitProfileAvatarEditorForm(form) {
  if (!(form instanceof HTMLFormElement)) {
    return;
  }
  ensureProfileCollections(state.data);
  clearFormFeedback(form);
  const formData = new FormData(form);
  const selectedFile = formData.get("avatarFile");
  const hasNewAvatarFile = selectedFile instanceof File && selectedFile.size > 0;
  const removeAvatar = String(formData.get("avatarRemove") || "0") === "1";
  const currentUser = state.data.currentUser && typeof state.data.currentUser === "object" ? state.data.currentUser : {};
  const currentMember = getCurrentUserTeamMember(state.data);
  const previousAvatarStoragePath = String(currentMember?.avatarStoragePath || "").trim();
  const previousAvatarUrl = String(currentUser.avatarUrl || currentMember?.avatarUrl || "").trim();

  if (!hasNewAvatarFile && !removeAvatar) {
    closeModal({ reopenTaskSheet: false });
    return;
  }

  if (state.supabaseConfigured && state.signedInUser && currentMember?.id) {
    let uploadedAvatar = null;
    try {
      const nextUpdatedAt = new Date().toISOString();
      if (hasNewAvatarFile) {
        uploadedAvatar = await uploadSupabaseProfileImage(
          currentMember.workspaceId || state.data.workspace?.id || "",
          currentMember.id,
          selectedFile
        );
      }
      const nextAvatarStoragePath = removeAvatar ? "" : String(uploadedAvatar?.storagePath || previousAvatarStoragePath || previousAvatarUrl).trim();
      const updatedMember = await updateSupabaseTeamMember(currentMember.id, {
        avatarUrl: nextAvatarStoragePath,
        updatedBy: resolveCurrentUserName(state.data),
        updatedAt: nextUpdatedAt
      });
      const nextAvatarUrl = removeAvatar
        ? ""
        : String(updatedMember?.avatarUrl || uploadedAvatar?.signedUrl || previousAvatarUrl).trim();
      currentUser.avatarUrl = nextAvatarUrl;
      currentUser.avatarStoragePath = nextAvatarStoragePath;
      if (currentMember) {
        currentMember.avatarUrl = nextAvatarUrl;
        currentMember.avatarStoragePath = nextAvatarStoragePath;
        syncCurrentUserFromMember({
          ...currentMember,
          ...updatedMember,
          avatarUrl: nextAvatarUrl,
          avatarStoragePath: nextAvatarStoragePath
        });
      }
      state.profileAvatarDraft = null;
      saveData(state.data);
      closeModal({ reopenTaskSheet: false });
      syncInlineProfileAvatarPreview();
      if (previousAvatarStoragePath && (removeAvatar || previousAvatarStoragePath !== nextAvatarStoragePath)) {
        await deleteSupabaseProfileImage(previousAvatarStoragePath).catch(() => null);
      }
      await refreshSupabaseTeamWorkspace({ alertOnDeny: false });
      syncInlineProfileAvatarPreview();
      return;
    } catch (error) {
      if (uploadedAvatar?.storagePath) {
        await deleteSupabaseProfileImage(uploadedAvatar.storagePath).catch(() => null);
      }
      showFormFeedback(form, `Profile photo update failed: ${String(error?.message || error || "Unknown error")}`);
      return;
    }
  }

  if (removeAvatar) {
    currentUser.avatarUrl = "";
    currentUser.avatarStoragePath = "";
    if (currentMember) {
      currentMember.avatarUrl = "";
      currentMember.avatarStoragePath = "";
      syncCurrentUserFromMember(currentMember);
    }
    state.profileAvatarDraft = null;
    closeModal({ reopenTaskSheet: false });
    persistDataAndRefresh();
    return;
  }

  try {
    const nextAvatarUrl = await readFileAsDataUrl(selectedFile);
    currentUser.avatarUrl = nextAvatarUrl;
    currentUser.avatarStoragePath = "";
    if (currentMember) {
      currentMember.avatarUrl = nextAvatarUrl;
      currentMember.avatarStoragePath = "";
      syncCurrentUserFromMember(currentMember);
    }
    state.profileAvatarDraft = null;
    closeModal({ reopenTaskSheet: false });
    persistDataAndRefresh();
  } catch (error) {
    showFormFeedback(form, String(error?.message || "Profile image could not be read."));
  }
}

function getWorkspaceLogoViewModel() {
  ensureProfileCollections(state.data);
  const workspace = state.data.workspace && typeof state.data.workspace === "object" ? state.data.workspace : {};
  const baseLogoUrl = String(workspace.logoUrl || "").trim();
  return {
    baseLogoUrl,
    logoUrl: baseLogoUrl,
    name: String(workspace.name || "Workspace").trim() || "Workspace",
    legalName: String(workspace.legalName || workspace.name || "Workspace LLC").trim() || "Workspace LLC",
    appLabel: normalizeSystemAppLabel(workspace.appLabel || workspace.name || "Workspace"),
    brandColor: String(workspace.brandColor || "#2f68df").trim() || "#2f68df",
    hasBaseLogo: Boolean(baseLogoUrl)
  };
}

function buildWorkspaceLogoPreviewMarkup(logoUrl, appLabel) {
  return `<img src="${escapeModalText(resolveBrandLogoUrl(logoUrl))}" alt="${escapeModalText(appLabel)}" />`;
}

function syncWorkspaceLogoEditorModal(form) {
  if (!(form instanceof HTMLFormElement)) {
    return;
  }
  const previewNode = form.querySelector("[data-workspace-logo-modal-preview]");
  const statusNode = form.querySelector("[data-workspace-logo-modal-status]");
  const secondaryButton = form.querySelector("[data-action='workspace-logo-secondary']");
  const removeField = form.querySelector("input[name='logoRemove']");
  const fileField = form.querySelector("input[name='logoFile']");
  const previewUrl = String(form.dataset.previewUrl || "").trim();
  const baseLogoUrl = String(form.dataset.baseLogoUrl || "").trim();
  const appLabel = String(form.dataset.appLabel || "Workspace").trim() || "Workspace";
  const removeLogo = removeField instanceof HTMLInputElement && removeField.value === "1";
  const fileSelected = fileField instanceof HTMLInputElement && Boolean(fileField.files?.length);
  const effectiveLogoUrl = removeLogo ? "" : previewUrl || baseLogoUrl;

  if (previewNode instanceof HTMLElement) {
    previewNode.innerHTML = buildWorkspaceLogoPreviewMarkup(effectiveLogoUrl, appLabel);
  }

  if (secondaryButton instanceof HTMLButtonElement) {
    if (removeLogo) {
      secondaryButton.hidden = false;
      secondaryButton.textContent = "Keep logo";
    } else if (previewUrl) {
      secondaryButton.hidden = false;
      secondaryButton.textContent = baseLogoUrl ? "Use current logo" : "Clear selection";
    } else if (baseLogoUrl) {
      secondaryButton.hidden = false;
      secondaryButton.textContent = "Remove logo";
    } else {
      secondaryButton.hidden = true;
      secondaryButton.textContent = "Remove logo";
    }
  }

  if (statusNode instanceof HTMLElement) {
    if (removeLogo) {
      statusNode.textContent = "The current workspace logo will be removed when you save this change.";
    } else if (previewUrl || fileSelected) {
      statusNode.textContent = "A new workspace logo is selected. Save to replace the current logo.";
    } else if (baseLogoUrl) {
      statusNode.textContent = "Your current workspace logo is active.";
    } else {
      statusNode.textContent = "No workspace logo has been added yet.";
    }
  }
}

